INSERT INTO `ich_project` VALUES (1, '龙泉青瓷烧制技艺', '龙泉市', '龙泉青瓷烧制技艺是流传于浙江省龙泉市的传统手工技艺，以烧制青釉瓷器而闻名于世，距今已有1700多年历史。龙泉青瓷始烧于三国两晋，南宋时期达到鼎盛，以其“青如玉、明如镜、薄如纸、声如磬”的特点被誉为“瓷中之宝”。龙泉青瓷烧制技艺包括原料配制、成型、施釉、烧成四大工序，细分达数十道环节。原料选用本地特有的瓷土和釉石，经过粉碎、淘洗、沉淀、陈腐等工序，制成细腻的胎料和釉料。成型方法有拉坯、印坯、雕镂等，可制作各种器型。施釉工艺独特，采用浸釉、荡釉、喷釉等方法，可达数层，使釉层肥厚如玉。烧成使用传统龙窑，需严格控制温度曲线，使釉色呈现粉青、梅子青等经典色调。龙泉青瓷分为哥窑和弟窑两大类型，哥窑以开片著称，弟窑以釉色取胜。2006年，龙泉青瓷烧制技艺被列入国家级非物质文化遗产代表性项目名录，2009年入选联合国教科文组织人类非物质文化遗产代表作名录。', '/pictures/龙泉青瓷烧制技艺.webp', '2006-05-01 00:00:00.000000', '国家级', '传统技艺');
INSERT INTO `ich_project` VALUES (2, '龙泉宝剑锻制技艺', '龙泉市', '龙泉宝剑锻制技艺是流传于浙江省龙泉市的传统手工技艺，以制作“坚韧锋利、刚柔相寓、寒光逼人、纹饰巧致”的宝剑而闻名于世，距今已有2500多年历史。龙泉宝剑始铸于春秋战国，相传为铸剑大师欧冶子在龙泉秦溪山麓铸成“龙渊”“泰阿”“工布”三剑而得名。龙泉宝剑锻制技艺包括炼、锻、铲、锉、刻、淬、磨等二十八道主要工序，全部手工完成。选料讲究，必须用低碳钢和中碳钢配合锻打，使剑身刚柔并济。锻打是关键，要经过反复折叠锻打，使钢材组织致密，形成独特的花纹。淬火是绝技，需根据剑的厚薄、长短，掌握好火候和水温，使剑身达到最佳硬度。磨砺是精细活，从粗磨到细磨再到精磨，使剑身光亮如镜，寒气逼人。龙泉宝剑的装饰也十分考究，剑鞘多用名贵木材，剑柄镶嵌玉石，剑身刻有龙、凤、七星等图案。2006年，龙泉宝剑锻制技艺被列入国家级非物质文化遗产代表性项目名录。', '/pictures/龙泉宝剑锻制技艺.webp', '2006-05-01 00:00:00.000000', '国家级', '传统技艺');
INSERT INTO `ich_project` VALUES (3, '龙泉窑传说', '龙泉市', '龙泉窑传说是流传于浙江省龙泉市的民间文学，是关于龙泉青瓷窑口起源和发展的民间传说故事，反映了当地人对青瓷文化的理解和想象，已有数百年历史。其中最著名的是“哥窑弟窑传说”，讲述古代龙泉有章生一、章生二兄弟俩，各自烧窑。哥哥烧的窑釉面开片，称为“哥窑”；弟弟烧的窑釉色如玉，称为“弟窑”。哥哥嫉妒弟弟的成就，偷偷往弟弟的窑里泼水，结果弟弟的瓷器反而产生了美丽的纹片，成为珍品。另有“窑变传说”，讲述窑工在烧窑时，有女子跳入窑中，烧出的瓷器格外精美，被称为“窑变”。还有“祭窑传说”，讲述窑工为烧出精品，用自身祭窑的故事。这些传说虽然带有神话色彩，但反映了龙泉窑工对技艺精益求精的追求。', '/pictures/龙泉窑传说.webp', '2025-07-04 00:00:00.000000', '县级', '民间文学');
INSERT INTO `ich_project` VALUES (4, '青田石雕', '青田县', '青田石雕是以浙江省青田县出产的叶蜡石为材料雕制的传统美术工艺品，距今已有1700多年历史。青田石雕以其“因材施艺、因色取巧”的艺术特色闻名于世，被誉为“在石头上绣花”。青田石雕的原料青田石，产于青田县山口、方山一带，石质细腻温润，色彩丰富多样，有青、黄、红、白、黑等上百种颜色，是理想的雕刻材料。青田石雕的技艺包括选料、构思、打坯、雕琢、修光、配座、打蜡等工序。选料讲究“相石”，根据石料的形状、色彩、纹理进行构思设计。打坯用大凿凿出粗坯，雕琢用各种刀具精雕细刻，修光用细刀打磨光滑。最具特色的是“因色取巧”，利用石料的不同颜色雕刻不同物象，如用红色雕花，白色雕鸟，绿色雕叶，使作品浑然天成。青田石雕题材广泛，有山水、人物、花鸟、走兽等。2006年，青田石雕被列入国家级非物质文化遗产代表性项目名录。', '/pictures/青田石雕.webp', '2006-05-01 00:00:00.000000', '国家级', '传统美术');
INSERT INTO `ich_project` VALUES (5, '梅源芒种开犁节', '云和县', '梅源芒种开犁节是流传于浙江省云和县崇头镇梅源一带的传统农事民俗，在每年芒种时节举行，通过祭神田、犒牛、开犁等仪式，祈求风调雨顺、五谷丰登，已有数百年历史。梅源地处浙西南山区，梯田层层叠叠，是典型的山地农耕区。开犁节起源于古代农耕祭祀，是农民在春耕开始前的重要仪式。节日当天，村民们身着盛装，聚集在梯田边，举行隆重的祭神田仪式。主祭人焚香点烛，献上三牲五果，诵读祭文，祈求土地神保佑丰收。随后举行犒牛仪式，给耕牛喂食糯米团和鸡蛋，感谢牛的辛勤劳作。最激动人心的是开犁仪式，老农扶着犁铧，赶着耕牛，在梯田中犁出第一道犁沟，标志着春耕正式开始。开犁节期间还有对歌、舞龙、演社戏等民俗活动，热闹非凡。2021年，梅源芒种开犁节被列入国家级非物质文化遗产代表性项目名录。', '/pictures/梅源芒种开犁节.webp', '2021-06-01 00:00:00.000000', '国家级', '民俗');
INSERT INTO `ich_project` VALUES (6, '木拱桥传统营造技艺', '庆元县', '木拱桥传统营造技艺是流传于浙江省庆元县的传统建筑技艺，用于建造木结构拱桥，工匠不用寸钉尺铁，仅凭榫卯衔接搭建横跨两岸的桥梁，结构科学，造型美观。这项技艺是中国古代木结构桥梁的活化石，至今已有近千年历史。庆元是中国现存木拱桥最多的县，有“中国廊桥之乡”之称。木拱桥传统营造技艺的核心是“编木拱”结构，用数十根圆木通过纵横交错、别压穿插的方式，编织成拱形承重结构。这种结构既科学又美观，受力合理，经久耐用。营造技艺包括选址、备料、建拱、架梁、铺板、建屋等工序。选址要选择两岸坚实、河面较窄处。备料选用优质杉木，要求笔直无疤节。建拱是最关键的环节，由掌墨师傅指挥，众人配合，将一根根圆木搭建成拱。架梁在拱上架设横梁，铺板铺设桥面，建屋在桥上建造廊屋。木拱桥不仅便于通行，还可供人休憩避雨。2008年，木拱桥传统营造技艺被列入国家级非物质文化遗产代表性项目名录，同年入选联合国教科文组织急需保护的非物质文化遗产名录。', '/pictures/木拱桥传统营造技艺.webp', '2008-06-01 00:00:00.000000', '国家级', '传统技艺');
INSERT INTO `ich_project` VALUES (7, '庆元龙灯', '庆元县', '庆元龙灯是流传于浙江省庆元县的传统舞蹈类项目，以布扎制龙身，内点灯火，夜间舞动，流光溢彩，是当地节庆活动的重要表演项目，已有数百年历史。庆元龙灯用竹篾扎制骨架，外罩彩绘龙布，龙身内装有灯座，可插蜡烛或装电灯。龙头重约二十斤，需要身强力壮的舞者才能举起。龙身分为九节或十二节，每节内都点有灯，整条龙长达三十米。表演时，由一人持龙珠引路，舞者手持龙杆，在锣鼓声中做出“龙抬头”“龙摆尾”“龙翻身”“龙戏珠”等动作。夜间表演时，龙身内灯火通明，整条龙流光溢彩，犹如真龙降世。庆元龙灯的舞法丰富多彩，有“盘龙柱”“穿龙肚”“跳龙门”“龙抢珠”等数十种套路，要求舞者配合默契，动作整齐划一。每逢春节、元宵、庙会等重大节日，庆元城乡都要舞起龙灯，祈求风调雨顺、国泰民安。庆元龙灯不仅是娱乐表演，更是村民凝聚力和向心力的象征。', '/pictures/庆元龙灯.webp', '2015-01-01 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (8, '黄帝祭典（缙云轩辕祭典）', '缙云县', '黄帝祭典（缙云轩辕祭典）是流传于浙江省缙云县的传统民俗活动，是祭祀中华民族人文始祖轩辕黄帝的盛大仪式，每年在清明和重阳举行，仪式庄重，规模宏大，已有上千年历史。缙云是黄帝文化的重要传承地，相传黄帝在缙云仙都鼎湖峰炼丹升天，因此缙云成为祭祀黄帝的重要场所。黄帝祭典分为春祭和秋祭，春祭在清明节，秋祭在重阳节。祭典仪式严格遵循古制，包括击鼓撞钟、敬献花篮、恭读祭文、行鞠躬礼、乐舞告祭等环节。主祭人身着古装，率领参祭人员，在庄严肃穆的气氛中向黄帝像行礼。乐舞告祭是祭典的高潮，身着古装的舞者表演“八佾舞”，以舞蹈形式表达对黄帝的崇敬。祭典期间还有学术研讨、书画展览、民间艺术表演等系列活动。缙云轩辕祭典不仅是祭祀仪式，更是传承中华文明、凝聚民族情感的重要载体。2011年，黄帝祭典被列入国家级非物质文化遗产代表性项目名录。', '/pictures/黄帝祭典（缙云轩辕祭典）.webp', '2011-05-01 00:00:00.000000', '国家级', '民俗');
INSERT INTO `ich_project` VALUES (10, '遂昌昆曲十番', '遂昌县', '遂昌昆曲十番是流传于浙江省遂昌县的传统音乐类项目，以昆曲曲牌为唱本，用丝竹乐器演奏，保留了早期昆曲的原始风貌，对于研究昆曲的传播与演变有重要价值，已有四百多年历史。遂昌昆曲十番起源于明代，相传与著名戏剧家汤显祖有关。汤显祖曾任遂昌知县，在任期间推广昆曲，遂昌民间逐渐形成了演奏昆曲十番的传统。十番即多种乐器轮番演奏，遂昌昆曲十番的乐器组合有笛子、二胡、三弦、琵琶、笙等丝竹乐器，配以板鼓、檀板、小锣等打击乐器。演奏的曲牌多为汤显祖《牡丹亭》中的唱段，如《游园》《惊梦》《寻梦》等，也有《长生殿》《西厢记》中的经典曲牌。遂昌昆曲十番的演奏风格古朴典雅，节奏舒缓，旋律优美，保留了明代昆曲的演唱风格和演奏技法。遂昌昆曲十番不仅在民间流传，还被吸收到道教音乐中，在斋醮仪式中演奏。2008年，遂昌昆曲十番被列入国家级非物质文化遗产代表性项目名录。', '/pictures/遂昌昆曲十番.webp', '2008-06-01 00:00:00.000000', '国家级', '传统音乐');
INSERT INTO `ich_project` VALUES (11, '班春劝农', '遂昌县', '班春劝农是流传于浙江省遂昌县的传统民俗活动，是明代著名文学家汤显祖在遂昌任知县时留下的鼓励农桑的习俗，每年春天举行迎春、鞭春仪式，号召农民积极耕作，已有四百多年历史。班春劝农起源于古代劝农制度，地方官在立春时节举行仪式，劝勉农民勤于耕作。汤显祖在遂昌任知县五年，大力推行劝农制度，使这一习俗在遂昌扎根流传。班春劝农仪式在立春日举行，主会场设在县城郊外的春场。仪式的主要内容包括迎春、鞭春、送春等。迎春时，县令率领官员和乡绅，到东郊迎春，祭祀春神句芒。鞭春是最隆重的环节，县令用彩鞭鞭打春牛，象征催促春耕开始。春牛是用泥土塑成的，鞭打后百姓争抢春牛碎片，拿回家中供奉，祈求丰收。送春时，将春牛头和春牛图送到各家各户，张贴在墙上。仪式结束后，县令还要到田间地头，与农民交谈，询问农事。班春劝农体现了古代官府对农业的重视，也是官民互动的重要方式。2011年，班春劝农被列入国家级非物质文化遗产代表性项目名录。', '/pictures/班春劝农.webp', '2011-05-01 00:00:00.000000', '国家级', '民俗');
INSERT INTO `ich_project` VALUES (1001, '丽水鼓词', '莲都区', '丽水鼓词是流传于浙江省丽水市莲都区及周边地区的传统曲艺形式，以丽水方言说唱为主要表演方式，以扁鼓为主要伴奏乐器，故称“鼓词”。这种艺术形式起源于清代，距今已有两百多年历史。表演时，艺人端坐桌前，左手持快板，右手击扁鼓，边说边唱，声情并茂地讲述历史故事、民间传说和时事新闻。丽水鼓词的唱腔融合了当地民歌小调，旋律优美动听，唱词通俗易懂，深受群众喜爱。传统的丽水鼓词多为盲艺人演唱，他们走村串户，以卖艺为生，将这种艺术传播到城乡各地。代表曲目有《三国演义》《水浒传》《白蛇传》等长篇历史故事，也有反映现实生活的短篇小调。2014年，丽水鼓词被列入国家级非物质文化遗产代表性项目名录，成为丽水曲艺文化的重要代表。', '/pictures/丽水鼓词.webp', '2014-12-01 00:00:00.000000', '国家级', '曲艺');
INSERT INTO `ich_project` VALUES (1002, '处州乱弹', '莲都区', '处州乱弹是流传于丽水（古称处州）地区的传统戏曲剧种，属于乱弹声腔系统，距今已有三百多年历史。处州乱弹以“乱弹”为主要唱腔，融合了高腔、昆腔、徽调等多种声腔，形成了“文武兼备、唱做并重”的艺术特色。其唱腔高亢激越，表演粗犷豪放，具有浓郁的山乡风味。处州乱弹的伴奏乐器以笛子、唢呐、板胡为主，配以锣鼓等打击乐器，气氛热烈。传统剧目有《双合印》《珍珠塔》《龙凤配》等数十本，内容多为历史故事和民间传说。在长期的演出实践中，处州乱弹形成了独特的表演程式和角色行当，深受浙南山区群众喜爱。2009年，处州乱弹被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/处州乱弹.webp', '2009-01-01 00:00:00.000000', '省级', '传统戏剧');
INSERT INTO `ich_project` VALUES (1003, '鱼跃酱油酿制技艺', '莲都区', '鱼跃酱油酿制技艺是流传于丽水市莲都区的传统酿造技艺，由“鱼跃”老字号传承至今已有上百年历史。这项技艺以优质大豆为原料，沿用传统的高盐稀态发酵工艺，经过原料筛选、浸泡蒸煮、制曲发酵、入缸晾晒、压榨灭菌等多道工序，历时一年以上才能酿出成品。其中最关键的是长达数月的露天晾晒环节，酱缸在阳光下自然发酵，昼夜温差和晴雨交替赋予了酱油独特的风味。鱼跃酱油色泽红褐鲜亮，酱香浓郁醇厚，滋味鲜美回甘，是当地居民烹饪不可或缺的调味品。该技艺不仅保留了传统的酿造方法，还传承了“诚信为本、质量第一”的商道精神。2023年，鱼跃酱油酿制技艺被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/鱼跃酱油酿制技艺.webp', '2023-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (1004, '南山中医骨伤科', '莲都区', '南山中医骨伤科是流传于丽水市莲都区南山一带的传统医药项目，以手法复位、夹板固定、中药外敷为主要特色，至今已传承四代以上，历时百余年。该疗法秉承中医“筋骨并重、内外兼治”的理念，在治疗骨折、脱位、软组织损伤等方面积累了丰富的临床经验。其核心技术包括：摸法诊断伤情、手法复位对位、杉树皮夹板固定、自制膏药外敷、分期内服中药等。特别是其独特的杉树皮夹板制作技术，取材方便、轻便透气、塑形性好，既符合人体解剖特点，又便于调整松紧。南山中医骨伤科还研制了多种祖传秘方膏药，具有活血化瘀、消肿止痛、续筋接骨的功效。2023年，该项目被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/南山中医骨伤科.webp', '2023-01-01 00:00:00.000000', '省级', '传统医药');
INSERT INTO `ich_project` VALUES (1005, '丽水吹打', '莲都区', '丽水吹打是流传于丽水市莲都区及周边地区的传统器乐乐种，以唢呐、笛子等吹奏乐器为主，配合锣、鼓、钹等打击乐器演奏，多在节庆庙会、婚丧嫁娶等场合表演。丽水吹打的曲牌丰富，既有《将军令》《水龙吟》等传统古曲，也有《八仙庆寿》《喜庆》等民间小调，还有根据当地民歌改编的吹打乐曲。演奏形式灵活多样，可独奏、齐奏，也可与戏曲、舞蹈等配合。丽水吹打的风格粗犷豪放，节奏明快热烈，具有浓郁的地方特色。在长期的传承发展中，丽水吹打形成了多个流派，各具特色。代表性传承人能够用唢呐模仿人声、鸟叫，技艺高超。2012年，丽水吹打被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/丽水吹打.webp', '2012-01-01 00:00:00.000000', '省级', '传统音乐');
INSERT INTO `ich_project` VALUES (1006, '陈十四信俗', '莲都区', '陈十四信俗是流传于丽水市莲都区及周边地区的传统民俗活动，以祭祀陈十四娘娘为核心内容。陈十四娘娘，又称陈靖姑，是浙南闽东地区广为崇拜的妇幼保护神，传说她能够保胎护幼、驱邪除灾。每年的农历正月十四和七月十四，莲都区多地的陈十四庙都会举行隆重的祭祀活动，包括上供、诵经、巡游、演戏等环节。其中最具特色的是“迎佛”巡游，信众抬着陈十四娘娘的神像穿街过巷，沿途居民焚香礼拜，祈求平安吉祥。巡游队伍中还有各种民间表演，如舞龙、舞狮、踩高跷等，热闹非凡。陈十四信俗融合了道教、民间信仰和民俗文化，反映了当地民众对平安幸福生活的期盼。2016年，陈十四信俗被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/陈十四信俗.webp', '2016-01-01 00:00:00.000000', '省级', '民俗');
INSERT INTO `ich_project` VALUES (1007, '潘百庙会', '莲都区', '潘百庙会是流传于丽水市莲都区雅溪镇潘百村的传统民俗活动，每年农历八月初一至初三定期举行，已有两百多年历史。庙会以祭祀当地守护神潘百大王为核心，传说潘百大王是宋代一位为民除害的勇士，村民为纪念他而建庙祭祀。庙会期间，村民们身着盛装，抬着潘百大王的神像巡游全村，沿途家家户户设香案迎拜。巡游队伍由彩旗队、锣鼓队、舞龙队等组成，浩浩荡荡，场面壮观。庙会上还有传统戏剧演出，邀请戏班连演三天大戏，剧目多为婺剧、越剧等地方戏曲。同时，庙会也是当地重要的物资交流会，周边商贩云集，农具、家具、日用百货、特色小吃琳琅满目。潘百庙会集祭祀、娱乐、商贸于一体，是当地民众一年一度的重要盛会，对于传承民俗文化、增进乡邻感情具有重要作用。', '/pictures/潘百庙会.webp', '2025-11-03 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (1008, '三官堂庙会', '莲都区', '三官堂庙会是流传于丽水市莲都区南明山街道三官堂村的传统民俗活动，每年农历正月十五、七月十五、十月十五定期举行，以祭祀天官、地官、水官“三官大帝”为核心内容。道教认为，天官赐福、地官赦罪、水官解厄，三官堂庙会正是民众祈求三官保佑的重要时机。庙会的主要仪式包括：开坛请圣、上表祈福、诵经拜忏、放河灯等。其中最具特色的是“放河灯”活动，信众将点燃的河灯放入瓯江支流，祈求水官保佑水路平安、消灾解厄。庙会期间还有传统戏曲表演、民间艺术展示和特色小吃摊位，吸引了周边数万群众参与。三官堂庙会融合了道教信仰和民间习俗，反映了当地民众对天地自然的敬畏和对美好生活的期盼。', '/pictures/三官堂庙会.webp', '2025-11-03 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (1009, '大庭庙会', '莲都区', '大庭庙会是流传于丽水市莲都区岩泉街道大庭村的传统民俗活动，每年农历九月初九重阳节举行，已有三百多年传承历史。庙会以祭祀大庭老爷为核心，传说大庭老爷是明代一位乐善好施的乡绅，去世后被村民奉为守护神。重阳节当天，村民们先在大庭庙举行隆重的祭祀仪式，献上三牲五果、敬香点烛、诵读祭文，然后抬着大庭老爷的神像巡游全村。巡游队伍中还有独特的“抬阁”表演，童男童女装扮成戏曲人物，坐在装饰华丽的阁楼上，由壮汉抬着前行，引得路人驻足观看。庙会上还有传统武术表演、地方戏曲演唱和特色美食品尝活动。大庭庙会不仅是祭祀活动，更是村民欢聚一堂、共庆丰收、联络感情的重要场合。', '/pictures/大庭庙会.webp', '2025-11-03 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (1010, '莲城雾峰茶制作技艺', '莲都区', '莲城雾峰茶制作技艺是流传于丽水市莲都区仙渡乡一带的传统制茶技艺，因茶园分布在海拔800米以上的雾峰山而得名，至今已有两百多年历史。这项技艺选用生长在高山云雾中的优质茶树鲜叶为原料，采摘标准严格，只取一芽一叶或一芽二叶。制作过程包括摊青、杀青、揉捻、初烘、复烘、提香等多道工序，全部手工完成。其中最具特色的是“双锅杀青”工艺，一锅高温快炒定形，一锅中温慢炒提香，使茶叶既保持翠绿色泽，又充分释放香气。莲城雾峰茶外形条索紧结，色泽翠绿油润，汤色清澈明亮，香气清高持久，滋味鲜爽醇厚，叶底嫩匀成朵。该技艺传承至今已历六代，保留了传统手工制茶的完整工艺和精湛技艺。', '/pictures/莲城雾峰茶制作技艺.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1011, '雅溪山粉丝制作技艺', '莲都区', '雅溪山粉丝制作技艺是流传于丽水市莲都区雅溪镇的传统食品加工技艺，以当地山区种植的红薯为原料，制作出口感爽滑、久煮不烂的山粉丝。这项技艺已有上百年历史，全套工序包括选薯、清洗、打浆、过滤、沉淀、调浆、漏粉、煮粉、晾晒、捆扎等十余道环节。其中最关键的是“漏粉”环节，制作者将调好的红薯淀粉浆装入底部有孔的漏瓢中，用手掌拍打，使粉浆均匀漏入沸水锅中，瞬间凝固成粉丝。雅溪山粉丝的独特之处在于完全采用传统手工制作，不添加任何明矾和添加剂，保留了红薯的天然营养和香味。成品粉丝粗细均匀、色泽透明、韧性十足，无论是煮汤、凉拌还是炒食，都爽滑可口。这项技艺不仅是当地农民增收的重要途径，也是山区饮食文化的生动体现。', '/pictures/雅溪山粉丝制作技艺.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1012, '梅苑卤鸭传统制作技艺', '莲都区', '梅苑卤鸭传统制作技艺是流传于丽水市莲都区碧湖镇梅苑村的特色卤味制作技艺，至今已有八十多年历史，传承三代以上。这项技艺选用当地放养的麻鸭为原料，这种鸭子以田间稻谷和水中鱼虾为食，肉质紧实、味道鲜美。制作过程包括宰杀清洗、腌制入味、卤制上色、晾凉切块等多个步骤。其中最关键的是卤水的配制，以二十多味中草药和香料，配以酱油、黄酒、冰糖等，经过长时间熬煮而成。卤水越陈越香，有的老店卤水已传承数十年。卤制时讲究火候掌控，先用大火烧开，再转小火慢卤，使卤汁充分渗入鸭肉，直至鸭肉酥烂入味。成品卤鸭色泽酱红油亮，香气扑鼻，肉质鲜嫩多汁，咸甜适中，是当地宴席上的必备佳肴，也是馈赠亲友的佳品。', '/pictures/梅苑卤鸭传统制作技艺.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1013, '畲族红粬酒酿造技艺', '莲都区', '畲族红粬酒酿造技艺是流传于丽水市莲都区畲族聚居区的传统酿酒技艺，以糯米和红粬为主要原料，酿制出酒色红润、口感醇厚的红粬酒。红粬是一种特殊的发酵剂，由大米经红粬霉菌发酵制成，既能使酒呈现红色，又赋予酒独特的风味和保健功效。这项技艺每年秋冬时节开始酿造，流程包括浸米、蒸饭、摊凉、拌粬、入缸发酵、加水二发、压榨取酒、陈化老熟等工序。其中发酵环节最为关键，需要严格控制温度和湿度，定时搅拌，观察发酵状态。经过一个多月的主发酵和数月的后发酵，酒液逐渐变得清亮红润，酒香浓郁。畲族红粬酒不仅是日常饮用的佳酿，更是畲族婚丧嫁娶、节日庆典中必不可少的饮品，承载着畲族人民的深厚情感和文化记忆。', '/pictures/畲族红粬酒酿造技艺.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1014, '莲都特色小吃制作技艺（年味猪头）', '莲都区', '年味猪头是丽水市莲都区传统年节食品制作技艺，每逢春节前夕，家家户户都要制作这道寓意吉祥的美味。这项技艺选用完整的猪头为原料，经过烧毛、刮洗、劈半、腌制、焯水、卤制等多道工序精心制作。其中卤制是最关键的一环，卤水由酱油、黄酒、冰糖和二十多种香料熬制而成，猪头在卤水中慢火卤煮三小时以上，直至肉质酥烂、骨肉分离。卤好的猪头色泽红亮，香气四溢，猪耳脆爽、猪舌绵软、猪头肉肥而不腻。在莲都习俗中，除夕夜祭祖时必供猪头，象征着“有头有脸”“从头开始”的美好寓意。正月初一，全家人围坐一起享用猪头肉，寓意新的一年丰衣足食、吉祥如意。这项技艺不仅是一种烹饪方法，更承载着浓浓的年味和乡愁。', '/pictures/莲都特色小吃制作技艺（年味猪头）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1015, '莲都特色小吃制作技艺（梅菜窑肉）', '莲都区', '梅菜窑肉是丽水市莲都区的传统名菜，以五花肉和梅干菜为主料，采用独特的窑制工艺烹制而成。制作梅菜窑肉，首先要选用三层五花肉，切成大块，焯水去腥；梅干菜则选用当地种植的芥菜，经过晒干、腌制、蒸制等多道工序制成，色泽乌黑、香气浓郁。烹制时，先在陶罐底部铺一层梅干菜，再放上五花肉，如此层层叠加，最后加入酱油、黄酒、冰糖等调料，用荷叶封口。然后将陶罐放入特制的土窑中，用炭火慢煨三小时以上。在密闭的窑中，肉与菜相互渗透，肉吸收梅菜的咸香，梅菜吸收肉的油脂，达到肥而不腻、瘦而不柴的完美口感。成品梅菜窑肉色泽酱红，香气扑鼻，肉质酥烂，梅菜香浓，是当地宴席上的压轴大菜。', '/pictures/莲都特色小吃制作技艺（梅菜窑肉）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1016, '莲都特色小吃制作技艺（泡精肉）', '莲都区', '泡精肉是丽水市莲都区的一道传统名菜，也是当地宴席上的必备冷盘，以其外酥里嫩、酸甜适口的独特风味深受喜爱。泡精肉选用猪里脊肉为主料，这种肉质细嫩、无筋膜，最适合制作这道菜。制作时，先将里脊肉切成薄片，用刀背轻轻拍松，然后加入盐、料酒、葱姜水腌制入味。接着将腌制好的肉片裹上用鸡蛋、淀粉调制的面糊，放入六成热的油锅中炸至金黄酥脆捞出。最关键的一步是调汁，将糖、醋、番茄酱、生抽等按比例调匀，入锅熬至浓稠，再将炸好的肉片倒入快速翻炒，使每片肉都均匀裹上酱汁。成品泡精肉色泽红亮，外皮酥脆，内里鲜嫩，酸甜开胃，老少皆宜。在莲都，无论是婚宴、寿宴还是春节家宴，都少不了这道美味。', '/pictures/莲都特色小吃制作技艺（泡精肉）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1017, '莲都特色小吃制作技艺（卷饼）', '莲都区', '卷饼是丽水市莲都区最具代表性的传统小吃之一，也是当地端午节必备的节令食品，已有数百年历史。莲都卷饼的制作技艺分为饼皮制作和馅料准备两部分。饼皮选用优质面粉，加入适量盐和水揉成面团，醒发后用特制的平底锅一张张烙制。烙好的饼皮薄如纸、圆如月、柔韧有弹性，不破不裂。馅料则丰富多样，通常有炒粉丝、炒豆芽、炒肉丝、炒蛋丝、炒笋丝、炒香菇等十多种，全部现炒现用。包卷时，将饼皮平铺，依次放上各种馅料，撒上花生碎和葱花，再淋上特制的甜面酱或辣酱，然后熟练地卷起，两头折进，一个饱满的卷饼就完成了。咬一口，饼皮的麦香、馅料的鲜香、酱料的咸甜在口中完美融合。每逢端午，莲都家家户户做卷饼，已经成为雷打不动的习俗。', '/pictures/莲都特色小吃制作技艺（卷饼）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1018, '莲都特色小吃制作技艺（包粽子）', '莲都区', '粽子制作技艺是丽水市莲都区传承已久的传统食品加工技艺，每逢端午节，家家户户都要包粽子，这一习俗已延续数百年。莲都粽子种类繁多，按口味分有咸粽和甜粽，按形状分有三角粽、四角粽、枕头粽等。制作技艺包括选料、浸米、洗叶、调味、包裹、扎绳、煮粽等环节。粽叶选用高山野生箬叶，清香浓郁；糯米选用当地优质糯米，浸泡三小时以上；馅料则因地因人而异，咸粽常包入腌制好的五花肉、咸蛋黄、香菇等，甜粽则包入红豆沙、蜜枣、莲子等。包裹是最见功力的环节，双手配合将粽叶折成漏斗状，填入糯米和馅料，再折叶盖住，用棕榈叶撕成的细绳扎紧，要求松紧适度，既不能漏米，又不能太紧影响口感。煮粽要用慢火煮三小时以上，再焖一夜，使粽叶的清香充分渗入糯米。', '/pictures/莲都特色小吃制作技艺（包粽子）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1019, '莲都特色小吃制作技艺（老面馒头）', '莲都区', '老面馒头制作技艺是丽水市莲都区传统面食技艺，与使用酵母粉发酵的现代馒头不同，老面馒头使用传统酵头发酵，保留了最原始的面香和口感。这项技艺的核心是“养面”，即长期保存和培养发酵用的面引子（老面）。每次做馒头时，取出一块老面，用温水化开，加入面粉揉成面团，在适宜的温度下发酵数小时，待面团膨胀两倍大、内部呈蜂窝状时即可。发酵好的面团需要反复揉制，排出气泡，然后分割成型，再次醒发后上笼蒸制。整个过程中不加任何添加剂，全靠经验和手感判断发酵程度和揉制力度。蒸出的老面馒头表面光滑，按压后迅速回弹，掰开可见均匀的蜂窝，闻之有浓郁的面香，吃起来松软中带着嚼劲，越嚼越甜。在莲都，老面馒头不仅是日常主食，更是过年过节走亲访友的必备礼品。', '/pictures/莲都特色小吃制作技艺（老面馒头）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1020, '莲都特色小吃制作技艺（稀卤螟脯）', '莲都区', '稀卤螟脯是丽水市莲都区的一道传统名菜，以墨鱼干（当地称“螟脯”）为主料，配以猪肉、冬笋、香菇等多种辅料制成羹状，鲜美可口，营养丰富。制作这道菜，首先要将墨鱼干用温水泡发，泡发的时间和水温都很有讲究，既要使墨鱼完全回软，又不能损失其鲜味。泡发好的墨鱼切成细丝，猪肉切丝上浆，冬笋、香菇切丝备用。烹制时，先用猪油爆香葱姜，下入肉丝煸炒变色，再加入墨鱼丝、笋丝、香菇丝翻炒出香味，然后加入高汤烧开，调味后用水淀粉勾芡，最后淋入蛋液搅成蛋花，撒上葱花即可。成品稀卤螟脯汤汁浓稠适中，墨鱼鲜美有嚼劲，肉丝滑嫩，笋丝脆爽，各种食材的味道相互融合，形成独特的风味。这道菜在莲都的婚宴、寿宴上必不可少，寓意“富足有余”。', '/pictures/莲都特色小吃制作技艺（稀卤螟脯）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1021, '莲都特色小吃制作技艺（炒双冬）', '莲都区', '炒双冬是丽水市莲都区的传统素菜佳肴，以冬笋和冬菇（香菇）为主料烹制而成，是当地宴席上必不可少的一道时令菜。冬笋选用立冬后至立春前采挖的嫩笋，此时笋质最为鲜嫩脆爽；冬菇则选用肉厚朵小的优质香菇，干香菇泡发后香气更加浓郁。制作时，先将冬笋剥壳去老根，切成薄片，入沸水焯烫去除涩味；冬菇泡发后去蒂切片。热锅下猪油，爆香姜片，先下冬笋片煸炒至边缘微黄，再加入冬菇片同炒，烹入黄酒，加入高汤、酱油、白糖调味，小火焖煮片刻，最后用水淀粉勾芡，淋上香油，撒上葱花即可。成品炒双冬色泽黄亮，冬笋脆嫩爽口，冬菇软滑香浓，两种食材相得益彰，清淡中透着鲜美，是莲都人春节餐桌上的必备素菜，寓意“双冬报春”。', '/pictures/莲都特色小吃制作技艺（炒双冬）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1022, '莲都特色小吃制作技艺（香菇里脊）', '莲都区', '香菇里脊是丽水市莲都区的传统名菜，以鲜香菇和猪里脊肉为主料烹制而成，鲜香滑嫩，老少皆宜。这道菜选用猪里脊肉，肉质细嫩无筋膜，切成薄片后上浆滑油，使肉片保持嫩滑。鲜香菇选用朵形完整、肉质肥厚的品种，切片后与肉片同炒，香菇吸收肉汁的鲜味，肉片染上香菇的香气，两者相得益彰。烹制时讲究火候，肉片滑油时间不宜过长，变色即捞出；炒制时先爆香葱姜，下香菇煸炒出香味，再加入肉片快速翻炒，调味后用水淀粉勾芡，使汤汁均匀包裹在食材上。成品香菇里脊色泽淡雅，肉片洁白滑嫩，香菇乌黑油亮，口感鲜香爽滑，汤汁浓郁可口。这道菜在莲都的大小宴席上都很常见，既可作为下饭菜，也可作为宴客佳肴，深受当地群众喜爱。', '/pictures/莲都特色小吃制作技艺（香菇里脊）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1023, '莲都特色小吃制作技艺（梁氏豆腐）', '莲都区', '梁氏豆腐制作技艺是流传于丽水市莲都区碧湖镇梁村的一项传统豆制品加工技艺，由梁氏先祖创制于清代道光年间，至今已传承七代，近两百年历史。这项技艺选用当地种植的优质黄豆为原料，采用传统石磨磨浆、柴火烧浆、盐卤点浆等古法工艺制作豆腐。其独特之处在于“三煮三压”工艺：豆浆要经过三次煮沸，每次煮沸后都要撇去浮沫，使豆浆更加纯净；点卤后要经过三次压制，逐渐加大压力，使豆腐既紧实又富有弹性。梁氏豆腐成品洁白细嫩，豆香浓郁，切面光滑，久煮不烂，无论是煎、炒、炖、煮都保持形状完整。除了传统的嫩豆腐、老豆腐，梁氏还制作豆腐干、油豆腐、豆腐皮等多种豆制品，各具特色。梁氏豆腐制作技艺不仅保留了传统的手工豆腐制作方法，更承载了当地人的饮食记忆和文化认同。', '/pictures/莲都特色小吃制作技艺（梁氏豆腐）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1024, '莲都特色小吃制作技艺（馋嘴鸡）', '莲都区', '馋嘴鸡是丽水市莲都区近年来兴起的特色菜肴，以其麻辣鲜香、回味悠长的独特风味迅速走红，成为当地餐饮市场的一张名片。这道菜的选料十分讲究，必须选用当地放养的土鸡，这种鸡以谷物和昆虫为食，活动量大，肉质紧实鲜美。制作工艺包括腌制、焯水、卤制、油炸、拌料等多个环节。鸡肉先经过秘制调料腌制入味，然后焯水去腥，再放入由二十多种香料熬制的卤水中卤制一小时，使香料充分渗入鸡肉。卤好的鸡肉晾凉后斩块，入油锅炸至表皮酥脆，最后拌入由辣椒油、花椒粉、芝麻、花生碎等调制的特制酱料。成品馋嘴鸡色泽红亮，外酥里嫩，麻辣中透着鲜香，让人一吃就停不下来。这道菜既可作下酒菜，也可作零食，深受年轻人喜爱，已成为莲都美食的新名片。', '/pictures/莲都特色小吃制作技艺（馋嘴鸡）.webp', '2025-11-03 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (1025, '同恩堂养生膏制作技艺', '莲都区', '同恩堂养生膏制作技艺是流传于丽水市莲都区的一项传统医药技艺，由同恩堂药号创制于清代光绪年间，至今已传承五代，一百二十余年历史。这项技艺以“药食同源”为理念，选用药食两用的中药材为原料，经过精选、炮制、浸泡、煎煮、浓缩、收膏、分装等十多道工序，熬制成膏方。同恩堂养生膏根据功效不同分为补气养血膏、滋阴润肺膏、健脾养胃膏、安神助眠膏等多个品种，每种膏方都有固定的配方和炮制工艺。其中最具特色的是“三煎三滤”工艺，药材要经过三次煎煮，每次煎煮后都要过滤取汁，最后将三次药汁合并浓缩，使药效充分释放。收膏环节更是考验功力，要掌握好火候和时机，使膏体达到“滴水成珠”的程度。同恩堂养生膏制作技艺代表了传统中药膏方的制作水平，是中医药文化的重要传承。', '/pictures/同恩堂养生膏制作技艺.webp', '2025-11-03 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (1026, '摇锅', '莲都区', '摇锅是流传于丽水市莲都区畲族聚居区的一项传统体育项目，也是畲族青年男女喜爱的竞技活动，已有数百年历史。这项活动的道具是一只特制的大铁锅，锅口直径约一米，锅深约半米，重约三四十斤。参与者站在锅沿上，通过身体的重心移动和脚步的配合，使铁锅向前滚动，既要保持平衡不摔倒，又要控制锅的滚动方向和速度。摇锅看似简单，实则需要极强的平衡能力和身体协调性。比赛时，可以比谁摇得远、摇得快，也可以比谁能在锅上做更多的动作，如转身、跳跃等。这项活动最初是畲族青年在山间劳作之余的娱乐方式，后来逐渐发展成为节庆活动的表演项目。摇锅不仅锻炼了参与者的平衡能力和勇气，也体现了畲族人民乐观向上的生活态度。如今，摇锅已成为莲都区民族体育的特色项目。', '/pictures/摇锅.webp', '2025-11-03 00:00:00.000000', '县级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (1027, '蹴石磉', '莲都区', '蹴石磉是流传于丽水市莲都区乡村的一项传统体育项目，也是农民在农闲时节喜爱的竞技活动，已有数百年历史。石磉是农村用来平整场院的石制工具，圆柱形，重约百斤，一端有孔可穿绳。蹴石磉比赛时，参与者用脚踢动石磉，使其向前滚动，比拼力量和技巧。比赛形式多样，可以比谁踢得远，也可以比谁踢得准，还可以进行团体接力。踢石磉需要全身发力，尤其考验腰腿力量和爆发力。有经验的选手不仅能把石磉踢出很远，还能控制其滚动方向和速度。这项活动最初是农民在打谷场上劳作之余的娱乐，后来逐渐发展成为节庆活动的比赛项目。蹴石磉不仅锻炼了参与者的体魄，也增进了乡邻之间的感情。如今，这项传统体育活动已成为莲都区乡村文化的重要组成。', '/pictures/蹴石磉.webp', '2025-11-03 00:00:00.000000', '县级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (1028, '厦河门十番', '莲都区', '厦河门十番是流传于丽水市莲都区厦河门一带的传统器乐乐种，由民间小调融合道教音乐元素发展而来，至今已有150多年历史。“十番”意指多种乐器轮番演奏，通常由笛子、二胡、三弦、琵琶、笙、箫等丝竹乐器，配以板鼓、檀板、小锣、小钹等打击乐器组成。厦河门十番的曲牌丰富，既有《将军令》《水龙吟》等传统古曲，也有《八仙庆寿》《采茶调》等民间小调，还有道士做法事时演奏的道教音乐。演奏时讲究“番番不同”，即同一首曲牌每次演奏都要有变化，或加花、或减字、或变奏，使音乐富有变化和生命力。厦河门十番多在节庆庙会、婚丧嫁娶等场合演奏，既能营造热烈气氛，也能表达哀思之情。2021年，厦河门十番被列入丽水市非物质文化遗产代表性项目名录。', '/pictures/厦河门十番.webp', '2021-10-01 00:00:00.000000', '市级', '传统音乐');
INSERT INTO `ich_project` VALUES (1029, '魏村采茶灯', '莲都区', '魏村采茶灯是流传于丽水市莲都区魏村的传统舞蹈，起源于清代，已有两百多年历史。采茶灯以表现茶农采茶劳动为主题，舞者手持彩灯，模仿采茶、制茶的各种动作，既是对劳动场景的艺术再现，也寄托着祈求茶叶丰收的美好愿望。表演时，通常由十二位少女手持茶篮灯，在锣鼓和丝竹伴奏下翩翩起舞。舞蹈动作包括“上山采茶”“双手摘茶”“背篓下山”“晾茶晒青”等，动作优美流畅，节奏欢快活泼。队形变化丰富，有“单龙戏水”“双凤朝阳”“梅花五瓣”等多种图案。魏村采茶灯的彩灯制作也很有特色，用竹篾扎制骨架，糊以彩绸，装饰有茶花、茶叶图案，内点蜡烛，夜间表演时流光溢彩。这项舞蹈不仅表现了茶农劳动的快乐，也展现了江南女子的柔美风姿，是莲都茶文化的重要载体。', '/pictures/魏村采茶灯.webp', '2021-10-01 00:00:00.000000', '市级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (1030, '保定布龙', '莲都区', '保定布龙是流传于丽水市莲都区保定村的传统舞蹈，以布扎制龙身，多人舞动，气势磅礴，已有三百多年历史。保定布龙全长约三十米，分为九节或十二节，龙身用竹篾扎制骨架，外罩彩绘龙布，龙鳞、龙爪、龙须等细节栩栩如生。龙头重约二十斤，需要身强力壮的舞者才能举起。表演时，由一人持龙珠引路，九至十二人持龙杆舞动，在锣鼓声中做出“龙抬头”“龙摆尾”“龙翻身”“龙戏珠”等动作。夜间表演时，龙身内点蜡烛，整个布龙流光溢彩，犹如真龙降世。保定布龙的套路丰富，有“盘龙柱”“穿龙肚”“跳龙门”“龙抢珠”等数十种，要求舞者配合默契，动作整齐划一。每逢春节、元宵、庙会等重大节日，保定村都要舞起布龙，祈求风调雨顺、国泰民安。保定布龙不仅是娱乐表演，更是村民凝聚力和向心力的象征。', '/pictures/保定布龙.webp', '2021-10-01 00:00:00.000000', '市级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (1031, '雅溪竹编', '莲都区', '雅溪竹编是流传于丽水市莲都区雅溪镇的传统手工技艺，以当地盛产的优质毛竹为原料，编织成各种生活用具和工艺品，已有三百多年历史。雅溪竹编的工艺流程包括选竹、砍竹、去青、破篾、匀篾、煮篾、染色、编织、收口、修整等十多道工序。其中最见功力的是破篾和匀篾，能将一根竹片分成五六层，每层薄如纸张，宽窄均匀，柔韧不断。编织技法有十字编、人字编、六角编、螺旋编等数十种，可编出各种图案和文字。雅溪竹编的产品种类繁多，有生产用的竹篮、竹筐、竹篓，有生活用的竹席、竹枕、竹椅，有装饰用的竹画、竹屏风、竹灯笼，还有专供喜庆用的提篮、果盒等。雅溪竹编以其工艺精细、造型美观、经久耐用而著称，不仅是当地农民的重要副业，也是雅溪文化的重要象征。', '/pictures/雅溪竹编.webp', '2021-10-01 00:00:00.000000', '市级', '传统技艺');
INSERT INTO `ich_project` VALUES (2003, '龙泉青瓷', '龙泉市', '龙泉青瓷烧制技艺是浙江省龙泉市的传统手工技艺，以烧制青釉瓷器而闻名，是国家级非物质文化遗产。这项技艺包括原料配制、成型、施釉、烧成四大工序。原料选用龙泉本地特有的瓷土和釉石，经过粉碎、淘洗、沉淀等工序制成。成型方法有拉坯、印坯、雕镂等，可制作各种器型。施釉工艺独特，采用浸釉、荡釉等方法，使釉层肥厚。烧成使用传统龙窑，需严格控制温度。龙泉青瓷分为哥窑和弟窑，哥窑以开片著称，弟窑以釉色取胜。南宋时期的粉青、梅子青釉色达到高峰，釉层厚润，色泽青翠，如玉似冰。龙泉青瓷不仅是实用器皿，更是艺术品，体现了中国传统美学的最高境界。2009年，龙泉青瓷烧制技艺入选联合国教科文组织人类非物质文化遗产代表作名录，成为全球陶瓷类首个入选的项目。', '/pictures/龙泉青瓷.webp', '2005-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (2004, '龙泉宝剑', '龙泉市', '龙泉宝剑锻制技艺是浙江省龙泉市的传统手工技艺，以制作坚韧锋利、刚柔相济的宝剑而闻名，是国家级非物质文化遗产。这项技艺包括炼、锻、铲、锉、刻、淬、磨等二十八道工序。选料讲究，必须用低碳钢和中碳钢配合锻打。锻打是关键，要经过反复折叠锻打，使钢材组织致密，形成独特的花纹。淬火是绝技，需掌握好火候和水温。磨砺使剑身光亮如镜。龙泉宝剑的装饰也十分考究，剑鞘多用名贵木材，剑柄镶嵌玉石，剑身刻有图案。龙泉宝剑不仅是兵器，更是权力和地位的象征，是中国剑文化的杰出代表。', '/pictures/龙泉宝剑.webp', '2005-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (2005, '香菇砍花技艺', '龙泉市', '香菇砍花技艺是流传于浙江省龙泉市的传统农业技艺，是世界香菇栽培技术的发源地之一，距今已有800多年历史。这项技艺由南宋龙泉人吴三公发明，他发现在砍伐的阔叶树上，用斧头砍出花痕，就能生长出香菇，开创了人工栽培香菇的先河。香菇砍花技艺包括选山、砍树、截段、砍花、遮衣、散水、惊蕈、采菇、烘干等一整套工序。选山要选择向阳通风、土壤肥沃的山地；砍树要选树龄合适的阔叶树，如栲树、枫树等；砍花是最关键的环节，用特制的砍花斧在树皮上砍出深浅、疏密有致的花纹，控制香菇生长的密度和质量；惊蕈是一种独特的催菇技术，用木槌敲击菇木，震动刺激菌丝生长。龙泉香菇砍花技艺的发明，使香菇从野生采集走向人工栽培，对世界食用菌产业产生了深远影响。', '/pictures/香菇砍花技艺.webp', '2009-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (2006, '提线木偶戏', '龙泉市', '提线木偶戏是流传于浙江省龙泉市的传统戏剧形式，由艺人以线操纵木偶表演，配以唱腔和乐器伴奏，演绎各类故事，至今已有三百多年历史。龙泉提线木偶戏的木偶制作十分精细，高约两尺，用樟木雕刻头部，彩绘脸谱，服饰用绸缎制作，四肢关节可活动，通过十几根甚至二十多根细线连接操纵。表演时，艺人站在戏台上方的架板上，通过提拉不同位置的线，使木偶做出行走、转身、作揖、舞剑等各种动作。唱腔以乱弹为主，融合徽调、昆腔等，伴奏乐器有锣、鼓、钹、笛子、二胡等。传统剧目有《白蛇传》《西游记》《三国演义》等数十本。龙泉提线木偶戏的独特之处在于，一个艺人可以同时操纵多个木偶，配合唱念做打，表演复杂的武打场面。', '/pictures/提线木偶戏.webp', '2025-07-04 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (2007, '菇民防身术', '龙泉市', '菇民防身术是流传于浙江省龙泉市龙南乡一带的传统体育项目，是菇民在长期深山劳作中创编的防身技艺，已有数百年历史。龙泉菇民每年秋冬季节进入深山老林培育香菇，要在山中居住数月之久，常遇野兽出没、歹人骚扰，于是创编了这套实用的防身术。菇民防身术包括拳术和器械两部分，拳术有扁担拳、柴刀拳、挑担拳等，器械有柴刀、扁担、木棍等日常用具。其特点是动作朴实、实用性强，讲究一招制敌，不追求花哨。如“扁担拳”以挑香菇的扁担为武器，有挑、压、扫、劈等招式；“柴刀术”以砍柴的柴刀为武器，有砍、削、挡、刺等动作。菇民防身术不仅是防身技艺，更是菇民艰苦生活的写照，体现了山区人民自强不息的精神。', '/pictures/菇民防身术.webp', '2025-07-04 00:00:00.000000', '县级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (2008, '龙泉青瓷烧制技艺（釉料配制）', '龙泉市', '龙泉青瓷釉料配制技艺是龙泉青瓷烧制技艺的核心组成部分，决定着青瓷釉色的品质和特色，是龙泉青瓷千年传承的绝技。龙泉青瓷釉料选用当地特有的釉石、草木灰等为原料，经过选料、粉碎、淘洗、沉淀、陈腐、调配等多道工序制成。釉石要选含铁量适中的矿石，粉碎后淘洗去杂，沉淀成釉浆。草木灰选用特定的植物烧制，如石灰石与青柴灰配合，能产生温润如玉的釉色。调配是最关键的环节，要根据胎体特性、窑温变化等因素，确定釉料配方。龙泉青瓷的经典釉色如粉青、梅子青、豆青、天青等，都是通过不同的釉料配方和烧成温度实现的。釉料配制技艺全凭经验掌握，配比稍有变化，釉色就会天差地别。这项技艺代代相传，是龙泉青瓷工匠的不传之秘。', '/pictures/龙泉青瓷烧制技艺（釉料配制）.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2009, '龙泉青瓷传统龙窑建造技艺', '龙泉市', '龙泉青瓷传统龙窑建造技艺是流传于浙江省龙泉市的传统建筑技艺，用于建造烧制青瓷的龙窑，已有上千年历史。龙窑因依山坡而建，形似长龙而得名，是龙泉青瓷烧制的重要设施。龙窑建造技艺包括选址、平整地基、夯筑窑床、砌筑窑墙、架设窑拱、开设窑门、修建烟囱等工序。选址要选择有一定坡度的山岗，既能利用自然抽力，又便于排水。窑床用黄土层层夯实，确保平整坚实。窑墙用耐火砖砌筑，内壁涂抹耐火泥。窑拱是龙窑的关键，要用楔形耐火砖砌成拱形，既要牢固又要便于拆修。窑门开设在窑身一侧，用于装窑和出窑。烟囱建在窑尾，高度要适中，保证抽力均匀。龙泉传统龙窑一般长三十至五十米，宽约两米，一次可装烧数千件瓷器。', '/pictures/龙泉青瓷传统龙窑建造技艺.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2010, '灵芝栽培技术', '龙泉市', '灵芝栽培技术是流传于浙江省龙泉市的传统农业技艺，利用段木栽培灵芝，已有数百年历史。龙泉地处浙西南山区，气候温暖湿润，森林资源丰富，是灵芝生长的理想之地。灵芝栽培技术包括菌种培育、段木准备、接种、发菌、埋土、出芝管理、采收加工等环节。菌种要选用优质灵芝菌株，在无菌条件下培育成栽培种。段木选用栲树、枫树等阔叶树，冬至前后砍伐，截成适宜长度，钻孔备用。接种时在孔中填入菌种，用蜡封口。发菌期要将段木堆放在阴凉处，保持适宜温湿度，让菌丝在木质部生长。埋土时将发好菌的段木半埋入土中，保持土壤湿润。出芝期要控制好温湿度和光照，使芝盖生长均匀。成熟灵芝要及时采收，烘干保存。龙泉灵芝朵大肉厚，质地坚实，药用价值高。', '/pictures/灵芝栽培技术.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2011, '古建筑营造技艺', '龙泉市', '古建筑营造技艺是流传于浙江省龙泉市的传统建筑技艺，用于建造传统民居、祠堂、庙宇等木结构建筑，已有数百年历史。这项技艺涵盖木作、瓦作、石作、油漆等多个工种，由掌墨师傅统一指挥。木作是核心，包括选材、加工、榫卯制作、大木安装等工序。选材讲究，柱用松木、梁用杉木，要选纹理顺直、无疤节的木材。榫卯制作是绝活，有燕尾榫、透榫、半榫、十字榫等数十种，不用一钉一铁，全靠榫卯连接。大木安装讲究“立架”的时机和方法，需要众人合力完成。瓦作包括铺瓦、筑脊、做檐口等，要保证屋顶不漏水、美观大方。石作包括柱础、台阶、门框的制作安装。油漆使用传统大漆，经多道工序使木构件防腐防蛀、光亮美观。龙泉古建筑营造技艺体现了中国传统木结构建筑的最高水平。', '/pictures/古建筑营造技艺.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2012, '开天门', '龙泉市', '开天门是流传于浙江省龙泉市的传统民俗活动，是一种为临终老人举行的送终仪式，寓意开启天堂之门，送老人灵魂升天，已有数百年历史。在龙泉民间，当老人病危时，家人会请来道士或族中有威望的长者主持开天门仪式。仪式通常在老人卧室举行，先在屋顶揭开几片瓦，露出一孔“天门”，象征打通天地通道。道士诵经念咒，引导老人灵魂从“天门”升天。同时，家人跪拜哭泣，送别亲人。开天门仪式还包括“铺路”“搭桥”等环节，用白布从床头铺到门口，象征为灵魂铺就升天之路。仪式结束后，家人要守夜陪伴，直到老人咽气。开天门体现了龙泉人民对生死的理解和尊重，是对逝者的最后告慰，也是孝道文化的集中体现。这项民俗活动承载着当地民众的情感记忆和生命观念。', '/pictures/开天门.webp', '2025-07-04 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (2013, '炼火', '龙泉市', '炼火是流传于浙江省龙泉市的传统民俗活动，表演者赤脚走过烧红的炭火，展示勇气和信仰，具有驱邪祈福的寓意，已有数百年历史。炼火通常在庙会或重大节日举行，由道士或法师主持。活动开始前，先在场地中央铺上厚厚一层木炭，点燃后烧成通红的炭火，温度可达数百摄氏度。表演者经过斋戒沐浴，在神灵前祈祷后，赤脚快速从炭火上走过，脚不受伤。有时多人同时踩过，或背着神像踩过，场面惊险震撼。炼火表演者认为，因为有神灵护佑，才能毫发无损。这项活动既是对表演者勇气和信仰的考验，也是为全村祈福消灾的仪式。龙泉炼火的独特之处在于，不仅有人踩火，还有“洗火脸”“舔火犁”等更高难度的表演。', '/pictures/炼火.webp', '2025-07-04 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (2014, '畲族山歌', '龙泉市', '畲族山歌是流传于浙江省龙泉市畲族聚居区的传统音乐，以畲语演唱，内容涉及爱情、劳动、生活、历史等，是畲族人民“以歌代言”的文化传统，已有数百年历史。畲族山歌的曲调优美动听，节奏自由灵活，有独唱、对唱、齐唱等多种形式。歌词多为七言四句，讲究押韵，比喻生动，情感真挚。内容十分丰富，有劳动歌如《采茶歌》《砍柴歌》，有情歌如《相思歌》《送郎歌》，有礼俗歌如《敬酒歌》《哭嫁歌》，还有叙事长歌如《高皇歌》讲述畲族始祖盘瓠的传说。对唱是畲族山歌最具特色的形式，男女青年在山间地头一唱一和，互相试探，表达爱慕之情。畲族山歌没有固定的曲谱，全凭口头传承，即兴编唱，体现了畲族人民的智慧和才情。', '/pictures/畲族山歌.webp', '2025-07-04 00:00:00.000000', '县级', '传统音乐');
INSERT INTO `ich_project` VALUES (2015, '狮舞', '龙泉市', '狮舞是流传于浙江省龙泉市的传统舞蹈，表演者扮成狮子，模仿狮子各种动作，配以锣鼓伴奏，热闹喜庆，已有数百年历史。龙泉狮舞的狮子用竹篾扎制骨架，外罩彩绘狮被，狮头重约十斤，狮身长约三米，由两人配合表演，一人舞头一人舞尾。表演时，由一人持绣球引狮，狮子随着绣球的引导做出各种动作，如“狮子出洞”“狮子打滚”“狮子搔痒”“狮子过桥”“狮子登高”等。龙泉狮舞的独特之处在于“高台舞狮”，将八仙桌叠成高台，狮子逐层攀爬，最高可达七八层，在高台上做出各种惊险动作。狮舞表演融合了武术、杂技元素，要求舞者配合默契，动作协调。每逢春节、元宵、庙会，龙泉城乡都要舞狮助兴，寓意驱邪避灾、吉祥如意。', '/pictures/狮舞.webp', '2025-07-04 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (2016, '龙泉红茶制作技艺', '龙泉市', '龙泉红茶制作技艺是流传于浙江省龙泉市的传统制茶技艺，以本地茶树鲜叶为原料，经萎凋、揉捻、发酵、干燥等工序制成红茶，已有上百年历史。龙泉红茶选用生长在高山云雾中的优质茶树，采摘标准严格，只取一芽一叶或一芽二叶。萎凋是将鲜叶摊放在萎凋槽中，使水分适度蒸发，叶片变软。揉捻用手工或揉捻机使茶叶卷曲成条，破坏细胞组织，促进发酵。发酵是红茶制作的关键，在温湿度适宜的发酵室中，茶叶发生氧化反应，叶色由绿变红，散发出特有的香气。干燥用炭火或烘干机终止发酵，固定品质。龙泉红茶外形条索紧结，色泽乌润，汤色红艳明亮，香气甜香浓郁，滋味醇厚鲜爽，叶底红亮匀齐。龙泉红茶制作技艺传承了传统工夫红茶的制作方法，形成了独特的品质风格。', '/pictures/龙泉红茶制作技艺.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2017, '龙泉白茶制作技艺', '龙泉市', '龙泉白茶制作技艺是流传于浙江省龙泉市的传统制茶技艺，采用特定茶树品种，经萎凋、干燥等轻发酵工艺制成白茶，保留了茶叶最天然的风味，已有数百年历史。龙泉白茶选用当地特有的白化茶树品种，如白叶一号等，这些茶树在春季新梢生长过程中，因温度变化出现阶段性白化现象，叶片呈玉白色。采摘标准严格，只取一芽一叶或一芽二叶，在清明前后白化最佳时期采摘。制作工艺包括萎凋和干燥两道主要工序，不揉不炒，最大限度保留茶叶的自然形态和内含物质。萎凋在通风阴凉处进行，历时两到三天，使茶叶缓慢失水，发生轻微发酵。干燥用炭火低温慢烘，固定品质。龙泉白茶外形芽叶完整，满披白毫，色泽银绿，汤色杏黄明亮，香气清鲜毫香显露，滋味鲜爽甘甜。', '/pictures/龙泉白茶制作技艺.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2018, '龙泉大漆髹饰技艺', '龙泉市', '龙泉大漆髹饰技艺是流传于浙江省龙泉市的传统漆器工艺，以天然大漆为原料，经多道髹涂、打磨、推光等工序制成漆器，已有数百年历史。大漆是从漆树割取的天然树脂，具有耐久、防腐、防潮、耐酸碱的特性。龙泉大漆髹饰技艺的工序包括制胎、打底、髹漆、打磨、推光、装饰等。胎骨可用木、竹、布等材料制作，要求平整坚实。打底用生漆调瓦灰刮涂，填补缝隙，打磨平整。髹漆是核心工序，要髹涂数道至数十道生漆，每道漆都要阴干后再髹下一道，使漆层达到一定厚度。打磨用不同粗细的水砂纸逐道打磨，使漆面平滑如镜。推光用植物油和细瓦灰反复擦拭，使漆面光亮如镜。装饰有彩绘、镶嵌、雕填等手法。龙泉大漆髹饰技艺制作的漆器光亮如镜，温润如玉。', '/pictures/龙泉大漆髹饰技艺.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2019, '宋式点茶', '龙泉市', '宋式点茶是流传于浙江省龙泉市的传统茶艺，是宋代饮茶方式的传承，包括碾茶、罗茶、候汤、熁盏、点茶等程序，具有深厚文化内涵。宋式点茶先将团饼茶用茶碾碾成细末，用罗筛筛出极细的茶粉。候汤即煮水，讲究“蟹眼已过鱼眼生”的水温。熁盏是用热水温热茶盏，使点茶时茶末不易下沉。点茶时，先取茶粉放入盏中，注入少量热水调成膏状，再用茶筅快速击拂，同时继续注水，使茶汤泛起细密的泡沫。点茶的评判标准是“沫饽”的色泽、细腻程度和持久性，白色、细腻、持久者为上品。宋式点茶还可进行“斗茶”“分茶”游戏，在茶汤表面绘制图案。龙泉是青瓷之都，用龙泉青瓷茶盏点茶，青瓷的青翠与茶汤的乳白相映成趣，别具韵味。', '/pictures/宋式点茶.webp', '2025-07-04 00:00:00.000000', '县级', NULL);
INSERT INTO `ich_project` VALUES (2020, '龙泉陈氏插花', '龙泉市', '龙泉陈氏插花是流传于浙江省龙泉市的传统插花艺术，由陈氏家族世代传承，讲究造型、色彩和意境，体现东方美学理念，已有上百年历史。陈氏插花以“师法自然”为原则，选用龙泉山野间的花、枝、叶、果为素材，通过修剪、造型、搭配，创造出源于自然高于自然的艺术品。陈氏插花的造型讲究“三主枝”结构，第一主枝决定作品的高度和气势，第二主枝决定作品的宽度和姿态，第三主枝决定作品的深度和层次。色彩讲究和谐统一，或清雅淡泊，或明快热烈，根据用途和场合而定。意境是陈氏插花的最高追求，通过花材的组合和造型，表达某种情感和理念，如“岁寒三友”表现坚韧品格，“花开富贵”表达美好祝愿。陈氏插花不仅是装饰艺术，更是修身养性的方式。', '/pictures/龙泉陈氏插花.webp', '2025-07-04 00:00:00.000000', '县级', NULL);
INSERT INTO `ich_project` VALUES (2021, '安仁鱼头烹制技艺', '龙泉市', '安仁鱼头烹制技艺是流传于浙江省龙泉市安仁镇的传统烹饪技艺，以当地水库鳙鱼头为主料，配以独特调料烹制，鱼头肥美，汤汁鲜醇，已有上百年历史。安仁镇地处瓯江上游，水质清澈，盛产鳙鱼，这种鱼头大肉嫩，最适合做鱼头菜肴。安仁鱼头烹制选用五斤以上的鲜活鳙鱼，只取鱼头，约重两至三斤。烹制时，先将鱼头洗净，用盐、料酒腌制去腥。热锅下猪油，爆香姜蒜，放入鱼头两面煎至金黄，烹入黄酒，加入高汤、豆腐、笋片、香菇等配料，大火烧开转小火慢炖半小时，使汤汁浓白，鱼肉酥烂。最后加入盐、胡椒粉调味，撒上葱花即可出锅。安仁鱼头的独特之处在于“一锅两吃”，先吃鱼头和豆腐，再用浓汤涮食各种蔬菜。', '/pictures/安仁鱼头烹制技艺.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2022, '安仁木雕彩绘', '龙泉市', '安仁木雕彩绘是流传于浙江省龙泉市安仁镇的传统工艺，集木雕和彩绘于一体，用于装饰建筑构件和家具，已有数百年历史。安仁木雕以当地产的樟木、银杏木等为原料，这种木材质地细腻，不易变形开裂，适合精细雕刻。雕刻技法有浮雕、透雕、圆雕等，题材有龙凤呈祥、麒麟送子、福禄寿喜、戏曲人物、花鸟鱼虫等，图案精美，寓意吉祥。彩绘是在木雕完成后施以色彩，使用矿物颜料，经打底、上色、勾线、贴金等多道工序，使木雕更加绚丽夺目。安仁木雕彩绘主要应用于祠堂、庙宇、民居的梁枋、雀替、门窗、家具等处，既有装饰作用，又寄托了人们对美好生活的期盼。安仁镇至今保存着大量清代民国时期的木雕彩绘建筑。', '/pictures/安仁木雕彩绘.webp', '2025-07-04 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (2023, '道太花鼓戏', '龙泉市', '道太花鼓戏是流传于浙江省龙泉市道太乡的传统戏曲形式，以花鼓为伴奏乐器，载歌载舞，表演生活故事，已有两百多年历史。道太花鼓戏起源于民间歌舞，融合了当地民歌、小调、舞蹈等元素，形成了独特的艺术风格。表演时，演员手持花鼓，边敲边唱边舞，节奏明快，气氛热烈。唱腔以当地山歌小调为基础，有“花鼓调”“采茶调”“秧歌调”等十多种曲牌，旋律优美动听。剧目多为生活小戏，如《打猪草》《捡螺蛳》《卖花线》等，表现农民的日常生活和爱情故事，语言幽默风趣，表演生动活泼。道太花鼓戏的演员都是当地农民，农忙时劳作，农闲时排练演出，自娱自乐。每逢节庆庙会，道太花鼓戏班都会搭台演出，深受群众欢迎。', '/pictures/道太花鼓戏.webp', '2025-07-04 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (2024, '查田馄饨制作技艺', '龙泉市', '查田馄饨制作技艺是流传于浙江省龙泉市查田镇的传统小吃技艺，以皮薄馅大、汤鲜味美著称，是当地特色早点，已有上百年历史。查田馄饨的制作分为皮、馅、汤三部分。馄饨皮用高筋面粉加鸡蛋和面，反复揉制，擀成薄如蝉翼的面皮，切成长方形状。馅料选用猪后腿肉，手工剁成肉茸，加入盐、酱油、葱姜水、香油等调料，朝一个方向搅拌上劲。包馄饨时，用竹签挑少许肉馅放在皮子一角，顺势一卷一捏，瞬间完成，形如元宝。汤底用猪骨、鸡架熬制数小时，汤色乳白，鲜香浓郁。馄饨入沸水煮熟，捞出放入碗中，浇上热汤，撒上葱花、紫菜、蛋皮丝、虾皮等配料。查田馄饨的独特之处在于“一清二白三红四绿”，汤清、皮白、馅红、葱绿，色香味俱全。', '/pictures/查田馄饨制作技艺.webp', '2025-07-04 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (2025, '高机与吴三春传说', '龙泉市', '高机与吴三春传说是流传于浙江省龙泉市的民间文学，讲述一对青年男女的爱情故事，在浙南地区广为流传，已有数百年历史。传说讲述明代龙泉织绸工匠高机，受雇于平阳吴员外家织绸，与吴家小姐吴三春相爱。两人私定终身后，高机回乡备婚。不料吴员外将三春许配给富家子弟，三春不从，写下血书寄给高机。高机赶往平阳，两人相约私奔，途中被追兵赶上。三春为保全高机，纵身跳入瓯江殉情。高机悲痛欲绝，终身不娶，每年清明到江边祭奠。这个传说情节曲折，情感真挚，歌颂了忠贞不渝的爱情，在浙南地区家喻户晓。传说有多种版本流传，后被改编成越剧、瓯剧等戏曲剧目，影响广泛。高机与吴三春传说不仅是民间文学瑰宝，也是研究浙南地区社会历史的重要资料。', '/pictures/高机与吴三春传说.webp', '2025-07-04 00:00:00.000000', '县级', '民间文学');
INSERT INTO `ich_project` VALUES (3002, '刘伯温传说', '青田县', '刘伯温传说是流传于浙江省青田县及浙南地区的民间口头文学，是关于明代开国元勋刘基（字伯温）的一系列传说故事，已有六百多年历史。刘基是青田县南田乡（今属文成县）人，明代开国功臣，以神机妙算著称，民间尊为“刘国师”“刘青田”。刘伯温传说内容丰富，有关于他出生和少年时期的神异传说，如“金童投胎”“天书传授”；有关于他辅佐朱元璋建立明朝的传说，如“火烧庆功楼”“施耐庵赠剑”；有关于他与家乡关系的传说，如“青田石传说”“太鹤山传说”；还有关于他死后显灵的传说。这些传说塑造了一个足智多谋、忠君爱民、能掐会算的智者形象，反映了民众对智慧和正义的崇敬。刘伯温传说情节曲折，语言生动，在浙南地区家喻户晓。2008年，刘伯温传说被列入国家级非物质文化遗产代表性项目名录。', '/pictures/刘伯温传说.webp', '2008-06-01 00:00:00.000000', '国家级', '民间文学');
INSERT INTO `ich_project` VALUES (3003, '青田鱼灯舞', '青田县', '青田鱼灯舞是流传于浙江省青田县的传统舞蹈，舞者手持扎制的鱼形彩灯，模仿江河中鱼类的生活习性进行表演，已有七百多年历史。青田鱼灯舞起源于南宋，最初是渔民祈求丰收的祭祀活动，后发展成节庆表演。鱼灯用竹篾扎制骨架，外糊彩纸或彩绸，绘有鱼鳞、鱼眼、鱼鳍，内点蜡烛，形态逼真。鱼灯种类有鲤鱼、鲢鱼、草鱼、青鱼等十多种，每种鱼大小不一，最大的鲤鱼灯长达两米。表演时，由一人持龙珠引路，数十人手持各色鱼灯，在锣鼓声中做出“鱼戏水”“鱼抢食”“鱼产卵”“鱼跃龙门”等动作，模拟鱼类的生活习性。队形变化丰富，有“单龙入海”“双凤朝阳”“八卦阵”等多种图案。夜间表演时，鱼灯内烛光闪烁，犹如鱼群在水中游动，美不胜收。2008年，青田鱼灯舞被列入国家级非物质文化遗产代表性项目名录。', '/pictures/青田鱼灯舞.webp', '2008-06-01 00:00:00.000000', '国家级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (3004, '青田百鸟灯舞', '青田县', '青田百鸟灯舞是流传于浙江省青田县的传统舞蹈，舞者手持扎制成各种鸟形的彩灯，模拟百鸟争鸣、展翅飞翔的生动场景，已有三百多年历史。青田百鸟灯舞起源于清代，最初是祭祀鸟神的仪式，后发展成节庆表演。百鸟灯用竹篾扎制骨架，外糊彩绸，彩绘羽毛、眼睛，内点蜡烛，形态逼真。鸟灯种类有凤凰、孔雀、仙鹤、锦鸡、画眉、喜鹊等数十种，每种鸟形态各异，色彩鲜艳。表演时，由一人持凤凰灯为领舞，其他人手持各种鸟灯，在丝竹乐伴奏下做出“百鸟朝凤”“凤凰展翅”“喜鹊登梅”“鸳鸯戏水”等动作，模仿各种鸟类的姿态。舞蹈动作轻盈优美，队形变化丰富，有“梅花五瓣”“八卦阵”“双龙戏珠”等图案。夜间表演时，百鸟灯内烛光闪烁，犹如百鸟在林间飞舞，美轮美奂。2014年，青田百鸟灯舞被列入国家级非物质文化遗产代表性项目名录。', '/pictures/青田百鸟灯舞.webp', '2014-12-01 00:00:00.000000', '国家级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (3005, '青田石雕', '青田县', '青田石雕是浙江省青田县的传统美术工艺品，以青田石为材料雕刻而成，是国家级非物质文化遗产。青田石产于青田县山口、方山一带，石质细腻温润，色彩丰富多样，有青、黄、红、白、黑等上百种颜色。青田石雕的技艺包括选料、构思、打坯、雕琢、修光、配座、打蜡等工序。选料讲究“相石”，根据石料的形状、色彩、纹理进行构思设计。打坯用大凿凿出粗坯，雕琢用各种刀具精雕细刻，修光用细刀打磨光滑。最具特色的是“因色取巧”，利用石料的不同颜色雕刻不同物象，使作品浑然天成。青田石雕题材广泛，有山水、人物、花鸟、走兽等。青田石雕作品构思巧妙，精巧细腻，既有传统题材，也有现代创新，是中国石雕艺术的重要代表。', '/pictures/青田石雕.webp', '2005-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (3006, '青田鱼灯', '青田县', '青田鱼灯舞是浙江省青田县的传统舞蹈，舞者手持鱼形彩灯表演，热烈奔放，是国家级非物质文化遗产。青田鱼灯舞起源于南宋，最初是渔民祈求丰收的祭祀活动。鱼灯用竹篾扎制骨架，外糊彩纸，绘有鱼鳞、鱼眼、鱼鳍，内点蜡烛，形态逼真。鱼灯种类有鲤鱼、鲢鱼、草鱼、青鱼等十多种。表演时，在锣鼓声中做出“鱼戏水”“鱼抢食”“鱼跃龙门”等动作，模拟鱼类的生活习性。队形变化丰富，有“单龙入海”“双凤朝阳”“八卦阵”等图案。青田鱼灯舞动作热烈奔放，节奏明快，具有浓郁的渔乡风情，是青田最具代表性的民间舞蹈。', '/pictures/青田鱼灯.webp', '2005-01-01 00:00:00.000000', '省级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (3007, '温溪传统刻字技艺', '青田县', '温溪传统刻字技艺是流传于浙江省青田县温溪镇的传统手工技艺，以木材为主要载体，进行文字雕刻，多用于制作匾额、楹联等，已有两百多年历史。温溪传统刻字技艺的工序包括选材、刨平、书写、过稿、刻字、修整、上色、保护等。选材多用樟木、银杏木等质地细腻的木材，要求无疤节、不变形。书写由擅长书法的人直接用墨汁写在木板上，或写在纸上反贴过稿。刻字是最关键的环节，用各种刻刀雕刻出文字的轮廓和深度，有阴刻、阳刻、双钩等技法。阴刻是刻去文字部分，使文字凹陷；阳刻是保留文字部分，刻去周围，使文字凸起；双钩是刻出文字轮廓，中间留平。刻好后要修整毛边，使文字边缘整齐光滑。最后上色，字面涂金粉或颜料，保护层刷清漆。温溪传统刻字技艺刀法洗练，字迹端庄，具有很高的艺术价值。', '/pictures/温溪传统刻字技艺.webp', '2023-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (3008, '太鹤传说', '青田县', '太鹤传说是流传于浙江省青田县的民间文学，与青田县城内的太鹤山密切相关，是关于地名由来、道教仙踪的传说故事，已有数百年历史。太鹤山古称“白鹤山”，因相传曾有白鹤栖息而得名。太鹤传说讲述古代有道士在此山修道，得道成仙后骑鹤飞升的故事。最著名的传说是“叶法善骑鹤升天”，讲述唐代道士叶法善在太鹤山修炼，最终骑鹤飞升成仙。另一传说是“刘伯温遇仙”，讲述刘基年轻时在太鹤山读书，遇见仙人指点，后来辅佐朱元璋建立明朝。太鹤山上至今留有“鹤栖洞”“炼丹井”“试剑石”等遗迹，都与这些传说有关。太鹤传说情节神奇，意境优美，将自然景观与道教文化、历史人物相结合，丰富了太鹤山的文化内涵，是青田地方文化的重要组成部分。', '/pictures/太鹤传说.webp', '2025-12-10 00:00:00.000000', '县级', '民间文学');
INSERT INTO `ich_project` VALUES (3009, '海溪山歌', '青田县', '海溪山歌是流传于浙江省青田县海溪乡的传统音乐，以当地方言演唱，内容多为劳动、爱情和生活感悟，曲调质朴动听，已有数百年历史。海溪地处山区，交通不便，山歌成为当地群众表达情感、传递信息的重要方式。海溪山歌的曲调以当地民歌为基础，融合了周边地区的音乐元素，形成了独特的风格。其旋律优美流畅，节奏自由灵活，有独唱、对唱、齐唱等多种形式。歌词多为七言四句，讲究押韵，比喻生动，情感真挚。劳动歌如《采茶歌》表现采茶时的喜悦；情歌如《望郎歌》表达对心上人的思念；生活歌如《劝世歌》传递做人道理。对唱是海溪山歌最具特色的形式，男女青年在山间地头一唱一和，互相试探，表达爱慕之情。海溪山歌没有固定的曲谱，全凭口头传承，即兴编唱。', '/pictures/海溪山歌.webp', '2025-12-10 00:00:00.000000', '县级', '传统音乐');
INSERT INTO `ich_project` VALUES (3010, '阜山花棍舞', '青田县', '阜山花棍舞是流传于浙江省青田县阜山乡的传统舞蹈，舞者手持装饰彩带的花棍，边舞边击打身体各部位，节奏明快，已有两百多年历史。花棍用竹竿制成，长约一米，两端挖孔，孔中串有铜钱，棍身缠绕彩色绸带，舞动时哗哗作响。阜山花棍舞起源于清代，最初是乞丐乞讨时的表演，后发展成节庆舞蹈。表演时，舞者手持花棍，随着锣鼓节奏，用花棍击打肩、背、腰、腿、脚等部位，同时做出跳跃、转身、蹲起等动作。击打部位不同，发出的声音也不同，形成独特的节奏。舞蹈动作有“雪花盖顶”“古树盘根”“鲤鱼翻背”“金鸡独立”等数十种。可以单人表演，也可以多人集体表演。集体表演时队形变化丰富，有“一字长蛇”“二龙戏珠”“八卦阵”等图案。阜山花棍舞动作活泼，节奏明快，具有浓郁的乡土气息。', '/pictures/阜山花棍舞.webp', '2025-12-10 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (3011, '叶店筒龙', '青田县', '叶店筒龙是流传于浙江省青田县舒桥乡叶店村的传统舞蹈，以竹筒连接成龙身，舞动时竹筒相击发声，独具特色，已有两百多年历史。筒龙用毛竹制成，将竹筒锯成约一尺长的段，每段两端打通，用绳索连接成串，龙头、龙尾用竹篾扎制，外糊彩纸。整条龙长约二十米，由二十多节竹筒组成。表演时，由一人持龙珠引路，十余人手持筒龙，在锣鼓声中舞动。舞动时竹筒相击，发出“哗啦哗啦”的响声，节奏明快，气势不凡。筒龙的舞法与布龙相似，有“龙抬头”“龙摆尾”“龙翻身”“龙戏珠”等动作。由于竹筒相连，筒龙的摆动幅度比布龙更大，动作更加夸张。夜间表演时，竹筒内点蜡烛，整条龙通体透亮，竹筒相击的声音和烛光摇曳的景象相得益彰。叶店筒龙舞动时声响独特，视觉震撼，是青田民间舞蹈的瑰宝。', '/pictures/叶店筒龙.webp', '2025-12-10 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (3012, '腊口灯彩', '青田县', '腊口灯彩制作技艺是流传于浙江省青田县腊口镇的传统手工技艺，以竹篾扎制骨架，糊以彩纸或绸缎，制作各种造型的彩灯，已有三百多年历史。腊口灯彩的种类繁多，有龙灯、鱼灯、鸟灯、走马灯、宫灯、纱灯等数十种。制作工序包括设计、破篾、扎架、糊纸、彩绘、装饰等。设计要构思造型和尺寸；破篾将竹子劈成粗细均匀的篾条；扎架用篾条扎出灯的基本骨架，要求结构牢固、比例准确；糊纸用糨糊将彩纸或绸缎平整地糊在骨架上；彩绘用颜料在灯面上绘制图案；装饰用流苏、珠串等点缀。腊口灯彩的独特之处在于“动”，走马灯利用空气对流原理，灯内画面可自动旋转；“滚龙灯”通过齿轮传动，龙身可蜿蜒摆动。每逢元宵佳节，腊口镇都要举办灯会，各式彩灯争奇斗艳，流光溢彩，吸引了周边数万群众观赏。', '/pictures/腊口灯彩.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3013, '千峡湖鱼头烹饪技艺', '青田县', '千峡湖鱼头烹饪技艺是流传于浙江省青田县北山镇的传统烹饪技艺，选用千峡湖出产的优质鳙鱼头，配以当地独特佐料烹制，鱼头肥美，汤汁鲜醇，已有上百年历史。千峡湖是瓯江上游的大型水库，水质清澈，盛产鳙鱼，这种鱼头大肉嫩，最适合做鱼头菜肴。千峡湖鱼头烹制选用五斤以上的鲜活鳙鱼，只取鱼头，约重两至三斤。烹制时，先将鱼头洗净，用盐、料酒腌制去腥。热锅下猪油，爆香姜蒜，放入鱼头两面煎至金黄，烹入黄酒，加入千峡湖水、豆腐、笋片、香菇等配料，大火烧开转小火慢炖半小时，使汤汁浓白，鱼肉酥烂。最后加入盐、胡椒粉调味，撒上葱花即可出锅。千峡湖鱼头的独特之处在于使用千峡湖的天然湖水炖煮，水质清甜，使鱼汤格外鲜美。', '/pictures/千峡湖鱼头烹饪技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3014, '懒汉包子制作技艺', '青田县', '懒汉包子制作技艺是流传于浙江省青田县船寮镇的传统面点技艺，以独特发酵方法和馅料配方制作，包子松软可口，已有上百年历史。懒汉包子的名字源于一个传说：从前有个懒汉，懒得每天发面，就把老面一直留着，每天往里加新面，结果发现这样发出来的面格外松软，包子格外好吃。懒汉包子的独特之处在于“老面发酵”和“三醒三揉”。老面是每次发面留下的面引子，日积月累，蕴含丰富的酵母菌和乳酸菌，发酵出的面团香气浓郁。制作时，先用温水化开老面，加入面粉揉成面团，第一次醒发两小时。然后加新面粉和水再次揉制，第二次醒发一小时。再加面粉揉制，第三次醒发半小时。经过三次醒发三次揉制，面团内部产生丰富的蜂窝组织，蒸出的包子格外松软。馅料选用猪前腿肉，手工剁馅，加入酱油、葱姜、香油等调料，鲜香多汁。', '/pictures/懒汉包子制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3015, '瓯青醇老酒汗酿造技艺', '青田县', '瓯青醇老酒汗酿造技艺是流传于浙江省青田县高湖镇的传统酿酒技艺，以糯米为原料，经发酵、蒸馏提取酒汗（白酒），酒香浓郁，已有两百多年历史。老酒汗是黄酒蒸馏后得到的白酒，因其蒸馏时最先流出的酒液如同汗水，故称“酒汗”。瓯青醇老酒汗的酿造工序包括浸米、蒸饭、摊凉、拌曲、入缸发酵、压榨取酒、蒸馏取汗、陈化老熟等。选用当地优质糯米，浸泡后蒸熟，摊凉至适宜温度，拌入红曲和麦曲，入缸发酵。发酵期约两个月，期间要定时搅拌，控制温度。发酵完成后压榨取酒，得到黄酒。再将黄酒倒入蒸馏锅，加热蒸馏，最先流出的酒液就是“酒汗”，酒精度高达六十度以上。酒汗装入陶坛，密封陈化三年以上，使酒质更加醇和。瓯青醇老酒汗无色透明，酒香浓郁，入口醇厚，回味悠长。', '/pictures/瓯青醇老酒汗酿造技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3016, '青田美丽琼酿造技艺', '青田县', '青田美丽琼酿造技艺是流传于浙江省青田县高市乡的传统酿酒技艺，酿制特色米酒，在当地颇有名气，已有上百年的历史。美丽琼是一种甜型黄酒，以其色泽金黄、香气芬芳、口感甜美而得名。酿造技艺包括浸米、蒸饭、摊凉、拌曲、入缸发酵、榨酒、澄清、煎酒、陈化等工序。选用当地优质糯米，淘洗干净后浸泡过夜，使米粒充分吸水。蒸饭用木甑蒸熟，要求饭粒熟透而不烂。摊凉将蒸好的米饭摊开降温，至适合发酵的温度。拌曲加入特制的酒曲，有麦曲和红曲两种，麦曲赋予酒香，红曲赋予酒色。入缸发酵是核心环节，要控制好温度和湿度，使发酵顺利进行。发酵约一周后榨取酒液，澄清数日，去除沉淀。煎酒是杀菌和定型的工序，将酒液加热到八十度左右，杀灭酵母菌，停止发酵。最后装坛密封，陈化数月使酒质更加醇和。', '/pictures/青田美丽琼酿造技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3017, '青田传统小吃制作技艺', '青田县', '青田传统小吃制作技艺是流传于浙江省青田县的各种特色小吃的制作方法，体现了青田饮食文化，已有数百年历史。青田小吃种类繁多，有山粉饺、青田麦饼、青田糖糕、青田豆腐丸等数十种。山粉饺以红薯淀粉为皮，包入肉馅，形如元宝，煮熟后晶莹剔透，口感滑嫩。青田麦饼用面粉和猪油揉制，包入梅干菜肉馅，擀成薄饼，烙至两面金黄，外酥里嫩。青田糖糕用糯米粉和红糖蒸制，加入红枣、核桃等果料，甜而不腻。青田豆腐丸以豆腐为主料，加入肉末、香菇等，捏成丸子，煮汤食用，鲜嫩爽滑。这些小吃制作技艺各有特色，但都讲究选料精细、制作考究、口味地道。青田是著名侨乡，这些传统小吃不仅在当地深受喜爱，也随着华侨远渡重洋，传播到世界各地，成为海外游子寄托乡愁的载体。', '/pictures/青田传统小吃制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3018, '粽叶加工技艺', '青田县', '粽叶加工技艺是流传于浙江省青田县的传统手工技艺，包括粽叶的采摘、晾晒、整理、保存等工序，为包粽子提供优质材料，已有数百年历史。青田山区盛产箬竹，其叶片宽大厚实，清香浓郁，是包粽子的最佳材料。粽叶加工技艺的第一步是采摘，每年端午前后，山民上山采摘新鲜箬叶，要求叶片完整、无虫蛀、无斑点。采摘时要轻采轻放，避免损伤叶片。第二步是晾晒，将采摘的箬叶摊放在阴凉通风处晾干，不能暴晒，否则叶片易脆裂。晾至半干时进行整理，剔除破损叶片，按大小分类。第三步是煮叶，将晾干的箬叶放入沸水中煮几分钟，使其软化并杀菌。第四步是再次晾晒，煮过的叶片摊开晾干，此时叶片变得柔软有韧性。第五步是扎捆，将晾干的叶片按一定数量扎成小捆，便于储存和使用。加工好的粽叶清香浓郁，柔韧耐用，可长期保存。', '/pictures/粽叶加工技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3019, '笋咸制作技艺', '青田县', '笋咸制作技艺是流传于浙江省青田县的传统食品加工技艺，以竹笋为原料，经腌制、晾晒等工序制成咸笋，便于保存，已有数百年历史。青田山区盛产竹笋，春笋、冬笋产量丰富，但鲜笋不易保存。笋咸制作技艺就是为了解决笋的保存问题而发明的。制作工序包括采笋、剥壳、切片、焯水、腌制、晾晒、回软、复晒等。采笋要选鲜嫩的竹笋，剥去外壳，切成薄片或条状。焯水是将笋片放入沸水中煮几分钟，去除涩味。腌制是核心环节，将焯水后的笋片与盐按比例混合，充分揉搓，使盐分渗入笋中，然后装入缸中压实，腌制数天。晾晒是将腌好的笋片摊开在竹匾上，在阳光下晒干。晒至半干时收回，让笋片回软，再进行第二次晾晒，直至完全干燥。制成的笋咸咸香适口，可以长期保存，食用时用水泡发，可炒可炖，风味独特。', '/pictures/笋咸制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3020, '寿桃制作技艺', '青田县', '寿桃制作技艺是流传于浙江省青田县的传统面点技艺，以面粉制作寿桃形状，用于祝寿、节庆等场合，已有数百年历史。寿桃寓意长寿吉祥，是青田民间祝寿必不可少的礼品。寿桃制作技艺包括和面、发酵、调色、塑形、蒸制、点彩等工序。和面用面粉加老面发酵，使面团松软有弹性。调色用食用色素或天然果蔬汁，将面团染成桃红色和绿色。塑形是最关键的环节，将红色面团包入豆沙馅，捏成桃形，用绿色面团做成桃叶贴在底部。寿桃的大小根据寿星的年龄而定，一般一岁一个，也有做成大寿桃周围簇拥小寿桃的造型。塑形好的寿桃要二次醒发，然后上笼蒸熟。蒸好的寿桃饱满圆润，色泽鲜艳。最后用红色颜料在桃尖点彩，更加逼真。青田寿桃不仅造型逼真，而且口感松软香甜，既是食品，又是艺术品。', '/pictures/寿桃制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3021, '清明果制作技艺', '青田县', '清明果制作技艺是流传于浙江省青田县的传统节令食品技艺，以鼠曲草或艾草汁和糯米粉制成外皮，包入馅料，蒸制而成，用于清明祭祀和食用，已有数百年历史。清明果的制作工序包括采草、洗草、煮草、捣汁、和面、制馅、包制、蒸制等。采草在清明前后，采摘鲜嫩的鼠曲草或艾草，洗净后入沸水煮软，捞出捣烂成泥，或用石臼捣出汁液。将草泥或草汁与糯米粉混合，加入适量白糖，揉成绿色的面团，这是清明果的外皮。馅料有甜咸两种，甜馅常用红豆沙，咸馅常用笋丁、肉末、香菇等炒制。包制时，取一小团面皮，捏成碗状，包入馅料，收口搓圆，放入刻有花纹的模具中压印成形。成形后的清明果垫上粽叶，上笼蒸熟。蒸好的清明果色泽碧绿，清香扑鼻，口感软糯，甜咸皆宜。', '/pictures/清明果制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3022, '黄山头绿茶制作技艺', '青田县', '黄山头绿茶制作技艺是流传于浙江省青田县章村乡黄山头村的传统制茶技艺，以当地茶树鲜叶为原料，经杀青、揉捻、干燥等工序制成绿茶，已有数百年历史。黄山头村海拔六百多米，常年云雾缭绕，土壤富含有机质，是优质茶叶的理想产地。黄山头绿茶选用当地群体种茶树，清明前后采摘一芽一叶或一芽二叶。制作技艺包括摊青、杀青、揉捻、初烘、复烘、提香等工序。摊青将鲜叶摊放数小时，使水分适度蒸发。杀青用铁锅高温炒制，破坏酶活性，固定茶叶品质。揉捻用手工或揉捻机使茶叶卷曲成条，促进茶汁溢出。初烘用炭火低温烘干，去除大部分水分。复烘再次烘干，使茶叶足干。提香用高温短时烘焙，激发茶叶香气。黄山头绿茶外形条索紧结，色泽翠绿，汤色清澈明亮，香气清高持久，滋味鲜爽醇厚，叶底嫩绿匀整。', '/pictures/黄山头绿茶制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3023, '章旦伯温茶制作技艺', '青田县', '章旦伯温茶制作技艺是流传于浙江省青田县章旦乡的传统制茶技艺，相传与明代开国元勋刘伯温有关，茶叶品质独特，已有六百多年历史。据传刘伯温回乡省亲时，发现章旦乡的茶叶品质优良，便指导当地茶农改进制茶技艺，从此章旦茶声名鹊起，被称为“伯温茶”。章旦伯温茶选用生长在海拔六百米以上的高山茶树，采摘标准严格，只取一芽一叶。制作技艺包括萎凋、杀青、揉捻、烘焙等多道工序，全部手工完成。其独特之处在于“三炒三揉”工艺：鲜叶先经轻度萎凋，然后进行第一次炒制，温度较高，快速杀青；出锅后趁热揉捻，使茶叶初步成形；再进行第二次炒制，温度稍低，进一步蒸发水分；再次揉捻，使茶叶紧结；最后进行第三次炒制，温度更低，固定形状，激发香气。章旦伯温茶外形紧结匀整，色泽绿润，汤色嫩绿明亮，香气清雅持久。', '/pictures/章旦伯温茶制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3024, '青田传统腌制技艺', '青田县', '青田传统腌制技艺是流传于浙江省青田县的传统食品加工技艺，用于腌制各种蔬菜、肉类，延长保质期并形成特殊风味，已有数百年历史。青田山区物产丰富，但保鲜不易，腌制成为保存食物的重要方法。腌制技艺包括盐腌、酱腌、糟腌等多种方法，适用于不同的食材。盐腌是最基本的方法，将蔬菜洗净晾干，与盐层层叠放，压实密封，通过盐的渗透作用抑制微生物生长。酱腌是将食材浸入酱油、豆瓣酱等酱料中腌制，既有咸味又有酱香。糟腌是用酒糟腌制食材，使食物带有酒香。青田传统腌制的代表性产品有腌菜、腌笋、腌肉、腌鱼等。腌菜用芥菜或白菜腌制，酸香开胃；腌笋用竹笋腌制，咸鲜脆嫩；腌肉用猪肉腌制，咸香耐存；腌鱼用溪鱼腌制，风味独特。这些腌制食品是青田人餐桌上的常客。', '/pictures/青田传统腌制技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3025, '竹排制作技艺', '青田县', '竹排制作技艺是流传于浙江省青田县祯埠镇的传统手工技艺，以毛竹为材料，经火烤、捆绑等工序制作水上交通工具竹排，已有数百年历史。青田境内溪流众多，竹排曾是重要的水上交通工具，用于载人运货。竹排制作技艺包括选竹、砍竹、火烤、矫直、打孔、穿藤、捆绑等工序。选竹要选生长三年以上的毛竹，竹身粗直，无虫蛀。砍竹在秋冬季节，此时竹子含水量低，不易生虫。火烤是制作竹排的关键环节，将竹子放在炭火上慢慢烘烤，边烤边矫直，使弯曲的竹子变得笔直。打孔在竹子两端和中部钻出小孔，用于穿藤连接。穿藤用野生的藤条穿过竹孔，将多根竹子并排连接在一起。捆绑用藤条将竹排的横档与纵竹捆绑牢固。制作好的竹排长约五六米，宽约一米多，可载数人。竹排轻便灵活，吃水浅，适合在浅水溪流行驶。', '/pictures/竹排制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3026, '祯旺红糖制作技艺', '青田县', '祯旺红糖制作技艺是流传于浙江省青田县祯旺乡的传统制糖技艺，以甘蔗为原料，经压榨、熬制、结晶等工序制成红糖，已有两百多年历史。祯旺乡气候温暖，土壤肥沃，适宜甘蔗种植。每年冬至前后，甘蔗成熟，是榨糖的最佳时节。红糖制作技艺包括砍蔗、清洗、压榨、过滤、熬制、打砂、成型等工序。砍蔗要选成熟度适中的甘蔗，去叶洗净。压榨用石碾或木榨机压出甘蔗汁，收集到缸中。过滤去除甘蔗汁中的杂质，得到纯净的蔗汁。熬制是最关键的环节，将蔗汁倒入大铁锅中，用柴火熬煮，不断搅拌，使水分蒸发，糖浆逐渐浓稠。熬至糖浆起大泡时，加入少量石灰中和酸度，继续熬至起小泡，糖浆呈琥珀色。打砂是将熬好的糖浆倒入木槽，快速搅拌，使其结晶成细砂状。成型将打砂后的红糖倒入模具，压实晾凉，切成块状。祯旺红糖色泽红褐，香甜醇厚。', '/pictures/祯旺红糖制作技艺.webp', '2025-12-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (3027, '侨乡出国习俗', '青田县', '侨乡出国习俗是浙江省青田县作为著名侨乡形成的独特民俗，包括出国前的祭祀、饯行，海外侨胞与家乡的联系等系列习俗，已有上百年历史。青田是著名侨乡，全县有三十多万人侨居海外。长期的出国潮形成了独特的出国习俗。出国前，要祭拜祖先，告知即将远行，祈求祖先保佑。要拜访亲友，接受饯行和祝福。要带上一包家乡的泥土，寄托思乡之情。出发当天，家人要送至村口，燃放鞭炮送行。侨胞在国外，要保持与家乡的联系，定期寄信寄钱，过年过节回国探亲。侨胞回乡时，要带礼物分送亲友，要修桥铺路回报乡里。侨胞去世后，要将其遗物带回故乡安葬，或者将骨灰送回故土。这些习俗维系着侨胞与家乡的情感纽带，形成了独特的侨乡文化。侨乡出国习俗是青田人闯荡世界的见证，也是家国情怀的生动体现。', '/pictures/侨乡出国习俗.webp', '2025-12-10 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (3028, '青田畲族婚嫁习俗', '青田县', '青田畲族婚嫁习俗是流传于浙江省青田县畲族聚居区的传统婚庆民俗，包括说亲、定亲、迎亲、拜堂、回门等系列仪式，富有民族特色，已有数百年历史。畲族婚嫁习俗以“歌”贯穿始终，有“以歌为媒”“以歌代言”之说。说亲时，男方请媒人到女方家提亲，双方父母同意后，择日“定亲”。定亲时，男方送聘礼到女方家，女方设宴款待，双方对唱山歌表示祝贺。迎亲是婚礼的高潮，新郎带着迎亲队伍到新娘家接亲，要经过“拦门”“对歌”“讨酒”等关卡，才能接到新娘。新娘头戴凤冠，身着盛装，由兄长背出家门，哭别父母。到男方家后，举行拜堂仪式，一拜天地，二拜高堂，夫妻对拜，然后送入洞房。当晚要闹洞房，亲友们唱山歌、做游戏，祝福新人。婚后三天，新婚夫妇回门，拜见女方父母。', '/pictures/青田畲族婚嫁习俗.webp', '2025-12-10 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (3029, '青田卢家拳', '青田县', '青田卢家拳是流传于浙江省青田县的传统体育项目，由卢氏家族世代相传的拳术，套路完整，注重实战，已有两百多年历史。卢家拳起源于清代，由卢氏先祖创编，融合了南拳和北腿的特点，形成了独特的风格。卢家拳的套路有“五虎拳”“四门拳”“梅花拳”等十多种，动作刚劲有力，步法稳健灵活。其特点是“手从口出，拳从心发”，讲究发力短促，劲力完整。套路中既有大开大合的舒展动作，也有紧凑小巧的近身打法。卢家拳还包括多种器械套路，如单刀、双刀、棍术、枪术等，器械与拳术一脉相承，讲究“刀如猛虎，棍如游龙”。卢家拳注重实战，每一招每一式都有明确的攻防含义。练习卢家拳不仅可以强身健体，还可以防身自卫。卢家拳世代口传身授，保持了完整的传承体系。', '/pictures/青田卢家拳.webp', '2021-10-01 00:00:00.000000', '市级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (4002, '畲族民歌', '云和县', '云和畲族民歌是流传于浙江省云和县畲族聚居区的传统音乐，以畲语演唱，内容涉及爱情、劳动、生活、历史等，是畲族人民“以歌代言”的文化传统，已有数百年历史。云和畲族民歌的曲调优美动听，节奏自由灵活，有独唱、对唱、齐唱等多种形式。歌词多为七言四句，讲究押韵，比喻生动，情感真挚。内容十分丰富，有劳动歌如《采茶歌》《砍柴歌》，表现了畲民劳动的艰辛和快乐；有情歌如《相思歌》《送郎歌》，表达了青年男女的爱慕之情；有礼俗歌如《敬酒歌》《哭嫁歌》，在婚丧嫁娶等场合演唱；还有叙事长歌如《高皇歌》讲述畲族始祖盘瓠的传说，是畲族历史的活化石。对唱是畲族山歌最具特色的形式，男女青年在山间地头一唱一和，互相试探，表达爱慕之情。云和畲族民歌没有固定的曲谱，全凭口头传承，即兴编唱。', '/pictures/畲族民歌.webp', '2009-01-01 00:00:00.000000', '省级', '传统音乐');
INSERT INTO `ich_project` VALUES (4003, '云和八步洪拳', '云和县', '云和八步洪拳是流传于浙江省云和县的传统体育项目，拳术套路完整，注重实战，在云和当地流传已有两百多年历史。八步洪拳属于南拳流派，相传由清代洪门高手传入云和，经当地拳师改良发展而成。这套拳法的特点是“拳打八步，脚踩八卦”，以八步为进退范围，以八卦为步法变化，动作刚劲有力，步法灵活多变。八步洪拳的基本功包括马步、弓步、虚步、歇步等步法，以及冲拳、劈拳、撩拳、砸拳等手法。套路有“八步连环拳”“八步洪拳一路”“八步洪拳二路”等，每套拳都由数十个动作组成，连贯流畅，气势磅礴。八步洪拳还包括器械套路，如八步单刀、八步双刀、八步棍法等。云和八步洪拳世代口传身授，保持了完整的传承体系，是云和武术文化的重要代表。', '/pictures/云和八步洪拳.webp', '2016-01-01 00:00:00.000000', '省级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (4004, '瓯江水上蛟龙节', '云和县', '瓯江水上蛟龙节是流传于浙江省云和县沿瓯江地区的端午节传统民俗活动，包括龙舟竞渡、水上巡游、祭江祈福等内容，场面壮观，已有数百年历史。瓯江是云和的母亲河，两岸百姓世代依水而生。每年端午节，沿江各村都要举办水上蛟龙节，祈求风调雨顺、平安吉祥。节日当天清晨，各村先在本村的龙王庙举行祭祀仪式，焚香点烛，献上供品，祈求龙王保佑。然后抬出龙舟，放入江中。龙舟狭长如梭，船头雕有龙头，船尾装有龙尾，船身彩绘龙鳞，威武雄壮。每条龙舟有二十多名划手，一人击鼓指挥，一人敲锣助威，一人掌舵定向。随着一声号令，各条龙舟如离弦之箭，在江面上劈波斩浪，奋力向前。两岸观众呐喊助威，锣鼓声、欢呼声震天动地。龙舟竞渡后还有水上巡游，各色彩船在江中缓缓行进，船上表演各种节目。', '/pictures/瓯江水上蛟龙节.webp', '2023-01-01 00:00:00.000000', '省级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (4005, '云和传统银器錾刻技艺', '云和县', '云和传统银器錾刻技艺是流传于浙江省云和县的传统手工艺，以银为材料，用錾子雕刻各种图案纹饰，制作银饰品和器皿，已有两百多年历史。云和银器錾刻技艺的工序包括熔银、锻打、退火、錾刻、焊接、打磨、抛光等。熔银将银料熔化，倒入模具制成银条或银片。锻打用铁锤反复锻打，使银料密实均匀。退火将银料加热后自然冷却，消除内应力，便于加工。錾刻是最关键的环节，用各种形状的錾子，在银器表面敲击出图案纹饰。錾子有平錾、尖錾、圆錾、线錾等数十种，每种錾子敲出的线条和纹理不同。錾刻技法有阴錾、阳錾、镂空錾等，可錾出人物、花鸟、山水、文字等各种图案。焊接用银焊料将各个部件连接在一起。打磨用锉刀和砂纸将表面打磨光滑。抛光用布轮抛光，使银器光亮如镜。云和银器錾刻技艺制作的银器精美绝伦。', '/pictures/云和传统银器錾刻技艺.webp', '2025-01-24 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (4006, '云和米烧酿造技艺', '云和县', '云和米烧酿造技艺是流传于浙江省云和县的传统酿酒技艺，以大米为原料，经发酵、蒸馏酿制白酒，酒香醇厚，已有两百多年历史。云和米烧属于小曲白酒，以其清澈透明、醇和甘爽的特点深受当地群众喜爱。酿造技艺包括浸米、蒸饭、摊凉、拌曲、糖化、发酵、蒸馏、陈化等工序。选用当地优质籼米，淘洗干净后浸泡数小时。蒸饭用木甑蒸熟，要求饭粒熟透而不烂。摊凉将蒸好的米饭摊开降温，至适合发酵的温度。拌曲加入特制的小曲，这是米烧酿造的关键，曲的质量直接影响酒的品质。糖化将拌曲后的米饭装入缸中，保温糖化二十四小时，使淀粉转化为糖。发酵加水进行液态发酵，约七至十天，酒醅成熟。蒸馏将发酵好的酒醅倒入蒸馏锅，加热蒸馏，提取白酒。新蒸出的米烧酒精度高达五十度以上，需装入陶坛陈化半年以上，使酒质更加醇和。', '/pictures/云和米烧酿造技艺.webp', '2025-01-24 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4007, '云和县畲族服饰制作技艺', '云和县', '云和县畲族服饰制作技艺是流传于浙江省云和县畲族聚居区的传统手工艺，包括裁剪、刺绣、镶缀等工序，制作具有民族特色的畲族服装，已有数百年历史。畲族服饰以其色彩鲜艳、图案精美、工艺精湛而著称，是畲族文化的重要载体。畲族服饰制作技艺包括面料选择、裁剪、刺绣、镶边、缀饰等环节。面料多选用自织的麻布或棉布，也有用绸缎的。裁剪根据穿着者的身材和服饰款式，将布料剪裁成衣片。刺绣是最重要的装饰手段，用彩色丝线在衣领、袖口、襟边、围裙等处绣出各种图案。刺绣针法有平绣、锁绣、打籽绣、辫绣等数十种，图案有花卉、鸟兽、几何纹样等，寓意吉祥。镶边用不同颜色的布条镶在衣边，增加美观和牢固度。缀饰在服饰上缀以银饰、铜钱、彩带等，使服饰更加华丽。畲族服饰因性别、年龄、场合不同而有区别。', '/pictures/云和县畲族服饰制作技艺.webp', '2025-01-24 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4008, '白粿制作技艺', '云和县', '白粿制作技艺是流传于浙江省云和县的传统食品加工技艺，以糯米为原料，经浸泡、蒸煮、捣制等工序制成白粿，是当地节庆食品，已有数百年历史。白粿是云和人对年糕的称呼，因其色泽洁白而得名，是春节期间家家户户必备的传统食品。白粿制作技艺包括选米、浸米、蒸米、捣制、成形、晾晒等工序。选用优质糯米，淘洗干净后浸泡过夜，使米粒充分吸水。蒸米将浸泡好的糯米放入木甑中，用旺火蒸熟，要求米粒熟透而不烂。捣制是最关键的环节，将蒸好的糯米饭趁热倒入石臼，用木槌反复捣打。捣打要用力均匀，不断翻动，使米粒完全破碎，相互粘连，形成有韧性的米团。捣好的米团取出，在案板上搓成长条，切成块状，或用模具压成各种形状。成形后的白粿放在竹匾上晾晒，使其表面风干，便于保存。食用时可煎、可炒、可煮，口感软糯，米香浓郁。', '/pictures/白粿制作技艺.webp', '2025-01-24 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4009, '云和绿茶传统制作技艺（老茶树传统火培制作技艺）', '云和县', '云和绿茶传统制作技艺是以老茶树鲜叶为原料，采用传统火培工艺干燥的制茶技艺，茶叶香气独特，已有数百年历史。云和地处浙南山区，境内有许多百年以上的老茶树，这些老茶树根系深扎，吸收的矿物质丰富，茶叶内含物质丰厚，制成的茶叶品质优异。这项技艺包括采摘、摊青、杀青、揉捻、初烘、复烘等工序，全部手工完成。采摘在清明前后，选取一芽一叶或一芽二叶。摊青将鲜叶摊放数小时，使水分适度蒸发。杀青用铁锅高温炒制，破坏酶活性，固定茶叶品质。揉捻用手工揉搓，使茶叶卷曲成条，促进茶汁溢出。初烘用炭火低温烘干，去除大部分水分。最具特色的是“火培”工艺，将初烘后的茶叶放在竹焙笼上，用炭火慢火烘焙，使茶叶足干，同时激发茶叶的香气。火培的温度和时间全凭经验掌握，既要使茶叶干燥，又不能烤焦。制成的绿茶外形紧结，色泽灰绿，汤色黄绿明亮。', '/pictures/云和绿茶传统制作技艺（老茶树传统火培制作技艺）.webp', '2025-01-24 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4010, '大襟连拳术', '云和县', '大襟连拳术是流传于浙江省云和县的传统体育项目，拳术套路连绵不断，注重内外兼修，已有两百多年历史。大襟连拳属于内家拳流派，相传由清代云和拳师根据太极、形意、八卦等拳法融合创编而成。这套拳法的特点是“大襟相连，绵绵不断”，动作如行云流水，连贯流畅，没有停顿。大襟连拳的基本功包括桩功、步法、手法、身法等，强调以意导气，以气催力，内外合一。套路有“大襟连拳一路”“大襟连拳二路”“大襟连拳三路”等，每套拳都由数十个动作组成，动作之间衔接紧密，环环相扣。大襟连拳的技击特点是以柔克刚，借力打力，讲究“四两拨千斤”。练习大襟连拳不仅可以强身健体，还可以修身养性。大襟连拳世代口传身授，保持了完整的传承体系，是云和武术文化的重要组成部分。', '/pictures/大襟连拳术.webp', '2025-01-24 00:00:00.000000', '县级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (4011, '上刀山下火海', '云和县', '上刀山下火海是流传于浙江省云和县的传统民俗活动，表演者赤脚爬上刀梯、走过火海，展示勇气和信仰，具有祈福禳灾的寓意，已有数百年历史。这项活动通常在庙会或重大节日举行，由法师或勇士表演。上刀山时，场上竖起一根高约十米的木杆，杆上插着三十六把或七十二把锋利的钢刀，刀刃朝上。表演者赤脚踩在刀刃上，手攀刀背，一步步向上爬，直至杆顶。在杆顶做出各种惊险动作后，再踩着刀刃下来。下火海时，场上铺一条长约十米的炭火路，木炭烧得通红。表演者赤脚快速从炭火上走过，脚不受伤。有时还要表演“洗火脸”，用手捧起炭火洗脸；“舔火犁”，用舌头舔烧红的犁头。表演者认为，因为有神灵护佑，才能毫发无损。上刀山下火海既是对表演者勇气和信仰的考验，也是为全村祈福消灾的仪式。', '/pictures/上刀山下火海.webp', '2025-01-24 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (4012, '沙铺插花板龙', '云和县', '沙铺插花板龙是流传于浙江省云和县沙铺乡的传统舞蹈，以木板连接成龙身，板上插满鲜花装饰，舞动时花枝招展，独具特色，已有两百多年历史。沙铺板龙用木板做龙身，每块木板长约两米，宽约二十厘米，板与板之间用木栓连接，可以灵活转动。龙头用竹篾扎制骨架，外糊彩纸，彩绘龙鳞、龙眼、龙须，威武雄壮。龙尾也用竹篾扎制，高高翘起。最具特色的是龙身上的“插花”，每块木板上都插满用彩纸制作的各色花朵，有牡丹、莲花、菊花、梅花等，色彩鲜艳，形态逼真。整条龙长达数十米，由数十人舞动。表演时，一人持龙珠引路，舞者手持龙板，在锣鼓声中做出“龙抬头”“龙摆尾”“龙翻身”“龙戏珠”等动作。由于龙身插满鲜花，舞动时花枝招展，摇曳生姿，别有一番风味。夜间表演时，龙身内点蜡烛，鲜花在烛光映照下更加绚丽。', '/pictures/沙铺插花板龙.webp', '2025-01-24 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (4013, '七夕四夫人庙会', '云和县', '七夕四夫人庙会是流传于浙江省云和县石塘镇的传统民俗活动，七夕节期间祭祀四夫人，祈求姻缘美满、家庭和睦，已有数百年历史。四夫人是当地民间信仰中的四位女神，分别掌管婚姻、生育、子女、家庭。传说她们是四位姐妹，生前乐善好施，死后被奉为神灵。四夫人庙坐落在石塘镇的山坡上，每年七夕，远近信众都会前来进香祈福。庙会的主要仪式包括上供、诵经、求签、还愿等。信众们献上香烛、花果、糕点等供品，跪拜祈祷。年轻女子尤其重视这个节日，她们会向四夫人祈求美满姻缘。求签是庙会的重要环节，信众摇动签筒，抽出签条，由庙祝解签。还愿的民众则会献上锦旗、牌匾，或请戏班唱戏酬神。庙会期间还有民间艺术表演和特色小吃摊位，吸引了周边数万群众参与。七夕四夫人庙会融合了民间信仰和民俗文化。', '/pictures/七夕四夫人庙会.webp', '2025-01-24 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (4014, '龙母仙娘传说', '云和县', '龙母仙娘传说是流传于浙江省云和县的民间文学，讲述龙母仙娘的传奇故事，在当地广为流传，已有数百年历史。传说讲述古代有位女子在溪边洗衣，捡到一颗龙蛋，带回家中孵化，孵出五条小龙。女子精心喂养小龙，小龙长大后飞入瓯江，成为龙王。女子死后，五条龙王感念养育之恩，将母亲接上天庭，封为龙母仙娘。从此，龙母仙娘成为保佑水上平安、风调雨顺的神灵。云和瓯江沿岸建有多座龙母庙，渔民船工出航前都要进香祈祷。龙母仙娘传说还有多个版本，有的讲述龙母生前乐善好施，死后显灵救苦救难；有的讲述龙母与五龙子的母子情深。这些传说情节感人，寓意深刻，歌颂了母爱的伟大，反映了民众对平安幸福的期盼。龙母仙娘传说不仅是民间文学瑰宝，也是研究云和地方信仰的重要资料。', '/pictures/龙母仙娘传说.webp', '2021-10-01 00:00:00.000000', '市级', '民间文学');
INSERT INTO `ich_project` VALUES (4015, '畲族祭祖舞', '云和县', '畲族祭祖舞是流传于浙江省云和县畲族聚居区的传统舞蹈，在祭祀祖先时表演，舞蹈动作庄重肃穆，已有数百年历史。祭祖是畲族最重要的家族活动，每年农历三月三、五月五、八月十五等节日，各家族都要举行祭祖仪式。祭祖舞是祭祖仪式的重要组成部分，由族中长老带领，身着盛装的男女青年表演。舞蹈动作以模仿祖先生产生活为主，有开山、耕田、播种、收割、狩猎等，表现了祖先创业的艰辛。舞蹈队形变化丰富，有围圈、穿插、列队等，象征家族的团结和延续。伴奏乐器有锣、鼓、钹、唢呐等，节奏沉稳庄重。祭祖舞的歌词用畲语演唱，内容多是歌颂祖先功德、祈求祖先保佑。整个舞蹈过程肃穆庄严，表达了畲族人民对祖先的崇敬和怀念。畲族祭祖舞不仅是舞蹈艺术，更是维系家族凝聚力的重要方式。', '/pictures/畲族祭祖舞.webp', '2021-10-01 00:00:00.000000', '市级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (4016, '神像雕刻', '云和县', '神像雕刻是流传于浙江省云和县的传统美术技艺，以木材雕刻各类神像，用于宗教和民俗活动，已有数百年历史。云和神像雕刻选用樟木、银杏木等质地细腻的木材，这些木材不易变形开裂，适合精细雕刻。雕刻工序包括选材、设计、打坯、细雕、修光、打磨、上彩、装脏等。选材要根据神像大小选择合适的木料，要求无疤节、无裂纹。设计要根据神像的身份和姿态，在木料上画出轮廓。打坯用大凿凿出粗坯，确定神像的大体形状。细雕用各种刀具精雕细刻，刻出五官、衣纹、手势等细节。修光用细刀和砂纸将表面打磨光滑。上彩用矿物颜料给神像上色，不同神像有固定的色彩规制。装脏是神像雕刻的最后一道工序，在神像背部开孔，放入经卷、五谷、钱币等物，象征赋予神像生命。云和神像雕刻造型生动，神态庄严，具有很高的艺术价值。', '/pictures/神像雕刻.webp', '2021-10-01 00:00:00.000000', '市级', '传统美术');
INSERT INTO `ich_project` VALUES (4017, '云和传统小吃制作技艺', '云和县', '云和传统小吃制作技艺是流传于浙江省云和县的各种特色小吃的制作方法，体现了云和饮食文化，已有数百年历史。云和地处山区，物产丰富，形成了独具特色的地方小吃。最具代表性的有云和豆腐丸、云和油筒饼、云和麻糍、云和清明果等。云和豆腐丸以豆腐为主料，加入肉末、香菇、笋丁等，捏成丸子，煮汤食用，鲜嫩爽滑。制作时选用当地卤水豆腐，捣碎后加入配料，用手捏成圆形，入沸水煮熟，汤清味鲜。云和油筒饼以面粉和萝卜丝为原料，油炸制成，外酥里嫩。制作时将面粉调成糊，加入萝卜丝、葱花，舀入特制的油筒模具中，入油锅炸至金黄，香脆可口。云和麻糍以糯米为原料，经蒸煮、捣制、裹粉等工序制成，软糯香甜。这些小吃制作技艺各有特色，但都讲究选料精细、制作考究、口味地道。', '/pictures/云和传统小吃制作技艺.webp', '2021-10-01 00:00:00.000000', '市级', '传统技艺');
INSERT INTO `ich_project` VALUES (4018, '云和雪梨酒酿造技艺', '云和县', '云和雪梨酒酿造技艺是流传于浙江省云和县的传统酿酒技艺，以当地特产雪梨为原料，经发酵酿制成果酒，已有上百年历史。云和雪梨是云和特产，果大皮薄，肉质细嫩，汁多味甜，是制作果酒的优质原料。雪梨酒酿造技艺包括选果、清洗、破碎、榨汁、调整、发酵、陈酿、澄清、杀菌等工序。选果要选充分成熟的新鲜雪梨，去除烂果。清洗后用破碎机破碎成小块。榨汁用压榨机榨出梨汁，收集到发酵缸中。调整在梨汁中加入适量白糖，调整糖度，并加入二氧化硫杀菌。发酵加入选育的果酒酵母，在适宜温度下发酵约一周，使糖分转化为酒精。陈酿将发酵后的酒液转入陶坛，密封陈化半年以上，使酒质更加醇和。澄清用下胶或冷冻方法使酒液清澈透明。杀菌用巴氏杀菌法杀灭酒中的酵母菌，稳定酒质。云和雪梨酒色泽金黄，香气清雅，口感醇和。', '/pictures/云和雪梨酒酿造技艺.webp', '2021-10-01 00:00:00.000000', '市级', '传统技艺');
INSERT INTO `ich_project` VALUES (4019, '梅源尝新节', '云和县', '梅源尝新节是流传于浙江省云和县崇头镇梅源一带的传统民俗，在新谷登场时举行，尝新米、祭祖先，庆祝丰收，已有数百年历史。梅源地处山区，梯田层层，以种植水稻为主。每年农历七八月间，稻谷成熟，各家各户都要举办尝新节，感谢神灵和祖先的保佑，庆祝一年的丰收。尝新节的主要仪式包括采新、祭祖、尝新等。采新是在稻谷成熟的第一天，家长带着孩子到自家田里，精选一束颗粒饱满的稻穗，采回家中。祭祖是将采回的稻穗和用新米做的饭，供奉在祖先牌位前，焚香点烛，磕头礼拜，感谢祖先保佑丰收。尝新是全家人围坐在一起，品尝用新米做的饭和酒，共享丰收的喜悦。尝新节期间还有走亲访友的习俗，人们互相赠送新米做的食品，分享丰收的快乐。梅源尝新节体现了农民对土地的感恩和对丰收的期盼。', '/pictures/梅源尝新节.webp', '2021-10-01 00:00:00.000000', '市级', '民俗');
INSERT INTO `ich_project` VALUES (4020, '云和竹编技艺', '云和县', '云和竹编技艺是流传于浙江省云和县的传统手工艺，以竹篾编织各种生活用具和工艺品，技艺精湛，已有数百年历史。云和地处山区，盛产毛竹，为竹编提供了丰富的原材料。竹编技艺的工序包括选竹、砍竹、破篾、匀篾、煮篾、染色、编织、收口、修整等。选竹要选生长三年以上的毛竹，竹身粗直，无虫蛀。破篾将竹子剖成粗细均匀的竹篾，最细的篾条可薄如纸张。匀篾用匀刀将竹篾刮匀刮薄，使宽窄厚度一致。煮篾将竹篾放入沸水中煮，去除糖分，防止虫蛀。染色用天然染料将竹篾染成各种颜色。编织是最关键的环节，有十字编、人字编、六角编、螺旋编等数十种编织技法，可编出各种图案和文字。云和竹编的产品种类繁多，有生产用的竹篮、竹筐、竹篓，有生活用的竹席、竹枕、竹椅，有装饰用的竹画、竹屏风、竹灯笼。', '/pictures/云和竹编技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4021, '云和木雕技艺', '云和县', '云和木雕技艺是流传于浙江省云和县的传统美术类项目，以木材雕刻人物、花鸟、山水等题材，工艺精细，已有数百年历史。云和木雕选用樟木、银杏木、楠木等质地细腻的木材，这些木材纹理优美，不易变形开裂。木雕技艺的工序包括选材、设计、打坯、细雕、修光、打磨、上漆等。选材要根据作品大小选择合适的木料，要求无疤节、无裂纹。设计要根据木料的形状和纹理，构思作品的内容和构图，在木料上画出轮廓。打坯用大凿凿出粗坯，确定作品的大体形状和层次。细雕用各种刀具精雕细刻，刻出人物五官、衣纹、花鸟羽毛、山水纹理等细节。修光用细刀和砂纸将表面打磨光滑，去除刀痕。上漆用清漆或色漆涂饰木雕，保护木料，增加美观。云和木雕的题材广泛，有宗教人物如观音、罗汉，有历史人物如关公、岳飞，有吉祥图案如龙凤呈祥、福禄寿喜。', '/pictures/云和木雕技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (4022, '云和豆腐丸制作技艺', '云和县', '云和豆腐丸制作技艺是流传于浙江省云和县的传统小吃技艺，以豆腐为原料，包入肉馅，制成丸状，煮汤食用，已有上百年历史。云和豆腐丸是当地最具特色的风味小吃之一，以其鲜嫩爽滑、汤清味美的特点深受喜爱。制作技艺包括选料、制馅、捏丸、煮制等工序。选用当地卤水豆腐，这种豆腐质地紧实，豆香浓郁，最适合制作豆腐丸。将豆腐捣碎，加入少量盐和淀粉，搅拌均匀，增加黏性。馅料选用猪前腿肉，手工剁成肉茸，加入葱姜、酱油、香油等调料，搅拌上劲。捏丸是最关键的环节，取一团豆腐泥，在掌心压扁，放入肉馅，收口搓圆。要求豆腐皮厚薄均匀，包裹严密，不露馅。煮制时将豆腐丸轻轻放入沸水中，用小火煮熟，待豆腐丸浮起即熟。碗中放入紫菜、虾皮、葱花、盐、味精，舀入热汤，再放入煮好的豆腐丸。云和豆腐丸色泽洁白，鲜嫩爽滑。', '/pictures/云和豆腐丸制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4023, '云和油筒饼制作技艺', '云和县', '云和油筒饼制作技艺是流传于浙江省云和县的传统小吃技艺，以面粉和萝卜丝为原料，油炸制成，香脆可口，已有上百年历史。油筒饼因其用特制的油筒模具炸制而得名，是云和街头巷尾最常见的风味小吃。制作技艺包括和面、调馅、炸制等工序。和面用面粉加水调成稀面糊，加入少许盐和五香粉调味，搅拌均匀，静置醒发。馅料选用白萝卜，刨成细丝，加入盐腌制片刻，挤去水分，再加入葱花、虾皮、胡椒粉拌匀。炸制是最关键的环节，使用特制的油筒模具，这是一种长柄的铁制圆筒。先将模具放入热油中预热，然后取出，在模具底部留一层油，舀入一勺面糊，转动模具使面糊均匀附着在模具内壁，再放入萝卜丝馅，再舀一勺面糊覆盖，最后放入油锅中炸制。炸至金黄酥脆时，轻轻敲击模具，油筒饼就会脱落。云和油筒饼外酥里嫩，萝卜丝清甜爽口。', '/pictures/云和油筒饼制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4024, '云和麻糍制作技艺', '云和县', '云和麻糍制作技艺是流传于浙江省云和县的传统食品加工技艺，以糯米为原料，经蒸煮、捣制、裹粉等工序制成，软糯香甜，是当地节庆食品，已有数百年历史。麻糍是云和人过年过节必备的传统食品，寓意团圆甜蜜。制作技艺包括选米、浸米、蒸米、捣制、成形、裹粉等工序。选用优质糯米，淘洗干净后浸泡过夜，使米粒充分吸水。蒸米将浸泡好的糯米放入木甑中，用旺火蒸熟，要求米粒熟透而不烂。捣制是最关键的环节，将蒸好的糯米饭趁热倒入石臼，用木槌反复捣打。捣打要用力均匀，不断翻动，使米粒完全破碎，相互粘连，形成有韧性的米团。捣好的米团取出，在案板上搓成条状，用刀切成小块。裹粉是将切好的麻糍块放入炒熟的黄豆粉或芝麻粉中翻滚，使其表面均匀裹上一层粉末。裹粉后的麻糍色泽金黄，香气扑鼻，软糯香甜。', '/pictures/云和麻糍制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (4025, '云和板龙', '云和县', '云和板龙是流传于浙江省云和县的传统舞蹈类项目，以木板连接成龙身，多人舞动，是当地节庆活动的重要表演项目，已有数百年历史。云和板龙用木板做龙身，每块木板长约两米，宽约二十厘米，厚约三厘米，板与板之间用木栓连接，可以灵活转动。龙头用竹篾扎制骨架，外糊彩纸，彩绘龙鳞、龙眼、龙须，威武雄壮。龙尾也用竹篾扎制，高高翘起。整条龙长达数十米，由数十人舞动。表演时，一人持龙珠引路，舞者手持龙板，在锣鼓声中做出“龙抬头”“龙摆尾”“龙翻身”“龙戏珠”等动作。云和板龙的舞法丰富多彩，有“盘龙柱”“穿龙肚”“跳龙门”“龙抢珠”等数十种套路，要求舞者配合默契，动作整齐划一。夜间表演时，龙身内点蜡烛，整条龙流光溢彩，犹如真龙降世。每逢春节、元宵、庙会等重大节日，云和城乡都要舞起板龙，祈求风调雨顺、国泰民安。', '/pictures/云和板龙.webp', '2015-01-01 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (5002, '菇民戏', '庆元县', '菇民戏是流传于浙江省庆元县的传统戏曲形式，由菇民创造，以香菇栽培为背景，反映菇民生活，具有浓郁地方特色，已有数百年历史。庆元是世界香菇发源地，千百年来，无数菇民每年秋冬季节进入深山老林培育香菇，菇民戏就是他们在漫长的菇山生活中创造的。菇民戏的唱腔以乱弹为主，融合了徽调、昆腔等，高亢激越，粗犷豪放。伴奏乐器有锣、鼓、钹、唢呐、笛子、二胡等，气氛热烈。剧目多为菇民生活的反映，如《香菇记》讲述菇民进山种菇的艰辛，《菇山情》表现菇民之间的感情，《采菇妹》描写菇山男女的爱情。这些剧目情节生动，语言朴实，充满山乡风味。菇民戏的演员都是菇民自己，农忙时种菇，农闲时演戏，自娱自乐。每逢菇神庙会，各地菇民戏班都会汇集一堂，连演数日，热闹非凡。菇民戏是菇民文化的活化石，也是研究香菇栽培史的重要资料。', '/pictures/菇民戏.webp', '2007-01-01 00:00:00.000000', '省级', '传统戏剧');
INSERT INTO `ich_project` VALUES (5003, '唱灯', '庆元县', '唱灯（茶灯戏）是流传于浙江省庆元县的传统戏剧类项目，以采茶灯为道具，载歌载舞，表演生活故事，已有数百年历史。唱灯起源于清代，最初是茶农在采茶季节的自娱自乐，后发展成独立的戏曲形式。唱灯的表演形式独特，演员手持茶灯，边唱边舞，灯随人转，人灯合一。茶灯用竹篾扎制骨架，外糊彩纸，内点蜡烛，形如茶篮，象征着采茶的工具。唱腔以当地山歌小调为基础，有“采茶调”“花灯调”“拜年调”等十多种曲牌，旋律优美动听。剧目多为生活小戏，如《采茶》《卖茶》《送茶》等，表现茶农的日常生活和爱情故事，语言幽默风趣，表演生动活泼。唱灯的演员都是当地农民，农忙时劳作，农闲时排练演出。每逢春节、元宵，唱灯戏班走村串户表演，为节日增添喜庆气氛。唱灯融合了歌舞、戏曲、灯彩等多种艺术形式，是庆元茶文化的生动体现。', '/pictures/唱灯.webp', '2007-01-01 00:00:00.000000', '省级', '传统戏剧');
INSERT INTO `ich_project` VALUES (5004, '百事吉剪纸', '庆元县', '百事吉剪纸是流传于浙江省庆元县的传统美术，以纸为材料，剪出各种吉祥图案，用于节庆装饰，已有数百年历史。“百事吉”意为百事吉祥，是庆元剪纸中最具代表性的图案，由“百”“事”“吉”三个字巧妙组合而成，寓意万事如意。百事吉剪纸的技艺包括设计、折纸、剪刻、揭离、粘贴等工序。设计要构思图案的造型和寓意，庆元剪纸的图案多为吉祥纹样，如福禄寿喜、龙凤呈祥、连年有余等。折纸将纸张按一定方式折叠，便于剪出对称图案。剪刻是最关键的环节，用剪刀或刻刀在纸上剪刻出图案，要求线条流畅，连接自然。揭离将剪好的作品轻轻揭开，展开成完整的图案。粘贴将剪纸作品粘贴在窗户、门楣、墙壁上，用于装饰。百事吉剪纸的独特之处在于“以字入画”，将文字与图案巧妙结合，如“福”字周围饰以蝙蝠、寿桃，“寿”字周围饰以仙鹤、松柏，既美观又吉祥。', '/pictures/百事吉剪纸.webp', '2022-06-27 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (5005, '黄粿制作技艺', '庆元县', '黄粿制作技艺是流传于浙江省庆元县的传统食品加工技艺，以糯米和草木灰水为原料，经浸泡、蒸煮、捣制等工序制成黄粿，是当地节庆食品，已有数百年历史。黄粿因其色泽金黄而得名，是庆元人过年过节必备的传统食品。制作技艺包括烧灰、浸米、蒸米、捣制、成形、晾晒等工序。烧灰是最具特色的环节，选用山中的灌木和杂草烧成灰，用开水冲泡过滤，得到草木灰水。这种灰水呈碱性，能使糯米变成金黄色，并赋予独特的清香。浸米将糯米放入灰水中浸泡过夜，使米粒充分吸收灰水，变成淡黄色。蒸米将浸泡好的糯米放入木甑中，用旺火蒸熟。捣制将蒸好的糯米饭趁热倒入石臼，用木槌反复捣打，使米粒完全破碎，相互粘连，形成有韧性的米团。捣好的米团取出，在案板上搓成长条，切成块状，或用模具压成各种形状。成形后的黄粿色泽金黄，清香扑鼻，口感软糯。', '/pictures/黄粿制作技艺.webp', '2022-06-27 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (5006, '竹编技艺', '庆元县', '庆元竹编技艺是流传于浙江省庆元县的传统手工艺，以竹篾编织各种生活用具和工艺品，技艺精湛，已有数百年历史。庆元地处山区，盛产毛竹，为竹编提供了丰富的原材料。竹编技艺的工序包括选竹、砍竹、破篾、匀篾、煮篾、染色、编织、收口、修整等。选竹要选生长三年以上的毛竹，竹身粗直，无虫蛀。破篾将竹子剖成粗细均匀的竹篾，最细的篾条可薄如纸张。匀篾用匀刀将竹篾刮匀刮薄，使宽窄厚度一致。煮篾将竹篾放入沸水中煮，去除糖分，防止虫蛀。染色用天然染料将竹篾染成各种颜色。编织是最关键的环节，有十字编、人字编、六角编、螺旋编等数十种编织技法，可编出各种图案和文字。庆元竹编的产品种类繁多，有生产用的竹篮、竹筐、竹篓，有生活用的竹席、竹枕、竹椅，有装饰用的竹画、竹屏风、竹灯笼。庆元竹编以其工艺精细、造型美观、经久耐用而著称。', '/pictures/竹编技艺.webp', '2022-06-27 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (5007, '咸菜制作技艺', '庆元县', '庆元咸菜制作技艺是流传于浙江省庆元县的传统食品加工技艺，以各种蔬菜为原料，经腌制发酵制成咸菜，已有数百年历史。庆元山区蔬菜产量丰富，但保鲜不易，腌制成为保存蔬菜的重要方法。咸菜制作技艺包括选菜、洗菜、晾晒、切菜、腌制、发酵等工序。选菜要选新鲜脆嫩的蔬菜，如芥菜、萝卜、白菜等。洗菜将蔬菜洗净，去除泥土和杂质。晾晒将洗净的蔬菜摊开晾晒，使表面水分蒸发，变得萎蔫。切菜将晾晒后的蔬菜切成适当大小，便于腌制。腌制是最关键的环节，将切好的蔬菜与盐按比例混合，充分揉搓，使盐分渗入菜中，然后装入缸中，层层压实，最后用石头压住。发酵在适宜温度下进行，约一个月后，咸菜发酵成熟。庆元咸菜的种类繁多，有酸菜、咸菜、泡菜等，各具特色。酸菜酸香开胃，适合炖肉；咸菜咸鲜可口，适合炒食；泡菜脆嫩爽口，适合生吃。庆元咸菜不仅是日常佐餐佳品，也是烹饪的重要配料。', '/pictures/咸菜制作技艺.webp', '2022-06-27 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (5008, '乌米饭制作技艺', '庆元县', '乌米饭制作技艺是流传于浙江省庆元县的传统食品技艺，以乌饭树叶汁浸泡糯米，蒸煮成乌米饭，是畲族传统食品，已有数百年历史。乌米饭是畲族“三月三”节日的必备食品，传说畲族祖先因吃乌米饭而躲过灾祸，从此乌米饭成为畲族的吉祥食品。制作技艺包括采叶、榨汁、浸米、蒸饭等工序。乌饭树是一种野生灌木，生长在山坡林缘，其叶片含有特殊的色素和香气。采叶在春季，选取鲜嫩的乌饭树叶。榨汁将乌饭树叶洗净，捣烂加水，过滤取汁，得到紫黑色的乌饭叶汁。浸米将糯米淘洗干净，放入乌饭叶汁中浸泡过夜，米粒充分吸收叶汁，变成紫黑色。蒸饭将浸泡好的糯米放入木甑中，用旺火蒸熟。蒸好的乌米饭色泽乌黑发亮，香气独特，口感软糯。乌米饭可以直接食用，也可以加糖或盐调味，还可以包入馅料做成乌饭团。乌米饭不仅美味，还有清热解毒、健脾开胃的功效。', '/pictures/乌米饭制作技艺.webp', '2021-10-01 00:00:00.000000', '市级', '传统技艺');
INSERT INTO `ich_project` VALUES (5009, '菇神庙会', '庆元县', '菇神庙会是流传于浙江省庆元县的传统民俗，在菇神庙举行祭祀活动，祈求香菇丰收，包含演戏、集市等内容，已有数百年历史。庆元是世界香菇发源地，菇民视吴三公为香菇始祖，各地建有菇神庙。每年农历三月十七日吴三公诞辰，菇民都要举行盛大的菇神庙会。庙会的主要仪式包括祭祀、演戏、集市等。祭祀在菇神庙举行，菇民们献上三牲五果，焚香点烛，跪拜祈祷，祈求香菇丰收、平安吉祥。主祭人诵读祭文，回顾吴三公发明香菇砍花技艺的功绩。演戏是庙会的重要内容，请来戏班连演数日，剧目多为菇民戏，如《香菇记》《吴三公》等，表现菇民生活。集市是菇民的物资交流会，各地商贩云集，出售农具、家具、日用百货、特色小吃。菇民们借此机会采购进山所需的物资，交流种菇经验。菇神庙会既是祭祀活动，也是菇民的聚会和交流平台。', '/pictures/菇神庙会.webp', '2021-10-01 00:00:00.000000', '市级', '民俗');
INSERT INTO `ich_project` VALUES (5010, '如龙桥传说', '庆元县', '如龙桥传说是流传于浙江省庆元县的民间文学，是关于庆元如龙桥的传说故事，反映了当地廊桥文化，已有数百年历史。如龙桥是庆元最具代表性的木拱廊桥之一，建于明代，距今已有四百多年历史。关于如龙桥的由来，有多种传说。一说桥建成时，恰好有一条龙从桥下经过，故名“如龙桥”。一说建桥的工匠技艺高超，所建之桥如龙腾飞，故名如龙桥。最动人的是“鲁班显圣”的传说：相传建桥时，工匠们怎么也合不拢最后一道拱，一筹莫展。一天夜里，一位白发老人来到工地，指点工匠如何施工，第二天桥梁顺利合龙。工匠们这才明白，是鲁班祖师显圣相助。从此，如龙桥成为工匠们心中的圣桥，每逢建桥开工都要祭祀鲁班。如龙桥传说情节神奇，寓意深刻，将桥梁建筑与民间信仰相结合，丰富了如龙桥的文化内涵。', '/pictures/如龙桥传说.webp', '2022-06-27 00:00:00.000000', '县级', '民间文学');
INSERT INTO `ich_project` VALUES (5011, '咏归桥传说', '庆元县', '咏归桥传说是流传于浙江省庆元县的民间文学，是关于庆元咏归桥的传说故事，在当地广为流传，已有数百年历史。咏归桥是庆元县城的一座古廊桥，建于宋代，历代重修，至今已有近千年历史。桥名“咏归”取自《论语》“浴乎沂，风乎舞雩，咏而归”，寓意归家的喜悦。关于咏归桥的传说很多，最著名的是“仙人指路”的传说。相传宋代有位书生赴京赶考，路过咏归桥时天降大雨，便在桥中避雨。一位白发老人也来桥中避雨，两人交谈甚欢。老人指点书生考试要诀，并赠他一首诗。书生后来果然金榜题名，回到庆元想找老人道谢，却再也找不到。人们都说那位老人是仙人化身。另一传说是“孝子救母”：一位孝子的母亲病重，想吃河中的鲤鱼。时值隆冬，河水结冰，孝子跪在咏归桥上哭泣，感动了河神，河面突然开裂，跃出一条鲤鱼。孝子用鲤鱼救活了母亲。', '/pictures/咏归桥传说.webp', '2022-06-27 00:00:00.000000', '县级', '民间文学');
INSERT INTO `ich_project` VALUES (5012, '香菇栽培技艺', '庆元县', '香菇栽培技艺是流传于浙江省庆元县的传统农业技艺，包括菇木砍伐、接种、管理、采收等环节，是“香菇开史”之地，已有八百多年历史。南宋时期，庆元龙岩村人吴三公发明了“砍花法”栽培香菇，开创了人工栽培香菇的先河。香菇栽培技艺包括选山、砍树、截段、砍花、遮衣、散水、惊蕈、采菇、烘干等一整套工序。选山要选择向阳通风、土壤肥沃、菇树资源丰富的山地。砍树在冬至前后，选择树龄合适的阔叶树，如栲树、枫树等。截段将砍倒的树木截成约一米长的段木。砍花是最关键的环节，用特制的砍花斧在段木上砍出深浅、疏密有致的花纹，控制香菇生长的密度和质量。遮衣用树枝树叶覆盖段木，保持湿润。散水在干燥时浇水保湿。惊蕈是一种独特的催菇技术，用木槌敲击菇木，震动刺激菌丝生长。采菇在香菇成熟时及时采摘，烘干保存。', '/pictures/香菇栽培技艺.webp', '2022-06-27 00:00:00.000000', '县级', NULL);
INSERT INTO `ich_project` VALUES (5013, '廊桥建造习俗', '庆元县', '廊桥建造习俗是流传于浙江省庆元县的传统民俗，包括选址、奠基、上梁、合龙等仪式，反映了对廊桥的崇敬，已有数百年历史。庆元是中国廊桥之乡，千百年来，廊桥建造形成了独特的习俗和禁忌。选址要请风水先生勘察，选择“藏风得水”的吉地。奠基要择吉日良辰，祭祀土地神，破土动工。上梁是建造中最隆重的仪式，掌墨师傅主持，焚香点烛，杀鸡祭梁，将写有“紫微高照”的红布系在主梁上，然后众人合力将主梁升起安装。合龙是木拱桥最后一道拱合拢的时刻，也要举行祭祀，感谢鲁班祖师保佑。桥建成后要举行“踩桥”仪式，请德高望重的长者首先过桥，寓意吉祥。廊桥建造还有许多禁忌，如妇女不得靠近工地，工人不得说不吉利的话等。这些习俗和禁忌，体现了古人对桥梁的敬畏，也反映了廊桥在当地人心目中的神圣地位。廊桥建造习俗是廊桥文化的重要组成部分。', '/pictures/廊桥建造习俗.webp', '2022-06-27 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (5014, '月山春晚习俗', '庆元县', '月山春晚习俗是流传于浙江省庆元县月山村的传统民俗，村民自编自演的春节联欢晚会，延续数十年，被誉为“中国第一村晚”。月山春晚始于1956年，由几位回乡知识青年发起，此后年年举办，从未间断，至今已有六十多年历史。月山春晚的独特之处在于“农民演、演农民、农民看”。演员都是本村村民，有老人、有孩子，有农民、有学生。节目都是自编自演，反映农村生活，如农耕表演、民歌演唱、民间舞蹈、戏曲小品等。舞台搭在村里的祠堂或晒谷场，观众就是全村的男女老少。月山春晚的筹备从腊月开始，村民们利用农闲时间排练，除夕夜正式演出，一直演到正月初一凌晨。月山春晚不仅是娱乐活动，更是村民团聚、联络感情的重要场合。月山春晚习俗传承了乡村文化，凝聚了乡情乡愁。', '/pictures/月山春晚习俗.webp', '2022-06-27 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (5015, '庆元方言', '庆元县', '庆元方言是流传于浙江省庆元县的地方语言，保留了大量古汉语特征，具有语言学研究价值，已有上千年历史。庆元地处浙西南山区，交通闭塞，与外界交流少，因而保留了较多的古汉语特点。庆元方言属于吴语处衢片，语音系统复杂，有声母三十多个，韵母四十多个，声调八个，保留了入声。词汇中保留了大量的古语词，如“箸”（筷子）、“镬”（锅）、“晏”（晚）、“睏”（睡）等。语法上也有独特之处，如状语后置、否定词用法等。庆元方言内部还有差异，东部、西部、南部略有不同。庆元方言不仅是日常交流工具，也是地方文化的重要载体，许多民间文学、戏曲、歌谣都是用方言创作的。随着普通话的推广，庆元方言的使用范围逐渐缩小，但作为地方文化遗产，其价值日益受到重视。庆元方言的保存和研究，对于了解古代汉语、研究地方文化具有重要意义。', '/pictures/庆元方言.webp', '2022-06-27 00:00:00.000000', '县级', NULL);
INSERT INTO `ich_project` VALUES (5016, '香菇功夫', '庆元县', '香菇功夫是流传于浙江省庆元县的传统体育项目，是菇民在长期深山劳作中创编的防身武术，用于防身健体，已有数百年历史。庆元菇民每年秋冬季节进入深山老林培育香菇，要在山中居住数月之久，常遇野兽出没、歹人骚扰，于是创编了这套实用的防身功夫。香菇功夫包括拳术和器械两部分，拳术有“扁担拳”“柴刀拳”“挑担拳”等，器械有柴刀、扁担、木棍等日常用具。其特点是动作朴实、实用性强，讲究一招制敌，不追求花哨。如“扁担拳”以挑香菇的扁担为武器，有挑、压、扫、劈等招式；“柴刀术”以砍柴的柴刀为武器，有砍、削、挡、刺等动作。香菇功夫还包含一些养生功法，如“八段锦”“易筋经”等，用于调理身体，抵御山中湿寒。香菇功夫不仅是防身技艺，更是菇民艰苦生活的写照，体现了山区人民自强不息的精神。', '/pictures/香菇功夫.webp', '2015-01-01 00:00:00.000000', '县级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (5017, '庆元唱灯戏', '庆元县', '庆元唱灯戏是流传于浙江省庆元县的传统戏剧类项目，以采茶灯为道具，载歌载舞，表演生活故事，已有数百年历史。唱灯戏起源于清代，最初是茶农在采茶季节的自娱自乐，后发展成独立的戏曲形式。唱灯戏的表演形式独特，演员手持茶灯，边唱边舞，灯随人转，人灯合一。茶灯用竹篾扎制骨架，外糊彩纸，内点蜡烛，形如茶篮，象征着采茶的工具。唱腔以当地山歌小调为基础，有“采茶调”“花灯调”“拜年调”等十多种曲牌，旋律优美动听。剧目多为生活小戏，如《采茶》《卖茶》《送茶》等，表现茶农的日常生活和爱情故事，语言幽默风趣，表演生动活泼。唱灯戏的演员都是当地农民，农忙时劳作，农闲时排练演出。每逢春节、元宵，唱灯戏班走村串户表演，为节日增添喜庆气氛。唱灯戏融合了歌舞、戏曲、灯彩等多种艺术形式。', '/pictures/庆元唱灯戏.webp', '2015-01-01 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (5018, '庆元木偶戏', '庆元县', '庆元木偶戏是流传于浙江省庆元县的传统戏剧类项目，艺人以线操纵木偶表演，配以唱腔和乐器伴奏，演绎各类故事，已有三百多年历史。庆元木偶戏属于提线木偶，木偶高约两尺，用樟木雕刻头部，彩绘脸谱，服饰用绸缎制作，四肢关节可活动，通过十几根细线连接操纵。木偶戏的操纵技巧十分复杂，艺人通过提拉不同位置的线，使木偶做出行走、转身、作揖、舞剑等各种动作。唱腔以乱弹为主，融合徽调、昆腔等，高亢激越。伴奏乐器有锣、鼓、钹、笛子、二胡等，气氛热烈。传统剧目有《白蛇传》《西游记》《三国演义》《封神榜》等数十本，内容多为历史故事和神话传说。庆元木偶戏的独特之处在于，一个艺人可以同时操纵多个木偶，配合唱念做打，表演复杂的武打场面。木偶戏班多在庙会、节庆时演出，深受群众欢迎。', '/pictures/庆元木偶戏.webp', '2015-01-01 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (5019, '庆元剪纸', '庆元县', '庆元剪纸是流传于浙江省庆元县的传统美术类项目，以纸为材料，剪出各种吉祥图案，用于节庆装饰，已有数百年历史。庆元剪纸的风格质朴粗犷，富有乡土气息，题材多为吉祥图案，如福禄寿喜、龙凤呈祥、连年有余、五谷丰登等。剪纸技艺包括设计、折纸、剪刻、揭离、粘贴等工序。设计要构思图案的造型和寓意，庆元剪纸的图案多为对称图形，便于折叠剪制。折纸将纸张按一定方式折叠，便于剪出对称图案。剪刻是最关键的环节，用剪刀或刻刀在纸上剪刻出图案，要求线条流畅，连接自然。庆元剪纸的剪刻技法有阳剪、阴剪、阴阳结合等，阳剪保留线条，阴剪刻去线条。揭离将剪好的作品轻轻揭开，展开成完整的图案。粘贴将剪纸作品粘贴在窗户、门楣、墙壁上，用于装饰。庆元剪纸的独特之处在于“以字入画”，将文字与图案巧妙结合，如“福”字周围饰以蝙蝠、寿桃，“寿”字周围饰以仙鹤、松柏。', '/pictures/庆元剪纸.webp', '2015-01-01 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (5020, '庆元根雕', '庆元县', '庆元根雕是流传于浙江省庆元县的传统美术类项目，以树根的自然形态为基础，进行艺术创作，已有数百年历史。庆元地处山区，森林资源丰富，为根雕提供了丰富的原材料。根雕艺术讲究“三分人工，七分天成”，充分利用树根的天然形态，稍加雕琢，使之成为艺术品。根雕的工序包括选材、构思、去皮、雕琢、打磨、上漆等。选材要选形态奇特、纹理美观的树根，如杜鹃根、紫薇根、黄杨根等。构思要根据树根的自然形态，想象它像什么，确定创作主题。去皮用刀刮去树根表面的树皮，露出木质纹理。雕琢用各种刀具对树根进行适当加工，突出主题，弥补不足。打磨用砂纸将表面打磨光滑，去除刀痕。上漆用清漆涂饰根雕，保护木质，增加光泽。庆元根雕的题材广泛，有人物、动物、山水、器物等。人物根雕如寿星、罗汉、仕女，动物根雕如龙、凤、鹰、鹿，山水根雕如峰峦、洞穴、瀑布。', '/pictures/庆元根雕.webp', '2015-01-01 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (5021, '庆元灰碱粽制作技艺', '庆元县', '庆元灰碱粽制作技艺是流传于浙江省庆元县的传统食品加工技艺，以灰碱水浸泡糯米，包制粽子，口感独特，是当地传统食品，已有数百年历史。灰碱粽是庆元端午节的传统食品，因其用草木灰水浸泡糯米而得名，色泽金黄，清香扑鼻。制作技艺包括烧灰、浸米、包粽、煮粽等工序。烧灰是最具特色的环节，选用山中的灌木和杂草烧成灰，用开水冲泡过滤，得到灰碱水。这种灰碱水呈碱性，能使糯米变成金黄色，并赋予独特的清香。浸米将糯米放入灰碱水中浸泡数小时，使米粒充分吸收灰碱水，变成淡黄色。包粽将浸泡好的糯米和馅料用粽叶包裹成三角形或四角形，用棕榈叶撕成的细绳扎紧。馅料可甜可咸，甜馅常用红豆沙，咸馅常用猪肉、咸蛋黄等。煮粽将包好的粽子放入大锅中，加水没过粽子，用旺火煮三小时以上，再焖一夜，使粽叶的清香充分渗入糯米。庆元灰碱粽色泽金黄，清香扑鼻，口感软糯。', '/pictures/庆元灰碱粽制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (5022, '庆元社粿制作技艺', '庆元县', '庆元社粿制作技艺是流传于浙江省庆元县的传统食品加工技艺，在社日制作的特色食品，以糯米粉制成，已有数百年历史。社日是古代祭祀社神（土地神）的日子，分春社和秋社。庆元民间有做社粿祭祀社神的习俗，祈求五谷丰登。社粿制作技艺包括浸米、磨浆、发酵、蒸制等工序。选用优质糯米，淘洗干净后浸泡过夜。磨浆将浸泡好的糯米加水磨成米浆，要求米浆细腻无颗粒。发酵是社粿制作的关键，在米浆中加入酒糟或老面，放置温暖处发酵数小时，使米浆微微发酸，产生气泡。发酵好的米浆加入白糖或红糖调味，搅拌均匀。蒸制时将米浆倒入铺有湿布的蒸笼中，摊平，用旺火蒸熟。蒸好的社粿厚约两三厘米，表面光滑，色泽洁白或淡黄。社粿可以直接食用，也可以切片煎至两面金黄，外酥里嫩。社粿口感软糯，甜中带酸，风味独特。社日吃社粿的习俗，体现了农民对土地的感恩和对丰收的期盼。', '/pictures/庆元社粿制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (6002, '庙会（张山寨七七会）', '缙云县', '张山寨七七会是流传于浙江省缙云县的传统庙会，每年农历七月初七在张山寨举行，包含献祭、演剧、迎案等多种活动，吸引了周边数万群众参与，已有数百年历史。张山寨七七会起源于明代，最初是祭祀陈十四娘娘的仪式，后发展成大型庙会。陈十四娘娘是浙南地区信奉的妇幼保护神，传说七月初七是她的诞辰。庙会的主要仪式包括祭祀、巡游、演戏、集市等。祭祀在张山寨的陈十四庙举行，信众献上三牲五果，焚香点烛，跪拜祈祷。巡游是庙会的高潮，信众抬着陈十四娘娘的神像巡游山寨，沿途居民焚香礼拜，祈求平安。巡游队伍中还有舞龙、舞狮、钢叉舞、迎罗汉等民间表演，热闹非凡。演戏请来戏班连演数日，剧目多为婺剧、越剧等地方戏曲。集市是物资交流会，各地商贩云集，出售农具、家具、日用百货、特色小吃。张山寨七七会集祭祀、娱乐、商贸于一体。2011年，张山寨七七会作为庙会的一部分被列入国家级非物质文化遗产代表性项目名录。', '/pictures/庙会（张山寨七七会）.webp', '2011-05-01 00:00:00.000000', '国家级', '民俗');
INSERT INTO `ich_project` VALUES (6003, '迎罗汉', '缙云县', '迎罗汉是流传于浙江省缙云县的传统体育项目，表演者通过叠罗汉等武术和技巧动作，展示力量与技巧，多在庙会或节庆期间进行表演，已有数百年历史。迎罗汉起源于古代民间武术活动，后发展成独立的表演形式。迎罗汉的表演形式多样，有叠罗汉、走罗汉、拳术、器械等。叠罗汉是最具特色的表演，由数十人层层叠起，搭成人塔，最高可达七八层。底层的人要身强力壮，稳稳站立；上层的人要身轻如燕，灵活攀爬。叠成的造型有“牌坊”“莲花”“宝塔”等，寓意吉祥。走罗汉是队列表演，表演者身着彩衣，手持器械，在锣鼓声中变换队形，动作整齐划一。拳术表演展示各种拳法套路，刚劲有力。器械表演有刀、枪、剑、棍等，招式娴熟。迎罗汉的表演者都是当地农民，利用农闲时间排练。每逢张山寨七七会等重要节庆，各村迎罗汉队都会前来表演，一较高下。2011年，迎罗汉被列入国家级非物质文化遗产代表性项目名录。', '/pictures/迎罗汉.webp', '2011-05-01 00:00:00.000000', '国家级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (6004, '传统面食制作技艺（缙云烧饼制作技艺）', '缙云县', '缙云烧饼制作技艺是流传于浙江省缙云县的传统面食制作技艺，利用传统烧饼桶炭火烤制特色面食，制作出的烧饼半焦黄、表皮松脆、内馅鲜美，是风靡全国的地方名小吃，已有数百年历史。缙云烧饼起源于明代，相传与抗倭名将戚继光有关。制作技艺包括和面、制馅、包饼、烤制等工序。和面用面粉加老面发酵，使面团松软有弹性。制馅选用猪五花肉，手工剁成肉末，加入梅干菜、葱、盐、酱油等调料拌匀。梅干菜是缙云烧饼的灵魂，用当地产的九头芥腌制晒干而成，咸香浓郁。包饼将发酵好的面团擀成圆皮，包入馅料，收口捏紧，再擀成圆饼形，表面刷上糖水，撒上芝麻。烤制是最关键的环节，使用传统的烧饼桶。这是一种特制的陶土桶，中间烧炭火，桶壁温度极高。将饼坯贴在桶壁上，用炭火烤制两三分钟，待饼面鼓起、色泽金黄时取出。缙云烧饼外酥里嫩，馅料咸香，回味悠长。2021年，缙云烧饼制作技艺被列入国家级非物质文化遗产代表性项目名录。', '/pictures/传统面食制作技艺（缙云烧饼制作技艺）.webp', '2021-06-01 00:00:00.000000', '国家级', '传统技艺');
INSERT INTO `ich_project` VALUES (6005, '缙云木雕', '缙云县', '缙云木雕是流传于浙江省缙云县的传统美术类项目，以木材为原料，雕刻各类题材，工艺精细，用于建筑装饰和工艺品制作，已有数百年历史。缙云木雕选用樟木、银杏木、楠木等质地细腻的木材，这些木材纹理优美，不易变形开裂。木雕技艺的工序包括选材、设计、打坯、细雕、修光、打磨、上漆等。选材要根据作品大小选择合适的木料，要求无疤节、无裂纹。设计要根据木料的形状和纹理，构思作品的内容和构图，在木料上画出轮廓。打坯用大凿凿出粗坯，确定作品的大体形状和层次。细雕用各种刀具精雕细刻，刻出人物五官、衣纹、花鸟羽毛、山水纹理等细节。修光用细刀和砂纸将表面打磨光滑，去除刀痕。上漆用清漆或色漆涂饰木雕，保护木料，增加美观。缙云木雕的题材广泛，有宗教人物如观音、罗汉，有历史人物如关公、岳飞，有吉祥图案如龙凤呈祥、福禄寿喜。缙云木雕主要用于建筑装饰，如祠堂、庙宇、民居的梁枋、雀替、门窗等。', '/pictures/缙云木雕.webp', '2016-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (6006, '缙云根雕', '缙云县', '缙云根雕是流传于浙江省缙云县的传统美术类项目，以树根的自然形态为基础，进行艺术创作，作品构思巧妙，栩栩如生，已有数百年历史。缙云地处山区，森林资源丰富，为根雕提供了丰富的原材料。根雕艺术讲究“三分人工，七分天成”，充分利用树根的天然形态，稍加雕琢，使之成为艺术品。根雕的工序包括选材、构思、去皮、雕琢、打磨、上漆等。选材要选形态奇特、纹理美观的树根，如杜鹃根、紫薇根、黄杨根等。构思要根据树根的自然形态，想象它像什么，确定创作主题。去皮用刀刮去树根表面的树皮，露出木质纹理。雕琢用各种刀具对树根进行适当加工，突出主题，弥补不足。打磨用砂纸将表面打磨光滑，去除刀痕。上漆用清漆涂饰根雕，保护木质，增加光泽。缙云根雕的题材广泛，有人物、动物、山水、器物等。人物根雕如寿星、罗汉、仕女，动物根雕如龙、凤、鹰、鹿，山水根雕如峰峦、洞穴、瀑布。缙云根雕构思巧妙，自然天成。', '/pictures/缙云根雕.webp', '2007-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (6007, '缙云剪纸', '缙云县', '缙云剪纸是流传于浙江省缙云县的传统美术类项目，以纸为材料，剪出各种吉祥图案，用于节庆装饰和民俗活动，已有数百年历史。缙云剪纸的风格细腻秀美，富有乡土气息，题材多为吉祥图案，如福禄寿喜、龙凤呈祥、连年有余、五谷丰登等。剪纸技艺包括设计、折纸、剪刻、揭离、粘贴等工序。设计要构思图案的造型和寓意，缙云剪纸的图案多为对称图形，便于折叠剪制。折纸将纸张按一定方式折叠，便于剪出对称图案。剪刻是最关键的环节，用剪刀或刻刀在纸上剪刻出图案，要求线条流畅，连接自然。缙云剪纸的剪刻技法有阳剪、阴剪、阴阳结合等，阳剪保留线条，阴剪刻去线条。揭离将剪好的作品轻轻揭开，展开成完整的图案。粘贴将剪纸作品粘贴在窗户、门楣、墙壁上，用于装饰。缙云剪纸的独特之处在于“以字入画”，将文字与图案巧妙结合，如“福”字周围饰以蝙蝠、寿桃，“寿”字周围饰以仙鹤、松柏。缙云剪纸既美观又吉祥。', '/pictures/缙云剪纸.webp', '2007-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (6008, '缙云地母庙会', '缙云县', '缙云地母庙会是流传于浙江省缙云县的传统民俗类项目，祭祀地母娘娘的传统庙会，包含祭祀、演剧、集市等活动，已有数百年历史。地母娘娘是民间信仰中的大地之神，掌管土地和万物生长。缙云地母庙会每年农历三月十八日地母诞辰举行。庙会的主要仪式包括祭祀、巡游、演戏、集市等。祭祀在地母庙举行，信众献上三牲五果，焚香点烛，跪拜祈祷，祈求风调雨顺、五谷丰登。主祭人诵读祭文，歌颂地母的功德。巡游是庙会的高潮，信众抬着地母娘娘的神像巡游村庄，沿途居民焚香礼拜，祈求平安。巡游队伍中还有舞龙、舞狮、钢叉舞等民间表演，热闹非凡。演戏请来戏班连演数日，剧目多为地方戏曲，内容多为神话传说和民间故事。集市是物资交流会，各地商贩云集，出售农具、家具、日用百货、特色小吃。地母庙会集祭祀、娱乐、商贸于一体，是当地重要的民俗活动。2023年，缙云地母庙会被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/缙云地母庙会.webp', '2023-01-01 00:00:00.000000', '省级', '民俗');
INSERT INTO `ich_project` VALUES (6009, '迎关公案', '缙云县', '迎关公案是流传于浙江省缙云县的传统民俗类项目，在特定节日举行迎请关公的仪式，祈求平安吉祥，已有数百年历史。关公即关羽，是三国时期的名将，被民间尊为“关圣帝君”，奉为武财神和保护神。缙云民间有祭祀关公的传统，各村都建有关帝庙。迎关公案每年农历五月十三日关公诞辰举行。仪式的主要内容包括祭祀、巡游、演戏等。祭祀在关帝庙举行，信众献上三牲五果，焚香点烛，跪拜祈祷，祈求关公保佑平安、招财进宝。巡游是仪式的核心，信众抬着关公的神像巡游村庄，沿途居民焚香礼拜，祈求保佑。巡游队伍中还有扮演关公的“关公案”，一人扮演关公，骑在高头大马上，手持青龙偃月刀，威风凛凛。关公案还有周仓、关平陪同，以及刀斧手、旗手等随行，再现关公出巡的威仪。演戏请来戏班演出关公戏，如《古城会》《单刀会》等。迎关公案既是对关公的崇拜，也是民间自娱自乐的方式。', '/pictures/迎关公案.webp', '2012-01-01 00:00:00.000000', '省级', '民俗');
INSERT INTO `ich_project` VALUES (6010, '婺剧', '缙云县', '婺剧是流传于浙江省缙云县的传统戏剧类项目，在缙云流传广泛，表演风格粗犷豪放，唱腔高亢激越，深受群众喜爱，已有数百年历史。婺剧是浙江主要地方戏曲之一，因金华古称婺州而得名。缙云婺剧属于婺剧的处州派，具有鲜明的地方特色。婺剧的唱腔以乱弹为主，融合高腔、昆腔、徽调等多种声腔，高亢激越，粗犷豪放。伴奏乐器有锣、鼓、钹、唢呐、笛子、板胡等，气氛热烈。表演程式丰富，有唱、念、做、打四功，手、眼、身、法、步五法，讲究功架和气势。传统剧目有《白蛇传》《三请梨花》《辕门斩子》《断桥》等数百本，内容多为历史故事和民间传说。缙云婺剧的独特之处在于“武戏文唱”，武打场面热烈火爆，但又不失韵味。缙云农村多有业余婺剧戏班，农忙时耕作，农闲时演戏，自娱自乐。每逢节庆庙会，都要请戏班演出。', '/pictures/婺剧.webp', '2009-01-01 00:00:00.000000', '省级', '传统戏剧');
INSERT INTO `ich_project` VALUES (6011, '缙云爽面制作技艺', '缙云县', '缙云爽面制作技艺是流传于浙江省缙云县的传统面食制作技艺，以制作精细、口感爽滑而得名，是当地的传统面食，已有数百年历史。缙云爽面又称“土面”，是缙云人待客和节庆的必备食品。制作技艺包括和面、醒面、切条、搓条、盘条、拉面、晒面等工序。和面用高筋面粉加盐和水，反复揉制，使面团光滑有筋道。醒面将和好的面团盖上湿布，静置一小时，使面筋充分舒展。切条将醒好的面团擀成厚片，切成粗条。搓条将粗条搓成细长条。盘条将搓好的面条盘旋在盆中，每层刷油，防止粘连，再次醒面。拉面是最关键的环节，将盘好的面条两端拉长，边拉边抖，使面条越来越细，均匀一致。晒面将拉好的面条挂在竹竿上，在阳光下晒干。晒干的爽面色泽洁白，细如发丝，柔韧有弹性。食用时入沸水煮熟，捞出可拌可炒可汤，口感爽滑筋道。缙云爽面制作技艺传承至今，保留了传统手工制面的完整工艺。', '/pictures/缙云爽面制作技艺.webp', '2023-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (6012, '缙云歌谣', '缙云县', '缙云歌谣是流传于浙江省缙云县的民间文学类项目，以当地方言传唱，内容涉及劳动、爱情、生活等，反映了当地人民的生活智慧，已有数百年历史。缙云歌谣是缙云人民在长期生产生活中创造的口头文学，以歌谣形式传唱，代代相传。歌谣的曲调质朴动听，节奏自由灵活，有独唱、对唱、齐唱等多种形式。歌词多为七言四句，讲究押韵，比喻生动，情感真挚。内容十分丰富，有劳动歌如《采茶歌》《插秧歌》《砍柴歌》，表现了农民劳动的艰辛和快乐；有情歌如《望郎歌》《送郎歌》《相思歌》，表达了青年男女的爱慕之情；有生活歌如《劝世歌》《教子歌》《十二月歌》，传递做人道理和生活常识；有仪式歌如《哭嫁歌》《贺新房》《祭祖歌》，在婚丧嫁娶等场合演唱。缙云歌谣没有固定的曲谱，全凭口头传承，即兴编唱，是缙云民间文化的活化石。', '/pictures/缙云歌谣.webp', '2009-01-01 00:00:00.000000', '省级', '民间文学');
INSERT INTO `ich_project` VALUES (6013, '钢叉舞', '缙云县', '钢叉舞是流传于浙江省缙云县的传统舞蹈类项目，舞者手持钢叉进行表演，动作刚劲有力，节奏明快，具有浓厚的乡土气息，已有数百年历史。钢叉舞起源于古代民间武术活动，后发展成节庆表演。钢叉是一种古代兵器，三股叉头，装有铁环，舞动时哗哗作响。钢叉舞的表演形式多样，有单人舞、双人舞、集体舞等。表演时，舞者手持钢叉，随着锣鼓节奏，做出“雪花盖顶”“古树盘根”“鲤鱼翻背”“金鸡独立”等动作，同时抖动钢叉，使叉头铁环哗哗作响。动作刚劲有力，节奏明快热烈。集体表演时队形变化丰富，有“一字长蛇”“二龙戏珠”“八卦阵”等图案。钢叉舞还常常与其他民间舞蹈配合，如与舞龙、舞狮同场表演，气氛更加热烈。钢叉舞的表演者都是当地农民，利用农闲时间排练。每逢节庆庙会，钢叉舞队都会前来表演，增添喜庆气氛。钢叉舞动作刚劲，气势磅礴，是缙云民间舞蹈的代表之一。', '/pictures/钢叉舞.webp', '2007-01-01 00:00:00.000000', '省级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (6014, '缙云丝竹锣鼓', '缙云县', '缙云丝竹锣鼓是流传于浙江省缙云县的传统音乐类项目，以丝竹乐器和锣鼓打击乐相结合，演奏风格独特，多在节庆和民俗活动中表演，已有数百年历史。丝竹锣鼓是缙云民间器乐乐种，由丝竹乐和锣鼓乐两部分组成。丝竹乐器有笛子、二胡、三弦、琵琶、笙等，音色清越悠扬；锣鼓乐器有锣、鼓、钹、板等，音色洪亮热烈。两者结合，刚柔相济，既有丝竹的细腻婉转，又有锣鼓的雄浑磅礴。缙云丝竹锣鼓的曲牌丰富，有《将军令》《水龙吟》《八仙庆寿》《采茶调》等数十首，既有传统古曲，也有民间小调。演奏形式灵活多样，可独奏、齐奏，也可与戏曲、舞蹈等配合。缙云丝竹锣鼓的独特之处在于“十番”演奏，即多种乐器轮番演奏，同一曲牌每次演奏都有变化，或加花、或减字、或变奏，使音乐富有变化和生命力。缙云丝竹锣鼓多在节庆庙会、婚丧嫁娶等场合演奏。', '/pictures/缙云丝竹锣鼓.webp', '2012-01-01 00:00:00.000000', '省级', '传统音乐');
INSERT INTO `ich_project` VALUES (6015, '独角台场', '缙云县', '独角台场是流传于浙江省缙云县的传统音乐类项目，一人同时演奏多种乐器，技艺高超，是缙云独特的民间艺术形式，已有两百多年历史。独角台场顾名思义，即一人一台戏，表演者同时演奏多种乐器，如锣、鼓、钹、笛子、二胡等，手脚并用，口手配合，一人完成一个乐队的演奏。表演时，演员坐在特制的乐器架前，双手演奏锣鼓，双脚踩动踏板控制其他乐器，口中还能吹奏唢呐或笛子，真正做到了“一心多用”。这种表演形式要求演员具有极高的协调能力和音乐素养，需要经过长期训练才能掌握。独角台场的曲目多为民间小调、戏曲选段，如《八仙庆寿》《采茶调》《花头台》等。表演时节奏明快，气氛热烈，一人演奏出千军万马的气势。独角台场是缙云民间艺人的独创，体现了民间艺术的智慧和创造力。2012年，独角台场被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/独角台场.webp', '2012-01-01 00:00:00.000000', '省级', '传统音乐');
INSERT INTO `ich_project` VALUES (6016, '上宕功夫', '缙云县', '上宕功夫是流传于浙江省缙云县上宕村的传统体育类项目，是当地世代相传的传统武术，包含拳术和器械套路，已有两百多年历史。上宕功夫起源于清代，由上宕村先民创编，用于防身健体、保卫家园。这套功夫融合了南拳和北腿的特点，形成了独特的风格。上宕功夫的基本功包括桩功、步法、手法、身法等，强调下盘稳固，发力刚猛。拳术套路有“五虎拳”“四门拳”“梅花拳”等十多种，动作刚劲有力，步法稳健灵活。器械套路有单刀、双刀、棍术、枪术等，器械与拳术一脉相承，讲究“刀如猛虎，棍如游龙”。上宕功夫注重实战，每一招每一式都有明确的攻防含义。练习上宕功夫不仅可以强身健体，还可以防身自卫。上宕功夫世代口传身授，保持了完整的传承体系。每逢节庆庙会，上宕功夫队都会表演助兴，展示精湛的武艺。2012年，上宕功夫被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/上宕功夫.webp', '2012-01-01 00:00:00.000000', '省级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (6017, '叠牌坊（缙云迎罗汉）', '缙云县', '叠牌坊是缙云迎罗汉项目中的一种表演形式，表演者通过叠成人形牌坊，展示力量与技巧，是迎罗汉中最惊险、最精彩的环节，已有数百年历史。叠牌坊由数十人层层叠起，搭成人形牌坊，最高可达七八层。底层由身强力壮的男子组成，他们马步站稳，肩扛木板，作为牌坊的基石。中层的人踩在底层人的肩上，层层叠起，越往上人越少，越往上越惊险。最顶层是一个小孩，站在最高处，做出各种造型，如“童子拜观音”“金鸡独立”等。整个牌坊高达数米，巍然屹立，蔚为壮观。叠牌坊的过程中，所有人要配合默契，保持平衡，稍有不慎就会倒塌。叠成的牌坊造型有“牌坊”“莲花”“宝塔”等，寓意吉祥。叠牌坊的表演者都是当地农民，利用农闲时间排练。每逢张山寨七七会等重要节庆，各村迎罗汉队都会表演叠牌坊，展示本村的实力和技艺。2009年，叠牌坊作为迎罗汉的组成部分被列入省级非物质文化遗产代表性项目名录。', '/pictures/叠牌坊（缙云迎罗汉）.webp', '2009-01-01 00:00:00.000000', '省级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (6018, '河阳古民居建筑艺术', '缙云县', '河阳古民居建筑艺术是流传于浙江省缙云县河阳村的传统技艺类项目，涵盖河阳村古民居的规划设计、建筑结构、装饰艺术等，具有深厚的历史文化价值，已有上千年历史。河阳村是缙云著名的古村落，保存着大量明清时期的古民居，被誉为“江南古村落活化石”。河阳古民居的建筑艺术包括选址布局、木结构营造、砖雕、石雕、木雕等。村落依山傍水，布局严谨，街巷纵横，水系完善。民居多为三合院或四合院形式，中轴对称，前厅后堂，两侧厢房。木结构采用抬梁式和穿斗式相结合，榫卯连接，牢固耐用。装饰艺术丰富多彩，木雕在梁枋、雀替、门窗等处，雕刻人物、花鸟、山水等图案；砖雕在门楼、照壁等处，雕刻吉祥纹样；石雕在柱础、门墩等处，雕刻精美。河阳古民居建筑艺术是江南传统民居的杰出代表。2012年，河阳古民居建筑艺术被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/河阳古民居建筑艺术.webp', '2012-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (6019, '缙云石雕', '缙云县', '缙云石雕是流传于浙江省缙云县的传统美术类项目，以本地石材为原料，雕刻人物、花鸟、山水等题材，工艺精细，已有数百年历史。缙云地处山区，石材资源丰富，尤其以“缙云石”闻名，石质细腻，色泽青灰，适合雕刻。石雕技艺的工序包括选材、设计、打坯、细雕、修光、打磨等。选材要选质地均匀、无裂纹的石料。设计要根据石料的形状和纹理，构思作品的内容和构图，在石料上画出轮廓。打坯用大锤和凿子打出粗坯，确定作品的大体形状和层次。细雕用各种刀具精雕细刻，刻出人物五官、衣纹、花鸟羽毛、山水纹理等细节。修光用细凿和砂纸将表面打磨光滑，去除刀痕。打磨用磨石将作品表面磨光，使石质温润如玉。缙云石雕的题材广泛，有宗教人物如观音、罗汉，有历史人物如关公、岳飞，有吉祥图案如龙凤呈祥、福禄寿喜，有建筑构件如石狮、柱础、门墩。缙云石雕造型生动，工艺精湛。2016年，缙云石雕被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/缙云石雕.webp', '2016-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (6020, '田氏传统接骨术', '缙云县', '田氏传统接骨术是流传于浙江省缙云县的传统医药类项目，由田氏家族世代相传的正骨医术，以手法复位、夹板固定、中药外敷为主要特色，已有两百多年历史。田氏接骨术起源于清代，由田氏先祖创编，代代相传，至今已传承七代。田氏接骨术秉承中医“筋骨并重、内外兼治”的理念，在治疗骨折、脱位、软组织损伤等方面积累了丰富的临床经验。其核心技术包括：摸法诊断伤情，通过触摸判断骨折类型和移位情况；手法复位，运用牵、拉、端、提等手法将骨折复位；夹板固定，用杉树皮制成夹板，根据伤情进行固定，既牢固又透气；中药外敷，使用祖传秘方研制的膏药，具有活血化瘀、消肿止痛、续筋接骨的功效；分期内服中药，根据骨折愈合的不同阶段，内服不同方剂的中药，促进愈合。田氏接骨术疗效显著，在缙云及周边地区享有盛誉。2018年，田氏传统接骨术被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/田氏传统接骨术.webp', '2018-01-01 00:00:00.000000', '省级', '传统医药');
INSERT INTO `ich_project` VALUES (6021, '土布纺织技艺', '缙云县', '土布纺织技艺是流传于浙江省缙云县的传统技艺类项目，以棉花为原料，经纺线、织布等多道工序，织出土布，用于制作衣物和被褥，已有数百年历史。土布纺织是缙云农村妇女的传统手艺，家家户户都会纺织。纺织技艺包括轧花、弹花、搓条、纺线、络线、浆纱、经布、织布等工序。轧花用轧花机去除棉籽。弹花用弹花弓将棉花弹松软，使纤维松散均匀。搓条将弹好的棉花搓成棉条，便于纺线。纺线是最关键的环节，用纺车将棉条纺成棉线，要求粗细均匀，韧性好。络线将纺好的线络成线团。浆纱用米汤浆过，增加线的强度和光滑度。经布将线按照一定的规律排列在织布机上。织布用织布机一梭一梭地织出土布。土布有白布、花布、条纹布等多种，花纹通过经线和纬线的不同颜色和交织方式形成。土布厚实耐用，透气性好，是过去缙云人制作衣物、被褥的主要材料。2018年，土布纺织技艺被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/土布纺织技艺.webp', '2018-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (6022, '缙云油焖笋制作技艺', '缙云县', '缙云油焖笋制作技艺是流传于浙江省缙云县的传统烹饪技艺，以春笋为原料，经油焖加工，笋香浓郁，是当地特色菜肴，已有数百年历史。缙云山区盛产竹笋，每年清明前后春笋大量上市，油焖笋成为家家户户的时令美味。制作技艺包括选笋、剥壳、切块、焯水、油焖、调味等工序。选笋要选鲜嫩肥壮的春笋，以黄泥拱为佳。剥壳去除老根和外壳，保留最嫩的笋肉。切块将笋肉切成滚刀块，大小均匀。焯水将笋块放入沸水中煮几分钟，去除涩味和草酸。油焖是最关键的环节，锅中放足量油，烧热后下笋块煸炒，炒至笋块表面微黄，加入酱油、白糖、黄酒、高汤，大火烧开转小火慢焖。焖至汤汁浓稠，笋块入味，最后大火收汁，淋上香油即可。油焖笋的独特之处在于“油多火候足”，使笋充分吸收油脂和调味料，口感脆嫩，味道鲜甜。缙云油焖笋色泽红亮，笋香浓郁，咸中带甜，是春季餐桌上的美味佳肴。', '/pictures/缙云油焖笋制作技艺.webp', '2025-12-11 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (6023, '楼氏酥饼制作技艺', '缙云县', '楼氏酥饼制作技艺是流传于浙江省缙云县楼氏家族的传统面点技艺，以面粉和油脂为原料，制作酥脆可口的酥饼，已有上百年历史。楼氏酥饼是缙云传统茶食，以其层层酥脆、入口即化的特点深受喜爱。制作技艺包括和面、制酥、制馅、包酥、成形、烤制等工序。和面将面粉加水和成水油皮面团，揉至光滑有筋道。制酥将面粉与猪油搓成油酥面团，这是酥饼起酥的关键。制馅选用芝麻、白糖、桂花等，炒熟研磨，调成甜馅。包酥是最关键的环节，将水油皮包入油酥，擀开折叠，反复数次，形成数十层面皮。将面皮卷起切段，每段压扁包入馅料，收口捏紧，压成饼形。成形后在饼面刷蛋液，撒上芝麻。烤制将饼坯放入烤炉，用中火烤至两面金黄。楼氏酥饼的独特之处在于“三翻三烤”，反复翻面烘烤，使酥饼均匀受热，层层分明。成品酥饼色泽金黄，酥脆可口，香气扑鼻。', '/pictures/楼氏酥饼制作技艺.webp', '2025-12-11 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (6024, '畲族蓝染制作技艺', '缙云县', '畲族蓝染制作技艺是流传于浙江省缙云县畲族聚居区的传统技艺，以蓝草为染料，对布料进行染色，制作出蓝色花纹的布料，是畲族传统工艺，已有数百年历史。蓝染技艺包括种蓝、采蓝、制靛、建缸、染色、氧化、清洗等工序。种蓝种植蓝草，如蓼蓝、菘蓝等。采蓝在夏秋季节收割蓝草。制靥将蓝草浸泡发酵，加入石灰搅拌，沉淀得到蓝靛泥。建缸将蓝靛泥加入碱水和酒糟，建立发酵缸，使染料还原成可染状态。染色是最关键的环节，将白布浸入染缸，反复多次，每染一次取出氧化，使蓝色加深。染色次数决定颜色的深浅，从浅蓝到深蓝，再到青黑色。缙云畲族蓝染的特色在于“扎染”和“蜡染”。扎染是将布料按设计扎结，染色后解开，形成花纹；蜡染是用蜡在布料上绘制图案，染色后去蜡，形成蓝底白花。染好的布料可制作服装、头巾、被面等。2025年，畲族蓝染制作技艺被列入缙云县非物质文化遗产代表性项目名录。', '/pictures/畲族蓝染制作技艺.webp', '2025-12-11 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (6025, '缙云清明粿制作技艺', '缙云县', '缙云清明粿制作技艺是流传于浙江省缙云县的传统节令食品技艺，以鼠曲草或艾草汁和糯米粉制成外皮，包入馅料，蒸制而成，用于清明祭祀和食用，已有数百年历史。清明粿是缙云人清明节必备的传统食品，既用于祭祀祖先，也是时令美味。制作技艺包括采草、洗草、煮草、捣汁、和面、制馅、包制、蒸制等工序。采草在清明前后，采摘鲜嫩的鼠曲草或艾草，洗净后入沸水煮软，捞出捣烂成泥，或用石臼捣出汁液。将草泥或草汁与糯米粉混合，加入适量白糖，揉成绿色的面团，这是清明粿的外皮。馅料有甜咸两种，甜馅常用红豆沙，咸馅常用笋丁、肉末、香菇、豆腐干等炒制。包制时，取一小团面皮，捏成碗状，包入馅料，收口搓圆，放入刻有花纹的模具中压印成形。成形后的清明粿垫上粽叶，上笼蒸熟。蒸好的清明粿色泽碧绿，清香扑鼻，口感软糯，甜咸皆宜。', '/pictures/缙云清明粿制作技艺.webp', '2025-12-11 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (6026, '溶江花灯制作技艺', '缙云县', '溶江花灯制作技艺是流传于浙江省缙云县溶江乡的传统手工技艺，以竹篾扎制骨架，糊以彩纸，制作各种造型的花灯，已有三百多年历史。溶江花灯种类繁多，有龙灯、鱼灯、走马灯、宫灯、纱灯等数十种。制作工序包括设计、破篾、扎架、糊纸、彩绘、装饰等。设计要构思造型和尺寸，溶江花灯造型生动，寓意吉祥。破篾将竹子劈成粗细均匀的篾条，要求柔韧有弹性。扎架用篾条扎出灯的基本骨架，要求结构牢固、比例准确。糊纸用糨糊将彩纸平整地糊在骨架上，要求表面光滑无褶皱。彩绘用颜料在灯面上绘制图案，溶江花灯的彩绘以花鸟、人物、山水为主，色彩鲜艳，线条流畅。装饰用流苏、珠串、剪纸等点缀，使花灯更加精美。溶江花灯的独特之处在于“动”，走马灯利用空气对流原理，灯内画面可自动旋转；“滚龙灯”通过齿轮传动，龙身可蜿蜒摆动。每逢元宵佳节，溶江乡都要举办灯会，各式花灯争奇斗艳，流光溢彩。', '/pictures/溶江花灯制作技艺.webp', '2025-12-11 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (6027, '归一针灸疗法', '缙云县', '归一针灸疗法是流传于浙江省缙云县的传统医药类项目，以针刺特定穴位治疗疾病，是中医外治法的一种，已有上百年历史。归一针灸由缙云民间中医创立，融合了传统针灸理论和实践经验，形成了独特的诊疗体系。归一针灸的理论基础是“归一论”，认为人体是一个有机整体，疾病是阴阳失衡、气血不畅的表现，通过针刺特定穴位可以调节阴阳、疏通经络、调和气血，使人体回归正常状态。归一针灸的取穴特点是“少而精”，每次治疗只取三五个穴位，但选穴精准，配伍得当。针法特点是“轻而透”，进针轻巧，透穴准确，患者痛苦小，疗效显著。归一针灸擅长治疗各种痛症、中风后遗症、面瘫、失眠、肠胃病等。传承人积累了丰富的临床经验，总结出数十种疾病的针灸治疗方案。归一针灸疗法在缙云及周边地区享有盛誉，深受群众信赖。2025年，归一针灸疗法被列入缙云县非物质文化遗产代表性项目名录。', '/pictures/归一针灸疗法.webp', '2025-12-11 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (6028, '缙云陶氏传统膏药制作技艺', '缙云县', '缙云陶氏传统膏药制作技艺是流传于浙江省缙云县陶氏家族的传统医药技艺，以多种中药材熬制膏药，用于治疗跌打损伤和风湿痹痛，已有上百年历史。陶氏膏药由陶氏先祖创制于清末，代代相传，至今已传承五代。陶氏膏药的制作技艺包括选药、炮制、配料、熬制、下丹、去火毒、摊涂等工序。选药要选道地药材，如川乌、草乌、乳香、没药、血竭等数十味。炮制将药材按规范进行炮制，如炒、炙、煅、煨等，增强药效，降低毒性。配料按祖传秘方将各味药材配比好。熬制是最关键的环节，将配好的药材放入香油中浸泡数日，然后用文火熬煮，使药效充分溶解在油中。熬至药枯焦黄时过滤去渣，继续熬炼药油，至滴水成珠。下丹将铅丹徐徐加入药油中，不断搅拌，使油丹化合，形成膏药基质。去火毒将熬好的膏药倒入冷水中浸泡数日，去除火毒。摊涂将膏药基质加热熔化，摊涂在布或纸上，折叠备用。陶氏膏药药力深厚，疗效显著，在缙云及周边地区享有盛誉。', '/pictures/缙云陶氏传统膏药制作技艺.webp', '2025-12-11 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (6029, '缙云悬雕', '缙云县', '缙云悬雕是流传于浙江省缙云县的传统美术类项目，在木材上进行悬空雕刻，技艺精湛，作品立体感强，已有两百多年历史。悬雕是一种高难度的雕刻技艺，作品与背景完全分离，仅靠少数连接点支撑，给人以悬空而立的感觉。悬雕的工序包括选材、设计、打坯、细雕、修光、打磨等。选材要选质地细腻、坚韧的木材，如黄杨木、银杏木等。设计要根据木材的形状和大小，构思作品的内容和构图，画出轮廓。打坯用各种刀具凿出粗坯，确定作品的大体形状和层次。细雕是最关键的环节，用极细的刀具精雕细刻，刻出人物的五官、衣纹，花鸟的羽毛、枝叶，要求线条流畅，形态逼真。悬雕的难度在于雕刻时要考虑作品的平衡和连接，既要刻出悬空的效果，又要保证作品的牢固。修光用细刀和砂纸将表面打磨光滑，去除刀痕。打磨使作品表面光滑细腻。缙云悬雕的题材以人物、花鸟为主，作品玲珑剔透，立体感强。2010年，缙云悬雕被列入丽水市非物质文化遗产代表性项目名录。', '/pictures/缙云悬雕.webp', '2010-12-01 00:00:00.000000', '市级', '传统美术');
INSERT INTO `ich_project` VALUES (6030, '稠峰神马', '缙云县', '稠峰神马是流传于浙江省缙云县稠峰村的传统舞蹈类项目，舞者腰间系着竹马道具，模仿骑马动作进行表演，已有两百多年历史。稠峰神马起源于清代，最初是祭祀山神的仪式，后发展成节庆舞蹈。神马道具用竹篾扎制马头和马身骨架，外糊彩纸或彩绸，彩绘马眼、马鬃、马鞍，系在舞者腰间，看起来就像人骑在马上。表演时，舞者手持马鞭，随着锣鼓节奏，做出“策马扬鞭”“勒马回首”“马跃山涧”“马踏飞燕”等动作，模仿骑马的各种姿态。可以单人表演，也可以多人集体表演。集体表演时队形变化丰富，有“一字长蛇”“二龙戏珠”“八卦阵”等图案。稠峰神马的独特之处在于“跑阵”，舞者按照一定的路线奔跑穿梭，形成各种阵势，如“梅花阵”“八卦阵”“迷魂阵”等，令人眼花缭乱。稠峰神马的表演者都是当地农民，利用农闲时间排练。每逢节庆庙会，稠峰神马队都会前来表演，增添喜庆气氛。', '/pictures/稠峰神马.webp', '2010-12-01 00:00:00.000000', '市级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (6031, '小溪大龙舞', '缙云县', '小溪大龙舞是流传于浙江省缙云县小溪村的传统舞蹈类项目，以布扎制龙身，多人舞动，气势磅礴，是当地节庆活动的重要表演项目，已有三百多年历史。小溪大龙全长约五十米，分为十二节，龙身用竹篾扎制骨架，外罩彩绘龙布，龙鳞、龙爪、龙须等细节栩栩如生。龙头重约三十斤，需要身强力壮的舞者才能举起。表演时，由一人持龙珠引路，十二人持龙杆舞动，在锣鼓声中做出“龙抬头”“龙摆尾”“龙翻身”“龙戏珠”等动作。小溪大龙的舞法丰富多彩，有“盘龙柱”“穿龙肚”“跳龙门”“龙抢珠”等数十种套路，要求舞者配合默契，动作整齐划一。夜间表演时，龙身内点蜡烛，整条龙流光溢彩，犹如真龙降世。小溪大龙的独特之处在于“龙吐水”，在龙嘴处安装喷水装置，舞动时可喷出水雾，象征龙行布雨，祈求风调雨顺。每逢春节、元宵、庙会等重大节日，小溪村都要舞起大龙，祈求风调雨顺、国泰民安。', '/pictures/小溪大龙舞.webp', '2010-12-01 00:00:00.000000', '市级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (6032, '缙云索面', '缙云县', '缙云索面制作工艺是流传于浙江省缙云县的传统技艺类项目，以面粉为原料，经拉制、晾晒等工序制成细如发丝的面条，已有数百年历史。缙云索面又称“长寿面”，是缙云人过生日、婚庆、过年等喜庆场合必备的食品，寓意长寿吉祥。索面制作技艺包括和面、醒面、切条、搓条、盘条、拉面、晒面等工序。和面用高筋面粉加盐和水，反复揉制，使面团光滑有筋道。醒面将和好的面团盖上湿布，静置一小时，使面筋充分舒展。切条将醒好的面团擀成厚片，切成粗条。搓条将粗条搓成细长条。盘条将搓好的面条盘旋在盆中，每层刷油，防止粘连，再次醒面。拉面是最关键的环节，将盘好的面条两端拉长，边拉边抖，使面条越来越细，均匀一致。缙云索面的独特之处在于“三拉三醒”，反复拉伸和醒面，使面条细如发丝而不断。晒面将拉好的面条挂在特制的面架上，在阳光下晒干。晒干的索面色泽洁白，细如发丝，柔韧有弹性。', '/pictures/缙云索面.webp', '2010-12-01 00:00:00.000000', '市级', '传统技艺');
INSERT INTO `ich_project` VALUES (7003, '遂昌昆曲十番', '遂昌县', '遂昌昆曲十番是流传于浙江省遂昌县的传统音乐类项目，以昆曲曲牌为唱本，用丝竹乐器演奏，保留了早期昆曲的原始风貌，已有四百多年历史。遂昌昆曲十番起源于明代，相传与著名戏剧家汤显祖有关。汤显祖曾任遂昌知县，在任期间推广昆曲，遂昌民间逐渐形成了演奏昆曲十番的传统。十番即多种乐器轮番演奏，遂昌昆曲十番的乐器组合有笛子、二胡、三弦、琵琶、笙等丝竹乐器，配以板鼓、檀板、小锣等打击乐器。演奏的曲牌多为汤显祖《牡丹亭》中的唱段，如《游园》《惊梦》《寻梦》等，也有《长生殿》《西厢记》中的经典曲牌。遂昌昆曲十番的演奏风格古朴典雅，节奏舒缓，旋律优美，保留了明代昆曲的演唱风格和演奏技法。遂昌昆曲十番不仅在民间流传，还被吸收到道教音乐中，在斋醮仪式中演奏。2007年，遂昌昆曲十番被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/遂昌昆曲十番.webp', '2007-01-01 00:00:00.000000', '省级', '传统音乐');
INSERT INTO `ich_project` VALUES (7004, '黑陶烧制技艺', '遂昌县', '遂昌黑陶烧制技艺是流传于浙江省遂昌县的传统手工技艺，以当地特有陶土为原料，经拉坯、雕刻、烧制等工序制成黑陶器皿，胎质细腻，色泽黑亮，已有数百年历史。遂昌黑陶选用本地特有的陶土，这种陶土含铁量高，烧成后呈黑色。黑陶烧制技艺的工序包括选土、淘洗、陈腐、练泥、拉坯、修坯、雕刻、晾干、烧制等。选土要选质地细腻、黏性好的陶土。淘洗将陶土加水淘洗，去除杂质。陈腐将淘洗好的泥料放置数月，使泥质更加均匀细腻。练泥用脚踩或手揉，排除泥中气泡，增加可塑性。拉坯是最关键的环节，将泥料放在转盘上，用手拉制成各种器型，要求器壁厚薄均匀，造型规整。修坯将拉好的坯体修整光滑。雕刻在坯体上雕刻各种图案，遂昌黑陶的雕刻以几何纹、云雷纹、龙纹为主。晾干将雕刻好的坯体阴干，不能暴晒，以免开裂。烧制将干坯装入窑中，用松柴烧制，烧成温度约一千度。遂昌黑陶色泽黑亮，古朴典雅。', '/pictures/黑陶烧制技艺.webp', '2007-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (7005, '遂昌布衣拳', '遂昌县', '遂昌布衣拳是流传于浙江省遂昌县民间的传统武术，据传与明代抗倭历史有关，拳法朴实实用，是布衣百姓创编的防身技艺，已有四百多年历史。布衣拳相传由明代遂昌布衣百姓在抗倭斗争中创编，用于保家卫国。这套拳法融合了南拳和北腿的特点，形成了独特的风格。布衣拳的基本功包括桩功、步法、手法、身法等，强调下盘稳固，发力刚猛。拳术套路有“布衣一路”“布衣二路”“布衣三路”等，每套拳都由数十个动作组成，动作朴实无华，但招招实用。布衣拳的特点是“近身短打”，讲究近距离格斗，以肘、膝、肩、胯等部位攻击，招式简捷，杀伤力强。布衣拳还包括器械套路，如布衣棍、布衣刀、布衣叉等，器械与拳术一脉相承，以农具为武器，如扁担、锄头、柴刀等，体现了布衣百姓的特点。布衣拳世代口传身授，保持了完整的传承体系。2023年，遂昌布衣拳被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/遂昌布衣拳.webp', '2023-01-01 00:00:00.000000', '省级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (7006, '茶园武术', '遂昌县', '茶园武术是流传于浙江省遂昌县茶园乡的传统体育项目，在茶园乡村世代相传，包含拳术和器械套路，具有强身健体和表演功能，已有两百多年历史。茶园武术起源于清代，由茶园乡先民创编，用于防身健体、保卫家园。这套武术融合了南拳和北腿的特点，形成了独特的风格。茶园武术的基本功包括桩功、步法、手法、身法等，强调下盘稳固，发力刚猛。拳术套路有“五虎拳”“四门拳”“梅花拳”等十多种，动作刚劲有力，步法稳健灵活。器械套路有单刀、双刀、棍术、枪术等，器械与拳术一脉相承，讲究“刀如猛虎，棍如游龙”。茶园武术的独特之处在于“茶山练功”，利用茶山的地形地貌进行训练，如在山坡上练步法，在茶树间练身法，在茶垄里练桩功。茶园武术世代口传身授，保持了完整的传承体系。每逢节庆庙会，茶园武术队都会表演助兴，展示精湛的武艺。2016年，茶园武术被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/茶园武术.webp', '2016-01-01 00:00:00.000000', '省级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (7007, '遂昌木偶戏', '遂昌县', '遂昌木偶戏是流传于浙江省遂昌县的传统戏剧类项目，艺人以线操纵木偶表演，配以古朴唱腔和传统乐器，演绎民间故事，深受群众喜爱，已有三百多年历史。遂昌木偶戏属于提线木偶，木偶高约两尺，用樟木雕刻头部，彩绘脸谱，服饰用绸缎制作，四肢关节可活动，通过十几根细线连接操纵。木偶戏的操纵技巧十分复杂，艺人通过提拉不同位置的线，使木偶做出行走、转身、作揖、舞剑等各种动作。唱腔以乱弹为主，融合徽调、昆腔等，高亢激越。伴奏乐器有锣、鼓、钹、笛子、二胡等，气氛热烈。传统剧目有《白蛇传》《西游记》《三国演义》《封神榜》等数十本，内容多为历史故事和神话传说。遂昌木偶戏的独特之处在于“文武兼备”，既能表演文戏的细腻情感，也能表演武戏的热烈场面。木偶戏班多在庙会、节庆时演出，走村串户，深受欢迎。2012年，遂昌木偶戏被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/遂昌木偶戏.webp', '2012-01-01 00:00:00.000000', '省级', '传统戏剧');
INSERT INTO `ich_project` VALUES (7008, '蔡和脸谱', '遂昌县', '蔡和脸谱是流传于浙江省遂昌县的传统美术，用于戏曲表演的面部化妆艺术，脸谱色彩鲜明，图案独特，具有浓郁的地方特色，已有两百多年历史。蔡和脸谱由蔡和村艺人创制，用于当地戏曲表演，逐渐形成独特的风格。蔡和脸谱的色彩以红、黑、白、黄、蓝为主，每种颜色都有特定的寓意，如红色代表忠勇，黑色代表刚直，白色代表奸诈，黄色代表勇猛，蓝色代表刚强。脸谱的图案丰富多样，有整脸、三块瓦、花脸、歪脸等类型，每种脸谱都有固定的谱式。蔡和脸谱的独特之处在于“象形脸”，根据人物的性格特点，在脸上画出象征性的图案，如包公额上的月牙，象征其明察秋毫；关羽脸上的七星，象征其忠义。蔡和脸谱的绘制工序包括净面、打底、勾线、填色、勾白等，全部手工绘制，要求线条流畅，色彩均匀。蔡和脸谱不仅在舞台上使用，还被绘制在木偶、面具上，成为独立的艺术品。2012年，蔡和脸谱被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/蔡和脸谱.webp', '2012-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (7009, '遂昌吟诵', '遂昌县', '遂昌吟诵是流传于浙江省遂昌县的传统音乐类项目，是用遂昌方言诵读古诗文的一种方式，具有独特的韵律和腔调，是研究当地方言和传统文化的重要载体，已有数百年历史。吟诵是中国传统的读书方式，用方言诵读诗文，既有音乐的韵律，又有语言的意义。遂昌吟诵以遂昌方言为基础，保留了古汉语的入声和声调特点，韵律独特。吟诵的腔调有平调、仄调、长调、短调等，根据诗文的内容和情感，选择不同的腔调。吟诵古诗时，节奏舒缓，韵味悠长；吟诵古文时，节奏变化，抑扬顿挫。遂昌吟诵的曲目丰富，有《诗经》《楚辞》中的篇章，有唐诗宋词中的名篇，也有当地文人创作的诗文。遂昌吟诵不仅是读书的方式，也是文人雅集、教学传承的重要内容。老一辈读书人都能吟诵，随着普通话的推广，会吟诵的人越来越少。2021年，遂昌吟诵被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/遂昌吟诵.webp', '2021-07-30 00:00:00.000000', '县级', '传统音乐');
INSERT INTO `ich_project` VALUES (7010, '畲族舞蹈', '遂昌县', '遂昌畲族舞蹈是流传于浙江省遂昌县畲族聚居区的传统舞蹈，舞姿优美，节奏欢快，多在节庆和祭祀场合表演，已有数百年历史。畲族舞蹈是畲族文化的重要组成部分，与畲族的历史、信仰、生活密切相关。遂昌畲族舞蹈的种类丰富，有祭祖舞、狩猎舞、采茶舞、婚庆舞等。祭祖舞在祭祀祖先时表演，动作庄重肃穆，表达对祖先的崇敬；狩猎舞模仿狩猎过程，动作矫健有力，表现畲族人民的勇敢；采茶舞模仿采茶劳动，动作优美流畅，表现茶园的欢乐；婚庆舞在婚礼上表演，动作欢快热烈，祝福新人幸福。遂昌畲族舞蹈的伴奏以锣鼓和山歌为主，节奏明快，气氛热烈。舞蹈队形变化丰富，有围圈、穿插、列队等。遂昌畲族舞蹈的独特之处在于“以歌带舞”，舞蹈与山歌紧密结合，边唱边舞，载歌载舞。舞蹈动作多模仿劳动和生活场景，如采茶、砍柴、舂米、织布等，生活气息浓郁。2021年，遂昌畲族舞蹈被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/畲族舞蹈.webp', '2021-07-30 00:00:00.000000', '县级', NULL);
INSERT INTO `ich_project` VALUES (7011, '雕刻', '遂昌县', '遂昌雕刻是流传于浙江省遂昌县的传统美术类项目，以木雕、石雕为主，题材广泛，工艺精细，用于建筑装饰和生活用具，已有数百年历史。遂昌雕刻选用当地产的木材和石材，如樟木、银杏木、青石等。木雕技艺的工序包括选材、设计、打坯、细雕、修光、打磨、上漆等。选材要选质地细腻、无疤节的木材。设计要根据材料的形状和纹理，构思作品的内容和构图。打坯用大凿凿出粗坯，确定作品的大体形状和层次。细雕用各种刀具精雕细刻，刻出人物五官、衣纹、花鸟羽毛、山水纹理等细节。修光用细刀和砂纸将表面打磨光滑。上漆用清漆涂饰，保护木料，增加美观。石雕技艺的工序包括选材、设计、打坯、细雕、修光、打磨等，与木雕相似，但工具和技法不同。遂昌雕刻的题材广泛，有宗教人物、历史故事、吉祥图案、花鸟鱼虫等。遂昌雕刻主要用于建筑装饰，如祠堂、庙宇、民居的梁枋、雀替、门窗等。2021年，遂昌雕刻被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/雕刻.webp', '2021-07-30 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (7012, '风炉宴烧制技艺', '遂昌县', '风炉宴烧制技艺是流传于浙江省遂昌县的传统烹饪技艺，以风炉为炊具，慢火炖煮，菜品原汁原味，是遂昌山区独特的饮食文化，已有数百年历史。风炉是遂昌山区特有的炊具，用陶土烧制而成，形如小缸，中间可烧炭火，上面架锅炖煮。风炉宴就是用风炉慢火炖煮的宴席，菜品多为山珍野味，如土鸡、野兔、山笋、香菇等。风炉宴烧制技艺包括选料、切配、入锅、加汤、调味、炖煮等工序。选料要选当地产的土鸡、土鸭、山猪肉等，肉质紧实，味道鲜美。切配将食材切成适当大小。入锅将食材放入锅中，加入山泉水。调味加入盐、姜、葱等简单调料，保持原汁原味。炖煮是最关键的环节，将锅放在风炉上，用炭火慢炖数小时，使食材充分软化，汤汁浓郁。风炉宴的独特之处在于“慢火出美味”，长时间的炖煮使食材的鲜味充分释放，汤汁醇厚。在遂昌山区，风炉宴是待客的最高礼遇。2021年，风炉宴烧制技艺被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/风炉宴烧制技艺.webp', '2021-07-30 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7013, '遂昌扎染技艺', '遂昌县', '遂昌扎染技艺是流传于浙江省遂昌县的传统手工技艺，以布料为原料，通过扎结、染色等工序制作出各种图案的纺织品，古朴雅致，已有数百年历史。扎染是一种古老的染色技艺，通过将布料扎结起来，使染料无法渗透到扎结部分，形成花纹。遂昌扎染技艺的工序包括设计、扎结、染色、氧化、清洗、拆结、晾晒等。设计要在布料上构思图案的布局。扎结是最关键的环节，用线将布料按设计扎结起来，扎结的方式不同，形成的花纹也不同。有缝扎、捆扎、夹扎等多种技法。染色将扎结好的布料浸入染缸中，反复多次，使未扎结的部分充分上色。氧化将染好的布料取出，接触空气，使颜色固定。清洗用清水洗去浮色。拆结将扎结的线拆开，露出花纹。晾晒将染好的布料晾干。遂昌扎染的染料以植物染料为主，如靛蓝、茜草、黄檗等，色彩自然柔和。扎染的图案有几何纹、花鸟纹、云雷纹等，古朴雅致。扎染制品可制作服装、围巾、桌布等。2021年，遂昌扎染技艺被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/遂昌扎染技艺.webp', '2021-07-30 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7014, '方粽制作技艺', '遂昌县', '方粽制作技艺是流传于浙江省遂昌县的传统食品加工技艺，与长粽不同，方粽造型独特，内馅丰富，是当地节庆食品，已有数百年历史。遂昌方粽因其方形而得名，是遂昌端午节的传统食品。制作技艺包括浸米、调味、制馅、包粽、煮粽等工序。选用优质糯米，淘洗干净后浸泡数小时。调味将浸泡好的糯米加入盐、酱油、五香粉等调料拌匀，使米粒入味。馅料有咸甜两种，咸馅常用猪肉、香菇、笋丁、板栗等炒制，甜馅常用红豆沙、蜜枣、莲子等。包粽是最关键的环节，用两张粽叶交叉叠放，放入调好味的糯米，中间放入馅料，再盖上糯米，将粽叶折起，包成方形，用棕榈叶撕成的细绳扎紧。包好的方粽四角分明，形状规整。煮粽将包好的方粽放入大锅中，加水没过粽子，用旺火煮三小时以上，再焖一夜，使粽叶的清香充分渗入糯米。遂昌方粽的独特之处在于“料多味足”，一个粽子重达半斤以上，馅料丰富，米香、肉香、叶香融合，风味独特。', '/pictures/方粽制作技艺.webp', '2021-07-30 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7015, '陈五粮白酒制作技艺', '遂昌县', '陈五粮白酒制作技艺是流传于浙江省遂昌县的传统酿酒技艺，以五种粮食为原料，经发酵、蒸馏酿制白酒，酒香醇厚，已有上百年历史。陈五粮白酒由陈氏家族创制，以高粱、大米、糯米、小麦、玉米五种粮食为原料，故名“五粮”。酿造技艺包括浸粮、蒸粮、摊凉、拌曲、入窖发酵、蒸馏取酒、陈化老熟等工序。浸粮将五种粮食分别浸泡，使粮粒充分吸水。蒸粮将浸泡好的粮食分别蒸熟，要求熟而不烂。摊凉将蒸好的粮食摊开降温，至适合发酵的温度。拌曲加入特制的酒曲，这是五粮酒酿造的关键，曲的质量直接影响酒的品质。入窖发酵将拌曲后的粮食装入泥窖中，密封发酵，发酵期约两个月，期间要控制温度湿度。蒸馏取酒将发酵好的酒醅倒入蒸馏锅，加热蒸馏，提取白酒。新蒸出的白酒酒精度高达六十度以上，需装入陶坛陈化三年以上，使酒质更加醇和。陈五粮白酒无色透明，酒香浓郁，入口醇厚，回味悠长。', '/pictures/陈五粮白酒制作技艺.webp', '2021-07-30 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7016, '饭果制作技艺', '遂昌县', '饭果制作技艺是流传于浙江省遂昌县的传统小吃技艺，以糯米为主料，经蒸煮、捣制、成型等工序制成，口感软糯，是当地传统食品，已有数百年历史。饭果是遂昌民间的小吃，因其形状如水果而得名。制作技艺包括浸米、蒸米、捣制、成型、裹粉等工序。选用优质糯米，淘洗干净后浸泡过夜，使米粒充分吸水。蒸米将浸泡好的糯米放入木甑中，用旺火蒸熟，要求米粒熟透而不烂。捣制是最关键的环节，将蒸好的糯米饭趁热倒入石臼，用木槌反复捣打。捣打要用力均匀，不断翻动，使米粒完全破碎，相互粘连，形成有韧性的米团。捣好的米团取出，在案板上搓成长条，切成小块，用手捏成各种水果形状，如桃子、苹果、梨等。成型后在表面裹上炒熟的黄豆粉或芝麻粉，防止粘连，增加香味。饭果的独特之处在于“形似水果”，不仅口感软糯，而且造型逼真，深受儿童喜爱。在遂昌农村，每逢喜庆节日，主人家都会制作饭果待客。', '/pictures/饭果制作技艺.webp', '2021-07-30 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7017, '传统竹编技艺', '遂昌县', '传统竹编技艺是流传于浙江省遂昌县的传统手工艺，以竹篾编织各种生活用具和工艺品，技艺精湛，品种繁多，已有数百年历史。遂昌地处山区，盛产毛竹，为竹编提供了丰富的原材料。竹编技艺的工序包括选竹、砍竹、破篾、匀篾、煮篾、染色、编织、收口、修整等。选竹要选生长三年以上的毛竹，竹身粗直，无虫蛀。破篾将竹子剖成粗细均匀的竹篾，最细的篾条可薄如纸张。匀篾用匀刀将竹篾刮匀刮薄，使宽窄厚度一致。煮篾将竹篾放入沸水中煮，去除糖分，防止虫蛀。染色用天然染料将竹篾染成各种颜色。编织是最关键的环节，有十字编、人字编、六角编、螺旋编等数十种编织技法，可编出各种图案和文字。遂昌竹编的产品种类繁多，有生产用的竹篮、竹筐、竹篓，有生活用的竹席、竹枕、竹椅，有装饰用的竹画、竹屏风、竹灯笼。遂昌竹编以其工艺精细、造型美观、经久耐用而著称。', '/pictures/传统竹编技艺.webp', '2021-07-30 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7018, '毛家布鞋制作技艺', '遂昌县', '毛家布鞋制作技艺是流传于浙江省遂昌县毛氏家族的传统制鞋技艺，以棉布为原料，经糊布、剪样、纳底、绱鞋等多道工序制成，穿着舒适，已有上百年历史。毛家布鞋由毛氏先祖创制于清末，代代相传，至今已传承五代。布鞋制作技艺包括打袼褙、剪样、包边、纳底、绱鞋、楦鞋等工序。打袼褙用面粉打成糨糊，将碎布一层一层糊在木板上，晒干成硬挺的袼褙。剪样根据鞋样尺寸，将袼褙剪成鞋底和鞋帮的形状。包边用白布条将鞋底和鞋帮的边缘包好。纳底是最关键的环节，用麻线将多层鞋底纳在一起，要求针脚均匀，疏密得当。纳好的鞋底结实耐磨，透气性好。绱鞋将鞋帮与鞋底缝合在一起，要求鞋帮平整，不歪不斜。楦鞋将鞋楦放入鞋内，撑出鞋型，使鞋子合脚舒适。毛家布鞋的独特之处在于“千层底”，鞋底由数十层布纳成，柔软而有弹性，穿着舒适，吸汗透气。毛家布鞋经久耐穿，深受群众喜爱。', '/pictures/毛家布鞋制作技艺.webp', '2021-07-30 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7019, '红军大凉茶', '遂昌县', '红军大凉茶是流传于浙江省遂昌县的传统医药项目，据传与红军革命历史有关，以多种中草药熬制，具有清凉解暑的功效，已有近百年历史。遂昌是革命老区，1935年红军挺进师在遂昌开展游击战争。据传，红军战士在山区活动时，当地百姓用祖传的凉茶秘方为红军战士解暑治病，故名“红军大凉茶”。红军大凉茶的配方包括夏枯草、金银花、菊花、薄荷、淡竹叶、甘草等十多味中草药，具有清热解毒、消暑利尿的功效。制作技艺包括选药、清洗、切段、配比、熬煮、过滤、冷却等工序。选药要选道地药材，以野生为佳。清洗将药材洗净，去除杂质。切段将长茎药材切段。配比按祖传秘方将各味药材配比好。熬煮将配好的药材放入大锅中，加水熬煮，先用大火烧开，再用小火慢熬，使药效充分溶解。过滤将药渣滤去，得到凉茶汤液。冷却将凉茶自然冷却，或放入冰箱冷藏。红军大凉茶色泽金黄，清凉爽口，是夏季解暑佳品。', '/pictures/红军大凉茶.webp', '2021-07-30 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (7020, '蛇医', '遂昌县', '蛇医是流传于浙江省遂昌县的传统医药项目，专门治疗蛇咬伤的民间医术，积累了大量治疗蛇伤的验方和经验，已有数百年历史。遂昌地处山区，蛇类众多，毒蛇咬伤时有发生，蛇医应运而生。蛇医世代口传身授，积累了丰富的蛇伤治疗经验。蛇医的核心技术包括蛇伤诊断、急救处理、药物治疗等。诊断要根据伤口形态、病人症状判断蛇的种类和毒性。急救处理包括结扎、排毒、清洗等，阻止毒素扩散。药物治疗是蛇医的绝活，使用多种中草药配制而成。常用草药有七叶一枝花、半边莲、白花蛇舌草、穿心莲等，具有清热解毒、消肿止痛的功效。蛇医根据不同的蛇伤，使用不同的方剂，有的内服，有的外敷。蛇医还掌握“拔毒”技法，用特制的药膏敷在伤口上，将毒素拔出。遂昌蛇医在长期实践中积累了丰富的经验，治愈率很高。蛇医不仅是医术，更是救命的本领，深受山区群众信赖。', '/pictures/蛇医.webp', '2021-07-30 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (7021, '吴氏耳穴诊疗技术', '遂昌县', '吴氏耳穴诊疗技术是流传于浙江省遂昌县吴氏家族的传统医药项目，通过刺激耳部特定穴位诊断和治疗疾病，是中医外治法的一种，已有上百年历史。耳穴诊疗的理论基础是中医经络学说，认为耳廓是人体经络的汇聚之处，全身各部位在耳廓上都有相应的反射区。吴氏耳穴诊疗技术包括耳穴诊断和耳穴治疗两部分。耳穴诊断通过观察耳廓的色泽、形态变化，或按压耳穴寻找压痛点，来判断疾病。如胃病在耳穴“胃区”有压痛，心脏病在“心区”有反应。耳穴治疗用针刺、按压、贴压等方法刺激耳穴，达到治疗目的。常用方法有耳针、耳压、耳灸等。耳针用毫针刺入耳穴，留针一段时间；耳压用王不留行籽贴在耳穴上，患者自行按压；耳灸用艾条熏灸耳穴。吴氏耳穴诊疗技术擅长治疗各种痛症、失眠、高血压、肠胃病等。传承人积累了丰富的临床经验，总结出数十种疾病的耳穴治疗方案。', '/pictures/吴氏耳穴诊疗技术.webp', '2021-07-30 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (7022, '蔡相传说', '遂昌县', '蔡相传说是流传于浙江省遂昌县的民间文学项目，讲述蔡氏宰相的传奇故事，在遂昌当地广为流传，已有数百年历史。蔡相传说讲述明代遂昌人蔡某官至宰相，为官清廉，为民请命的故事。传说有多种版本，最著名的是“蔡相还乡”的故事。讲述蔡相年老还乡，两袖清风，只带回一箱书籍。当地豪绅怀疑箱中装有金银，向朝廷告发。皇帝派人搜查，结果只有书籍。皇帝感动，赐予“清官第一”匾额。另一传说是“蔡相救民”，讲述遂昌遭遇旱灾，蔡相上书请求减免赋税，开仓赈灾，救活无数百姓。还有“蔡相与汤显祖”的传说，讲述蔡相与遂昌知县汤显祖的交往，两人志同道合，一起关心民生，推广文化。蔡相传说塑造了一个清正廉洁、关心民瘼的清官形象，反映了民众对清官的敬仰和期盼。传说情节生动，语言朴实，在遂昌民间代代相传。2026年，蔡相传说被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/蔡相传说.webp', '2026-02-10 00:00:00.000000', '县级', '民间文学');
INSERT INTO `ich_project` VALUES (7023, '蔡和乱弹', '遂昌县', '蔡和乱弹是流传于浙江省遂昌县蔡和村的传统戏剧项目，是地方戏曲的一种，唱腔粗犷豪放，表演生动活泼，已有两百多年历史。蔡和乱弹属于乱弹声腔系统，融合了徽调、秦腔、婺剧等多种元素，形成了独特的风格。蔡和乱弹的唱腔高亢激越，节奏明快，有“二凡”“三五七”“芦花”等板式。伴奏乐器以锣、鼓、钹、唢呐为主，气氛热烈。表演风格粗犷豪放，动作夸张，富有乡土气息。传统剧目有《龙凤配》《珍珠塔》《三请梨花》等数十本，内容多为历史故事和民间传说。蔡和乱弹的独特之处在于“村班”演出，演员都是本村农民，农忙时耕作，农闲时演戏，自娱自乐。蔡和村有百年历史的戏班，世代传承，至今仍活跃在乡村舞台。每逢节庆庙会，蔡和乱弹戏班都会搭台演出，连演数日，吸引周边村民前来观看。蔡和乱弹是遂昌乡村文化的重要组成部分。2026年，蔡和乱弹被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/蔡和乱弹.webp', '2026-02-10 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (7024, '遂昌汤公菜烹饪技艺', '遂昌县', '遂昌汤公菜烹饪技艺是流传于浙江省遂昌县的传统烹饪技艺，相传与明代戏剧家汤显祖有关，以当地食材烹制，口味独特，已有四百多年历史。汤显祖曾任遂昌知县，在任期间关心民生，推广文化，相传还亲自指点当地厨师创制了一些菜肴，后人称为“汤公菜”。汤公菜选用当地食材，如土鸡、河鱼、山笋、香菇等，烹饪方法以炖、蒸、烧为主，口味清淡鲜美，原汁原味。代表菜品有“汤公鸡”“汤公鱼”“汤公笋”等。汤公鸡选用当地土鸡，用砂锅慢炖，加入香菇、笋片，汤清味鲜；汤公鱼选用瓯江溪鱼，清蒸后淋上葱油，鱼肉鲜嫩；汤公笋选用春笋，油焖后清香脆嫩。汤公菜的烹饪技艺讲究“原汁原味”，少用调料，突出食材本身的味道。汤公菜不仅是菜肴，更承载着遂昌人民对汤显祖的怀念。在遂昌，汤公菜是宴请贵客的佳肴。2026年，遂昌汤公菜烹饪技艺被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/遂昌汤公菜烹饪技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7025, '遂昌红茶制作技艺', '遂昌县', '遂昌红茶制作技艺是流传于浙江省遂昌县的传统制茶技艺，以本地茶青为原料，经萎凋、揉捻、发酵、干燥等工序制成红茶，已有上百年历史。遂昌地处浙南山区，气候温暖湿润，土壤富含有机质，是优质茶叶的理想产地。遂昌红茶选用当地群体种茶树，采摘一芽一叶或一芽二叶。制作技艺包括萎凋、揉捻、发酵、干燥等工序。萎凋将鲜叶摊放在萎凋槽中，使水分适度蒸发，叶片变软。揉捻用手工或揉捻机使茶叶卷曲成条，破坏细胞组织，促进发酵。发酵是红茶制作的关键，在温湿度适宜的发酵室中，茶叶发生氧化反应，叶色由绿变红，散发出特有的香气。干燥用炭火或烘干机终止发酵，固定品质。遂昌红茶的独特之处在于“松烟香”，在干燥环节用松柴熏焙，使茶叶吸附松烟的香气，形成独特的松烟香和桂圆汤味。遂昌红茶外形条索紧结，色泽乌润，汤色红艳明亮，香气松烟香浓郁，滋味醇厚鲜爽。', '/pictures/遂昌红茶制作技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7026, '遂昌传统糕点制作技艺', '遂昌县', '遂昌传统糕点制作技艺是流传于浙江省遂昌县的食品加工技艺，包括发糕、麻糍、玉米饼等多种糕点的制作方法，已有数百年历史。遂昌糕点品种繁多，各具特色。发糕用米粉发酵蒸制而成，松软香甜，是过年必备的食品。制作时，将米粉加水和酒糟发酵，倒入蒸笼蒸熟，表面撒上红枣、芝麻。麻糍用糯米蒸熟捣制而成，软糯香甜，是喜庆节日的食品。制作时，将糯米蒸熟，放入石臼捣烂，取出搓条切块，裹上黄豆粉。玉米饼用玉米粉烙制而成，香脆可口，是山区主食。制作时，将玉米粉加水和成面团，擀成薄饼，在铁锅上烙至两面金黄。遂昌糕点的独特之处在于“土法制作”，使用传统的石磨、石臼、蒸笼等工具，保持原汁原味。遂昌糕点不仅是食品，更是民俗文化的重要载体，过年吃发糕寓意“发家致富”，结婚吃麻糍寓意“甜甜蜜蜜”。遂昌传统糕点制作技艺代代相传。', '/pictures/遂昌传统糕点制作技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7027, '遂昌龙谷绿茶制作技艺', '遂昌县', '遂昌龙谷绿茶制作技艺是流传于浙江省遂昌县的传统制茶技艺，以高山茶青为原料，经杀青、揉捻、干燥等工序制成绿茶，是遂昌特色名茶，已有数百年历史。龙谷茶产于遂昌龙谷山，这里海拔八百多米，常年云雾缭绕，土壤富含有机质，是优质茶叶的理想产地。龙谷绿茶选用当地群体种茶树，清明前后采摘一芽一叶或一芽二叶。制作技艺包括摊青、杀青、揉捻、初烘、复烘、提香等工序，全部手工完成。摊青将鲜叶摊放数小时，使水分适度蒸发。杀青用铁锅高温炒制，破坏酶活性，固定茶叶品质。揉捻用手工揉搓，使茶叶卷曲成条，促进茶汁溢出。初烘用炭火低温烘干，去除大部分水分。复烘再次烘干，使茶叶足干。提香用高温短时烘焙，激发茶叶香气。龙谷绿茶外形条索紧结，色泽翠绿，汤色清澈明亮，香气清高持久，滋味鲜爽醇厚，叶底嫩绿匀整。遂昌龙谷绿茶制作技艺传承至今，保留了传统手工制茶的完整工艺。', '/pictures/遂昌龙谷绿茶制作技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7028, '遂昌苦褚豆腐制作技艺', '遂昌县', '遂昌苦褚豆腐制作技艺是流传于浙江省遂昌县的传统食品加工技艺，以苦褚树果实为原料，经浸泡、磨浆、凝固等工序制成，风味独特，已有数百年历史。苦褚树是一种野生乔木，其果实富含淀粉，可制作豆腐，因带有苦味而得名“苦褚豆腐”。制作技艺包括采果、晒果、去壳、浸泡、磨浆、过滤、沉淀、煮浆、凝固等工序。采果在秋季，采摘成熟的苦褚果实。晒果将果实晒干，便于保存和加工。去壳去除坚硬的外壳，得到果仁。浸泡将果仁放入清水中浸泡数天，每天换水，去除苦味。磨浆将浸泡好的果仁加水磨成浆。过滤用纱布将浆汁过滤，去除渣滓。沉淀将滤液静置，使淀粉沉淀，倒去上层清水。煮浆将沉淀的淀粉加水调匀，倒入锅中煮沸，不断搅拌。凝固将煮好的浆液倒入容器中，自然冷却凝固，即成苦褚豆腐。遂昌苦褚豆腐色泽灰褐，口感滑嫩，带有独特的苦味，清凉爽口。食用时可凉拌、煮汤、炒食，具有清热解毒的功效。', '/pictures/遂昌苦褚豆腐制作技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7029, '遂昌三叶青加工制作技艺', '遂昌县', '遂昌三叶青加工制作技艺是流传于浙江省遂昌县的传统医药技艺，三叶青是珍贵中药材，其加工炮制方法直接影响药效，已有数百年历史。三叶青又名“金线吊葫芦”，是葡萄科崖爬藤属植物，以块根入药，具有清热解毒、祛风化痰、活血止痛的功效。遂昌山区盛产野生三叶青，当地药农积累了丰富的采挖和加工经验。三叶青加工制作技艺包括采挖、清洗、分级、蒸制、干燥、切片等工序。采挖在秋季，选取生长三年以上的三叶青，此时药效最佳。清洗将采回的块根洗净，去除泥土和须根。分级按大小分类，便于分别加工。蒸制是最关键的环节，将三叶青放入蒸笼中蒸制，时间要恰到好处，既使药材熟透，又不破坏有效成分。蒸制后的三叶青颜色变深，药效增强。干燥将蒸好的三叶青晒干或烘干，使含水量达标。切片将干燥的三叶青切成薄片，便于煎煮和使用。加工好的三叶青片色泽乌黑，质地坚实，药香浓郁。遂昌三叶青加工制作技艺保证了药材的质量和药效。', '/pictures/遂昌三叶青加工制作技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (7030, '遂昌油焖笋制作技艺', '遂昌县', '遂昌油焖笋制作技艺是流传于浙江省遂昌县的传统烹饪技艺，以春笋为原料，经油焖加工，笋香浓郁，是当地特色菜肴，已有数百年历史。遂昌山区盛产竹笋，每年清明前后春笋大量上市，油焖笋成为家家户户的时令美味。制作技艺包括选笋、剥壳、切块、焯水、油焖、调味等工序。选笋要选鲜嫩肥壮的春笋，以黄泥拱为佳。剥壳去除老根和外壳，保留最嫩的笋肉。切块将笋肉切成滚刀块，大小均匀。焯水将笋块放入沸水中煮几分钟，去除涩味和草酸。油焖是最关键的环节，锅中放足量油，烧热后下笋块煸炒，炒至笋块表面微黄，加入酱油、白糖、黄酒、高汤，大火烧开转小火慢焖。焖至汤汁浓稠，笋块入味，最后大火收汁，淋上香油即可。遂昌油焖笋的独特之处在于“油多火候足”，使笋充分吸收油脂和调味料，口感脆嫩，味道鲜甜。遂昌油焖笋色泽红亮，笋香浓郁，咸中带甜，是春季餐桌上的美味佳肴。2026年，遂昌油焖笋制作技艺被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/遂昌油焖笋制作技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7031, '遂昌草编工艺技艺', '遂昌县', '遂昌草编工艺技艺是流传于浙江省遂昌县的传统手工艺，以稻草、麦秆等为原料，编织成各种生活用具和工艺品，已有数百年历史。遂昌山区盛产水稻、小麦，为草编提供了丰富的原材料。草编工艺的工序包括选料、浸泡、染色、编织、收口、修整等。选料要选色泽金黄、韧性好的稻草或麦秆。浸泡将草料放入清水中浸泡，使其变软，便于编织。染色用天然染料将草料染成各种颜色，用于编织彩色图案。编织是最关键的环节，有辫编、盘编、编结、编织等多种技法。遂昌草编的产品种类繁多，有生活用的草帽、草席、草鞋、草篮，有生产用的草绳、草包、草垫，有装饰用的草编画、草编动物、草编挂件。遂昌草编的独特之处在于“以草为线”，编织出各种精美的图案和造型。草编艺人手艺娴熟，能编出花鸟鱼虫、人物故事等复杂图案。遂昌草编不仅实用，而且美观，是山区农民的重要副业。2026年，遂昌草编工艺技艺被列入遂昌县非物质文化遗产代表性项目名录。', '/pictures/遂昌草编工艺技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7032, '遂昌养蜂制蜜技艺', '遂昌县', '遂昌养蜂制蜜技艺是流传于浙江省遂昌县的传统农业技艺，包括蜜蜂养殖、蜂群管理、蜂蜜采收加工等环节，产出优质蜂蜜，已有数百年历史。遂昌山区森林茂密，蜜源植物丰富，有油菜花、乌桕、荆条、五倍子等，为养蜂提供了优越条件。养蜂制蜜技艺包括蜂箱制作、蜂群繁育、蜂群管理、病虫害防治、蜂蜜采收、蜂蜜加工等环节。蜂箱用木板制作，要求严密、保温、通风。蜂群繁育在春季进行，选择优良蜂王，培育新蜂群。蜂群管理要定期检查蜂群，适时加脾、取蜜、防病。病虫害防治要预防蜂螨、巢虫等病害。蜂蜜采收在蜜源充足时进行，用摇蜜机将蜂蜜从蜂脾中分离出来。蜂蜜加工包括过滤、澄清、装瓶等工序，去除杂质，保持蜂蜜的纯度和品质。遂昌蜂蜜色泽金黄，香气浓郁，口感纯正。遂昌养蜂制蜜技艺世代相传，蜂农积累了丰富的经验，能根据蜜源植物的不同，生产出不同花种的蜂蜜，如油菜花蜜、乌桕蜜、野桂花蜜等，各具特色。', '/pictures/遂昌养蜂制蜜技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (7033, '遂昌山粉饺制作技艺', '遂昌县', '遂昌山粉饺制作技艺是流传于浙江省遂昌县的传统小吃技艺，以红薯淀粉为皮，包入肉馅，蒸煮而成，是当地特色小吃，已有数百年历史。山粉饺因以山芋（红薯）粉为原料而得名，是遂昌人喜爱的传统食品。制作技艺包括和面、制馅、包制、蒸煮等工序。和面将红薯淀粉用开水烫熟，揉成光滑的面团。山芋粉团要趁热揉制，凉了容易干裂。制馅选用猪前腿肉，手工剁成肉茸，加入葱姜、酱油、香油、笋丁、香菇丁等调料，搅拌上劲。包制是最关键的环节，取一小团面皮，捏成碗状，包入肉馅，收口捏紧，搓成圆形或饺子形。山芋粉皮韧性好，可以包出很薄的皮，蒸熟后晶莹剔透。蒸煮将包好的山粉饺放入蒸笼蒸熟，或入沸水煮熟。蒸熟的山粉饺皮薄馅大，晶莹剔透，隐约可见里面的馅料。遂昌山粉饺的独特之处在于“皮滑馅鲜”，山芋粉皮滑嫩有嚼劲，肉馅鲜美多汁。食用时可蘸醋、辣椒油，风味更佳。', '/pictures/遂昌山粉饺制作技艺.webp', '2026-02-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8001, '松阳高腔', '松阳县', '松阳高腔是流传于浙江省松阳县的传统戏曲剧种，是浙江省现存最古老的戏曲剧种之一，被誉为“戏曲界的活化石”，已有五百多年历史。松阳高腔属于高腔系统，以“一唱众和、锣鼓伴奏”为特点，唱腔高亢激越，表演粗犷古朴。松阳高腔的唱腔有“九腔十八调”之说，曲牌丰富，如《驻云飞》《江头金桂》《红纳袄》等数十种。演唱时，台上演员独唱，后台众人帮腔，只用锣鼓伴奏，不用丝竹，风格独特。表演形式粗犷古朴，动作夸张，富有乡土气息。传统剧目有《白兔记》《琵琶记》《荆钗记》等数十本，内容多为历史故事和民间传说。松阳高腔的演员都是当地农民，农忙时耕作，农闲时演戏，自娱自乐。松阳高腔对研究中国戏曲史、声腔演变具有重要价值。2006年，松阳高腔被列入国家级非物质文化遗产代表性项目名录。', '/pictures/松阳高腔.webp', '2006-05-01 00:00:00.000000', '国家级', '传统戏剧');
INSERT INTO `ich_project` VALUES (8002, '松阳县黄家大院木雕技艺', '松阳县', '松阳县黄家大院木雕技艺是流传于浙江省松阳县的传统美术类项目，以黄家大院的木雕装饰为代表，工艺精细，图案精美，已有两百多年历史。黄家大院是松阳著名的古民居，建于清代，其木雕装饰精美绝伦，被誉为“江南木雕博物馆”。黄家大院木雕的技艺包括选材、设计、打坯、细雕、修光、打磨、上漆等。选材要选质地细腻、纹理优美的木材，如樟木、银杏木、楠木等。设计要根据建筑构件的形状和位置，构思木雕的内容和构图。打坯用大凿凿出粗坯，确定作品的大体形状和层次。细雕用各种刀具精雕细刻，刻出人物五官、衣纹、花鸟羽毛、山水纹理等细节。黄家大院木雕的题材广泛，有历史故事如“三国演义”“西游记”，有吉祥图案如“龙凤呈祥”“福禄寿喜”，有花鸟鱼虫如“喜鹊登梅”“鲤鱼跳龙门”。修光用细刀和砂纸将表面打磨光滑。上漆用清漆涂饰，保护木料，增加美观。黄家大院木雕技艺精湛，代表了浙南地区木雕的最高水平。', '/pictures/松阳县黄家大院木雕技艺.webp', '2007-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (8003, '道教音乐（月宫调）', '松阳县', '月宫调是流传于浙江省松阳县的道教音乐的一种，用于道教仪式，曲调悠扬，具有宗教文化内涵，已有数百年历史。月宫调因曲调优美如月宫仙乐而得名，是松阳道教音乐的代表。月宫调的乐器组合以笛子、二胡、三弦、笙等丝竹乐器为主，配以锣、鼓、钹等打击乐器，音色清越悠扬。曲牌有《步虚声》《三宝赞》《焚香赞》《水龙吟》等数十首，曲调舒缓悠扬，庄严肃穆。月宫调的演奏形式有独奏、合奏、伴奏等，在道教斋醮仪式中，配合道士的诵经、步罡、礼拜等仪式活动。月宫调的独特之处在于“道俗结合”，既有道教音乐的庄严神秘，又有民间音乐的优美动听。月宫调的传承全靠口传心授，道士们代代相传，保持了古老的音乐风貌。月宫调不仅是道教仪式的重要组成部分，也是研究道教音乐和民间音乐的重要资料。2009年，月宫调被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/道教音乐（月宫调）.webp', '2009-01-01 00:00:00.000000', '省级', '传统音乐');
INSERT INTO `ich_project` VALUES (8004, '松阳银猴茶制作技艺', '松阳县', '松阳银猴茶制作技艺是流传于浙江省松阳县的传统制茶技艺，以当地茶青为原料，经杀青、揉捻、干燥等工序制成银猴茶，茶叶品质优良，已有数百年历史。松阳银猴茶因茶叶外形满披白毫，形似小猴而得名，是松阳特色名茶。制作技艺包括采摘、摊青、杀青、揉捻、初烘、复烘、提香等工序。采摘在清明前后，选取一芽一叶或一芽二叶。摊青将鲜叶摊放数小时，使水分适度蒸发。杀青用铁锅高温炒制，破坏酶活性，固定茶叶品质。揉捻用手工或揉捻机使茶叶卷曲成条，促进茶汁溢出。初烘用炭火低温烘干，去除大部分水分。复烘再次烘干，使茶叶足干。提香用高温短时烘焙，激发茶叶香气。松阳银猴茶的独特之处在于“手工炒制”，每一道工序都凭经验掌握，炒出的茶叶外形紧结，色泽翠绿，白毫显露，汤色清澈明亮，香气清高持久，滋味鲜爽醇厚。松阳银猴茶制作技艺传承至今，保留了传统手工制茶的完整工艺。', '/pictures/松阳银猴茶制作技艺.webp', '2023-11-27 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8005, '松阳白铁制品制作技艺', '松阳县', '松阳白铁制品制作技艺是流传于浙江省松阳县的传统技艺类项目，以白铁皮为原料，制作各种生活用具，工艺精细，已有上百年历史。白铁即镀锌铁皮，耐腐蚀，易加工，是制作生活用具的理想材料。白铁制品制作技艺包括设计、画线、裁剪、折边、咬口、焊接、打磨等工序。设计要根据用途构思产品的形状和尺寸。画线在铁皮上画出裁剪的线条。裁剪用铁皮剪按画线剪出坯料。折边用折边机将边缘折起，增加强度和美观。咬口是最关键的环节，将两片铁皮的边缘咬合在一起，形成牢固的连接，不用焊接也能密封。焊接对咬口处进行锡焊，增加牢固度和密封性。打磨用砂纸将焊接处打磨光滑。松阳白铁制品品种繁多，有水桶、水壶、漏斗、簸箕、烟囱等日常生活用品。白铁制品轻便耐用，不易生锈，深受群众喜爱。白铁制品制作技艺是传统手工业的代表，随着塑料制品的普及，会这门手艺的人越来越少。', '/pictures/松阳白铁制品制作技艺.webp', '2023-11-27 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8006, '松阳香肠制作技艺', '松阳县', '松阳香肠制作技艺是流传于浙江省松阳县的传统食品加工技艺，以猪肉为原料，经腌制、灌肠、晾晒等工序制成香肠，风味独特，已有上百年历史。松阳香肠是当地传统腊味，每年冬至前后制作，是过年必备的食品。制作技艺包括选肉、切肉、腌制、灌肠、扎节、晾晒等工序。选肉要选猪前后腿肉，肥瘦比例三七开，肉质紧实。切肉将肉切成小丁，大小均匀。腌制将肉丁加入盐、白糖、白酒、酱油、五香粉等调料，充分搅拌，腌制数小时，使肉入味。灌肠是最关键的环节，将腌制好的肉丁灌入洗净的猪小肠中，要灌得紧实，不能有空隙。灌好的香肠按一定长度扎成节，用针在肠衣上扎孔排气，防止晾晒时爆裂。晾晒将灌好的香肠挂在阴凉通风处晾晒，约半月左右，待香肠表面干燥，颜色变深即可。松阳香肠的独特之处在于“风干”，不经过烟熏，保持肉的原味。晾晒好的香肠色泽红亮，肉质紧实，咸甜适口，酒香浓郁。', '/pictures/松阳香肠制作技艺.webp', '2023-11-27 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8007, '松阳烤饼制作技艺', '松阳县', '松阳烤饼制作技艺是流传于浙江省松阳县的传统面食技艺，以面粉为原料，经发酵、成型、烤制等工序制成烤饼，香脆可口，是当地特色小吃，已有上百年历史。松阳烤饼又称“烧饼”，是松阳街头巷尾最常见的风味小吃。制作技艺包括和面、发酵、制馅、包饼、烤制等工序。和面用面粉加老面和水，揉成光滑的面团。发酵将和好的面团盖上湿布，静置数小时，使面团发酵膨胀。制馅选用猪五花肉，手工剁成肉末，加入梅干菜、葱、盐、酱油等调料拌匀。梅干菜是烤饼的灵魂，用当地产的九头芥腌制晒干而成，咸香浓郁。包饼将发酵好的面团擀成圆皮，包入馅料，收口捏紧，再擀成圆饼形，表面刷上糖水，撒上芝麻。烤制是最关键的环节，使用传统的烤炉。这是一种特制的陶土炉，中间烧炭火，炉壁温度极高。将饼坯贴在炉壁上，用炭火烤制两三分钟，待饼面鼓起、色泽金黄时取出。松阳烤饼外酥里嫩，馅料咸香，回味悠长。', '/pictures/松阳烤饼制作技艺.webp', '2023-11-27 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8008, '松阳雪茄卷制制作技艺', '松阳县', '松阳雪茄卷制制作技艺是流传于浙江省松阳县的传统技艺类项目，以烟叶为原料，经选叶、卷制、陈化等工序制成雪茄，已有上百年历史。松阳地处浙南山区，气候温暖湿润，适宜烟叶种植，历史上就是烟叶产区。雪茄卷制技艺包括选叶、去梗、发酵、配色、卷制、定型、陈化等工序。选叶要选优质烟叶，根据颜色、质地、大小分类。去梗去除烟叶主脉，保留叶片。发酵将烟叶堆放在适宜温湿度下发酵，去除杂气，增加香气。配色根据雪茄的颜色要求，将不同颜色的烟叶搭配使用。卷制是最关键的环节，用茄芯、茄套、茄衣三层烟叶手工卷制而成。茄芯用碎烟叶，决定雪茄的风味；茄套用整叶，包裹茄芯；茄衣用最优质的烟叶，包裹在最外层，要求完整无瑕。卷好的雪茄用模具定型，保持形状一致。陈化将定型后的雪茄在恒温恒湿环境中陈化数月，使风味更加醇和。松阳雪茄卷制技艺全凭手工，卷制师经验丰富，技艺娴熟。', '/pictures/松阳雪茄卷制制作技艺.webp', '2023-11-27 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8009, '太平船灯', '松阳县', '太平船灯是流传于浙江省松阳县的传统民俗类项目，在节庆期间制作和展示船形彩灯，祈求平安吉祥，已有数百年历史。太平船灯起源于古代渔民祈求平安的祭祀活动，后发展成节庆灯彩。船灯用竹篾扎制骨架，外糊彩纸或彩绸，造型为船只形状，有船身、船舱、船帆、船桨等部分，内点蜡烛或灯泡。船灯大小不一，小的长一两米，大的长五六米。制作工序包括设计、破篾、扎架、糊纸、彩绘、装饰等。设计要构思船灯的造型和尺寸。破篾将竹子劈成粗细均匀的篾条。扎架用篾条扎出船灯的基本骨架，要求结构牢固、比例准确。糊纸用糨糊将彩纸平整地糊在骨架上。彩绘用颜料在船灯上绘制图案，如龙、凤、花鸟等。装饰用流苏、彩带等点缀。太平船灯多在元宵节期间展示，人们在河边或池塘边放船灯，祈求一年平安顺利。船灯放入水中，烛光点点，随波逐流，寄托着人们对美好生活的期盼。', '/pictures/太平船灯.webp', '2023-11-27 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (8010, '松阳畲族婚嫁', '松阳县', '松阳畲族婚嫁是流传于浙江省松阳县畲族聚居区的传统民俗类项目，畲族传统婚庆仪式，包含说亲、定亲、迎亲、拜堂、对歌等环节，已有数百年历史。畲族婚嫁以“歌”贯穿始终，有“以歌为媒”“以歌代言”之说。说亲时，男方请媒人到女方家提亲，双方父母同意后，择日“定亲”。定亲时，男方送聘礼到女方家，女方设宴款待，双方对唱山歌表示祝贺。迎亲是婚礼的高潮，新郎带着迎亲队伍到新娘家接亲，要经过“拦门”“对歌”“讨酒”等关卡，才能接到新娘。新娘头戴凤冠，身着盛装，由兄长背出家门，哭别父母。到男方家后，举行拜堂仪式，一拜天地，二拜高堂，夫妻对拜，然后送入洞房。当晚要闹洞房，亲友们唱山歌、做游戏，祝福新人。婚后三天，新婚夫妇回门，拜见女方父母。松阳畲族婚嫁仪式隆重，歌声不断，充满了喜庆和欢乐。2023年，松阳畲族婚嫁被列入松阳县非物质文化遗产代表性项目名录。', '/pictures/松阳畲族婚嫁.webp', '2023-11-27 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (8011, '贤溪花棍舞', '松阳县', '贤溪花棍舞是流传于浙江省松阳县贤溪村的传统舞蹈类项目，舞者手持装饰彩带的花棍，边舞边击打身体各部位，节奏明快，已有两百多年历史。花棍用竹竿制成，长约一米，两端挖孔，孔中串有铜钱，棍身缠绕彩色绸带，舞动时哗哗作响。贤溪花棍舞起源于清代，最初是乞丐乞讨时的表演，后发展成节庆舞蹈。表演时，舞者手持花棍，随着锣鼓节奏，用花棍击打肩、背、腰、腿、脚等部位，同时做出跳跃、转身、蹲起等动作。击打部位不同，发出的声音也不同，形成独特的节奏。舞蹈动作有“雪花盖顶”“古树盘根”“鲤鱼翻背”“金鸡独立”等数十种。可以单人表演，也可以多人集体表演。集体表演时队形变化丰富，有“一字长蛇”“二龙戏珠”“八卦阵”等图案。贤溪花棍舞的独特之处在于“击打节奏”，花棍击打身体不同部位，发出有节奏的响声，与锣鼓声相和，气氛热烈。', '/pictures/贤溪花棍舞.webp', '2023-11-27 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (8012, '陈氏骨伤疗法', '松阳县', '陈氏骨伤疗法是流传于浙江省松阳县陈氏家族的传统医药类项目，以手法复位、夹板固定、中药外敷治疗骨伤，在当地享有盛誉，已有上百年历史。陈氏骨伤疗法由陈氏先祖创制于清末，代代相传，至今已传承五代。陈氏骨伤疗法秉承中医“筋骨并重、内外兼治”的理念，在治疗骨折、脱位、软组织损伤等方面积累了丰富的临床经验。其核心技术包括：摸法诊断伤情，通过触摸判断骨折类型和移位情况；手法复位，运用牵、拉、端、提等手法将骨折复位；夹板固定，用杉树皮制成夹板，根据伤情进行固定，既牢固又透气；中药外敷，使用祖传秘方研制的膏药，具有活血化瘀、消肿止痛、续筋接骨的功效；分期内服中药，根据骨折愈合的不同阶段，内服不同方剂的中药，促进愈合。陈氏骨伤疗法疗效显著，在松阳及周边地区享有盛誉。2023年，陈氏骨伤疗法被列入松阳县非物质文化遗产代表性项目名录。', '/pictures/陈氏骨伤疗法.webp', '2023-11-27 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (8013, '松阳歇力茶制作技艺', '松阳县', '松阳歇力茶制作技艺是流传于浙江省松阳县的传统医药类项目，以多种中草药配制熬制，具有解乏提神的功效，已有数百年历史。歇力茶是松阳山区农民的传统饮品，在农忙时节饮用，可消除疲劳，恢复体力。歇力茶的配方包括夏枯草、淡竹叶、薄荷、金银花、菊花、甘草等十多味中草药，具有清热解毒、消暑解乏的功效。制作技艺包括采药、洗药、切药、晒药、配药、熬煮等工序。采药在夏秋季节，采摘新鲜的中草药。洗药将采回的药材洗净，去除泥土和杂质。切药将长茎药材切段，便于熬煮。晒药将切好的药材晒干，便于保存。配药按祖传秘方将各味药材配比好。熬煮将配好的药材放入大锅中，加水熬煮，先用大火烧开，再用小火慢熬，使药效充分溶解。煮好的歇力茶滤去药渣，可热饮也可冷饮。松阳歇力茶色泽金黄，清凉爽口，是山区农民夏秋季的日常饮品。', '/pictures/松阳歇力茶制作技艺.webp', '2023-11-27 00:00:00.000000', '县级', '传统医药');
INSERT INTO `ich_project` VALUES (8014, '松阳地方小戏', '松阳县', '松阳地方小戏是流传于浙江省松阳县的传统戏剧类项目，以当地方言表演的小型戏曲，内容多为生活故事，生动活泼，已有数百年历史。松阳地方小戏起源于民间歌舞和说唱艺术，融合了当地民歌、小调、舞蹈等元素，形成了独特的艺术风格。表演形式简单灵活，三五人即可成戏，道具简陋，多在祠堂、晒谷场演出。唱腔以当地山歌小调为基础，有“花鼓调”“采茶调”“秧歌调”等十多种曲牌，旋律优美动听。剧目多为生活小戏，如《打猪草》《捡螺蛳》《卖花线》《补缸》等，表现农民的日常生活和爱情故事，语言幽默风趣，表演生动活泼。松阳地方小戏的演员都是当地农民，农忙时劳作，农闲时排练演出，自娱自乐。每逢节庆庙会，戏班都会搭台演出，连演数日，深受群众欢迎。松阳地方小戏是松阳乡村文化的重要组成部分，反映了当地人民的生活和情感。', '/pictures/松阳地方小戏.webp', '2023-11-27 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (8015, '松阳黄蜡石赏石艺术', '松阳县', '松阳黄蜡石赏石艺术是流传于浙江省松阳县的传统美术类项目，以黄蜡石为观赏对象，讲究造型、质地、色泽，体现赏石文化，已有数百年历史。黄蜡石是一种石英岩，因石质细腻温润，色泽金黄如蜡而得名。松阳是黄蜡石的重要产地，所产黄蜡石质地优良，色彩丰富，有金黄、蜡黄、鸡油黄等色。赏石艺术包括采石、选石、配座、命名、陈列等环节。采石要在河滩、山野寻找形态奇特的黄蜡石。选石要根据“瘦、漏、透、皱”的传统赏石标准，结合黄蜡石的特点，讲究造型奇特、质地细腻、色泽纯正。配座根据石头的形状，配以合适的底座，使石头稳定，突出主题。命名根据石头的形态和意境，赋予富有诗意的名字，如“金鸡报晓”“仙山琼阁”“卧虎藏龙”等。陈列将配好座的赏石摆放在合适的位置，供人欣赏。松阳黄蜡石赏石艺术不仅是对自然奇石的欣赏，更是对自然美的发现和创造。', '/pictures/松阳黄蜡石赏石艺术.webp', '2023-11-27 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (8016, '松阳端午茶', '松阳县', '松阳端午茶是流传于浙江省松阳县的传统医药类项目，端午节期间采集多种中草药配制而成，具有清热解毒的功效，已有数百年历史。端午茶是松阳民间的传统饮品，相传起源于唐代，盛于宋代。每年端午节，人们上山采药，制作端午茶，既可饮用，又可防病治病。端午茶的配方因地因人而异，但基本药材包括艾草、菖蒲、金银花、夏枯草、鱼腥草、车前草等数十味。这些药材大多具有清热解毒、祛风除湿的功效。制作技艺包括采药、洗药、切药、晒药、配药、储存等工序。采药在端午节前后，此时草药药效最佳。洗药将采回的药材洗净，去除泥土和杂质。切药将长茎药材切段。晒药将切好的药材晒干，便于保存。配药按传统配方将各味药材配比好。储存将配好的端午茶装入布袋或陶罐中，置于干燥处保存。饮用时，取适量端午茶用开水冲泡，或煮沸后饮用。松阳端午茶色泽金黄，清香爽口，是夏季解暑佳品。', '/pictures/松阳端午茶.webp', '2012-01-01 00:00:00.000000', '省级', '传统医药');
INSERT INTO `ich_project` VALUES (8017, '松阳豺虎画', '松阳县', '松阳豺虎画是流传于浙江省松阳县的传统美术类项目，以豺和虎为题材的民间绘画，用于驱邪避灾，已有数百年历史。豺虎画起源于古代民间信仰，认为豺和虎能驱邪避灾，保护家宅平安。每逢端午，人们将豺虎画张贴在门上，以驱除瘟疫和邪祟。豺虎画的构图简洁明快，色彩鲜艳，形象夸张。豺通常画成黄色或棕色，张牙舞爪，凶悍威猛；虎通常画成黄色带黑纹，额上有“王”字，威风凛凛。豺虎多画在一起，或对峙，或追逐，充满动感。豺虎画的绘制技艺包括勾线、填色、渲染等，全部手工绘制。颜料多用矿物质颜料，色彩鲜艳，经久不褪。豺虎画不仅是驱邪避灾的符咒，也是民间美术的佳作。其造型生动，色彩艳丽，富有装饰性。松阳豺虎画传承至今，成为当地端午节特有的民俗文化。2012年，松阳豺虎画被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/松阳豺虎画.webp', '2012-01-01 00:00:00.000000', '省级', '传统美术');
INSERT INTO `ich_project` VALUES (8018, '松阳竹编', '松阳县', '松阳竹编是流传于浙江省松阳县的传统技艺类项目，以竹篾编织各种生活用具和工艺品，技艺精湛，已有数百年历史。松阳地处山区，盛产毛竹，为竹编提供了丰富的原材料。竹编技艺的工序包括选竹、砍竹、破篾、匀篾、煮篾、染色、编织、收口、修整等。选竹要选生长三年以上的毛竹，竹身粗直，无虫蛀。破篾将竹子剖成粗细均匀的竹篾，最细的篾条可薄如纸张。匀篾用匀刀将竹篾刮匀刮薄，使宽窄厚度一致。煮篾将竹篾放入沸水中煮，去除糖分，防止虫蛀。染色用天然染料将竹篾染成各种颜色。编织是最关键的环节，有十字编、人字编、六角编、螺旋编等数十种编织技法，可编出各种图案和文字。松阳竹编的产品种类繁多，有生产用的竹篮、竹筐、竹篓，有生活用的竹席、竹枕、竹椅，有装饰用的竹画、竹屏风、竹灯笼。松阳竹编以其工艺精细、造型美观、经久耐用而著称。2012年，松阳竹编被列入丽水市非物质文化遗产代表性项目名录。', '/pictures/松阳竹编.webp', '2012-01-01 00:00:00.000000', '市级', NULL);
INSERT INTO `ich_project` VALUES (8019, '松阳石雕', '松阳县', '松阳石雕是流传于浙江省松阳县的传统美术类项目，以本地石材为原料，雕刻人物、花鸟、山水等题材，工艺精细，已有数百年历史。松阳地处山区，石材资源丰富，尤其以青石、红石闻名，石质细腻，适合雕刻。石雕技艺的工序包括选材、设计、打坯、细雕、修光、打磨等。选材要选质地均匀、无裂纹的石料。设计要根据石料的形状和纹理，构思作品的内容和构图，在石料上画出轮廓。打坯用大锤和凿子打出粗坯，确定作品的大体形状和层次。细雕用各种刀具精雕细刻，刻出人物五官、衣纹、花鸟羽毛、山水纹理等细节。修光用细凿和砂纸将表面打磨光滑，去除刀痕。打磨用磨石将作品表面磨光，使石质温润如玉。松阳石雕的题材广泛，有宗教人物如观音、罗汉，有历史人物如关公、岳飞，有吉祥图案如龙凤呈祥、福禄寿喜，有建筑构件如石狮、柱础、门墩。松阳石雕造型生动，工艺精湛，是松阳传统工艺的代表。', '/pictures/松阳石雕.webp', '2012-01-01 00:00:00.000000', '市级', '传统美术');
INSERT INTO `ich_project` VALUES (8020, '松阳麦秆扇制作技艺', '松阳县', '松阳麦秆扇制作技艺是流传于浙江省松阳县的传统技艺类项目，以麦秆为原料，编织成扇子，工艺精细，造型美观，已有数百年历史。麦秆扇是松阳农村妇女的传统手艺，用小麦收割后的麦秆编织而成，既实用又美观。制作技艺包括选料、浸泡、染色、编织、镶边、装柄等工序。选料要选色泽金黄、粗细均匀的麦秆，以小麦穗下第一节为佳。浸泡将麦秆放入清水中浸泡，使其变软，便于编织。染色用天然染料将麦秆染成各种颜色，用于编织彩色图案。编织是最关键的环节，有平编、辫编、盘编等多种技法。松阳麦秆扇的编织图案丰富多样，有几何纹、花鸟纹、文字纹等。扇面编好后，要进行镶边，用布条或藤条将扇边包好，既美观又耐用。最后装上扇柄，可用竹片或木片制作。松阳麦秆扇轻便实用，扇风清凉，还有淡淡的麦秆清香。麦秆扇不仅是纳凉工具，也是精美的工艺品。', '/pictures/松阳麦秆扇制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8021, '松阳红糖制作技艺', '松阳县', '松阳红糖制作技艺是流传于浙江省松阳县的传统制糖技艺，以甘蔗为原料，经压榨、熬制、结晶等工序制成红糖，已有上百年历史。松阳气候温暖，土壤肥沃，适宜甘蔗种植。每年冬至前后，甘蔗成熟，是榨糖的最佳时节。红糖制作技艺包括砍蔗、清洗、压榨、过滤、熬制、打砂、成型等工序。砍蔗要选成熟度适中的甘蔗，去叶洗净。压榨用石碾或木榨机压出甘蔗汁，收集到缸中。过滤去除甘蔗汁中的杂质，得到纯净的蔗汁。熬制是最关键的环节，将蔗汁倒入大铁锅中，用柴火熬煮，不断搅拌，使水分蒸发，糖浆逐渐浓稠。熬至糖浆起大泡时，加入少量石灰中和酸度，继续熬至起小泡，糖浆呈琥珀色。打砂是将熬好的糖浆倒入木槽，快速搅拌，使其结晶成细砂状。成型将打砂后的红糖倒入模具，压实晾凉，切成块状。松阳红糖色泽红褐，香甜醇厚，保留了甘蔗的天然风味。', '/pictures/松阳红糖制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8022, '松阳豆腐娘制作技艺', '松阳县', '松阳豆腐娘制作技艺是流传于浙江省松阳县的传统食品加工技艺，以黄豆为原料，制作豆腐娘（豆腐花）的传统工艺，已有数百年历史。豆腐娘是松阳人对豆腐花的称呼，是当地传统早餐食品。制作技艺包括选豆、浸豆、磨浆、煮浆、点卤、成型等工序。选豆要选颗粒饱满、无虫蛀的黄豆，以本地小黄豆为佳。浸豆将黄豆淘洗干净，用清水浸泡过夜，使豆粒充分吸水膨胀。磨浆将浸泡好的黄豆加水磨成豆浆，用石磨磨出的豆浆最香浓。煮浆将磨好的豆浆倒入锅中煮沸，边煮边撇去浮沫，煮沸后继续煮几分钟，使豆浆熟透。点卤是最关键的环节，将盐卤或石膏水慢慢倒入热豆浆中，轻轻搅拌，使蛋白质凝固，形成豆腐花。点卤的火候决定豆腐花的老嫩，全凭经验掌握。成型将点好的豆腐花舀入铺有纱布的模具中，压去部分水分，即成豆腐娘。松阳豆腐娘洁白细嫩，豆香浓郁，可咸可甜。', '/pictures/松阳豆腐娘制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (8023, '松阳灰汁糕制作技艺', '松阳县', '松阳灰汁糕制作技艺是流传于浙江省松阳县的传统食品加工技艺，以米粉和灰碱水为原料，蒸制成糕，口感软糯，是当地传统食品，已有数百年历史。灰汁糕因用草木灰水制作而得名，色泽淡黄，清香扑鼻。制作技艺包括烧灰、浸米、磨浆、发酵、蒸制等工序。烧灰选用山中的灌木和杂草烧成灰，用开水冲泡过滤，得到灰碱水。这种灰碱水呈碱性，能使米糕产生独特的清香。浸米将籼米淘洗干净，用灰碱水浸泡过夜，使米粒充分吸收灰碱水。磨浆将浸泡好的米加水磨成米浆，要求米浆细腻无颗粒。发酵是灰汁糕制作的关键，在米浆中加入老面或酒糟，放置温暖处发酵数小时，使米浆微微发酸，产生气泡。发酵好的米浆加入白糖或红糖调味，搅拌均匀。蒸制时将米浆倒入铺有湿布的蒸笼中，摊平，用旺火蒸熟。蒸好的灰汁糕厚约两三厘米，表面光滑，色泽淡黄。灰汁糕可以直接食用，也可以切片煎至两面金黄，外酥里嫩。', '/pictures/松阳灰汁糕制作技艺.webp', '2015-01-01 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9001, '畲族民歌', '景宁县', '畲族民歌是流传于浙江省景宁畲族自治县及周边畲族聚居区的传统音乐，是畲族人民在长期生产生活中创造的口头文学，以“以歌代言”著称，内容涉及历史、传说、婚恋、劳动等，已有上千年历史。畲族民歌的曲调优美动听，节奏自由灵活，有独唱、对唱、齐唱等多种形式。歌词多为七言四句，讲究押韵，比喻生动，情感真挚。内容十分丰富，有历史歌如《高皇歌》讲述畲族始祖盘瓠的传说，长达三百多句，是畲族的史诗；有劳动歌如《采茶歌》《砍柴歌》，表现了畲民劳动的艰辛和快乐；有情歌如《相思歌》《送郎歌》，表达了青年男女的爱慕之情；有礼俗歌如《敬酒歌》《哭嫁歌》，在婚丧嫁娶等场合演唱。对唱是畲族民歌最具特色的形式，男女青年在山间地头一唱一和，互相试探，表达爱慕之情。畲族民歌没有固定的曲谱，全凭口头传承，即兴编唱。2008年，畲族民歌被列入国家级非物质文化遗产代表性项目名录。', '/pictures/畲族民歌.webp', '2008-06-01 00:00:00.000000', '国家级', '传统音乐');
INSERT INTO `ich_project` VALUES (9002, '畲族医药（痧症疗法）', '景宁县', '畲族医药（痧症疗法）是流传于浙江省景宁畲族自治县的传统医药，是畲族人民在特定自然环境和历史条件下创造的民族医药，其中“痧症疗法”针对发痧（中暑）等病症，具有独特的诊断、治疗方法和用药经验，已有数百年历史。畲族医药的理论基础是“六神”学说，将人体分为心、肝、肺、脾、肾、胆六脏，认为疾病是六神失调所致。痧症疗法是畲族医药中最具特色的部分，专门治疗各种痧症。畲医将痧症分为热痧、寒痧、绞肠痧等数十种，根据不同的症状采用不同的治疗方法。治疗方法包括刮痧、放血、揪痧、药浴、内服草药等。刮痧用铜钱或瓷匙蘸植物油，在患者背部、颈部刮出痧痕；放血用三棱针刺破特定穴位，放出少量血液；揪痧用手指揪扯皮肤，使局部充血；药浴用多种草药煎水洗澡；内服草药根据不同的痧症，使用不同的方剂。畲族医药痧症疗法疗效显著，在畲族地区广泛流传。2008年，畲族医药（痧症疗法）被列入国家级非物质文化遗产代表性项目名录。', '/pictures/畲族医药（痧症疗法）.webp', '2008-06-01 00:00:00.000000', '国家级', '传统医药');
INSERT INTO `ich_project` VALUES (9003, '畲族三月三', '景宁县', '畲族三月三是流传于浙江省景宁畲族自治县及周边畲族聚居区的传统节日，是畲族最为重要的传统节日，每逢农历三月初三，举办歌会，吃乌米饭，祭祀祖先，进行各种民俗活动，已有上千年历史。畲族三月三起源于唐代，相传畲族英雄雷万兴率众起义，被围困山中，靠乌稔果充饥，最终取得胜利。为纪念此事，畲民每年三月三吃乌米饭，遂成节日。三月三的主要活动包括祭祖、歌会、吃乌米饭等。祭祖在祠堂举行，全族聚集，献上三牲五果，焚香点烛，祭祀祖先。歌会是三月三的高潮，男女老少身着盛装，聚集在山坡上，对唱山歌，一唱一和，通宵达旦。歌会上还有畲族舞蹈、武术表演等。吃乌米饭是三月三的重要习俗，乌米饭用乌稔树叶汁浸泡糯米蒸制而成，色泽乌黑，清香扑鼻。三月三期间还有赶墟、舞龙、舞狮等民俗活动。2008年，畲族三月三被列入国家级非物质文化遗产代表性项目名录。', '/pictures/畲族三月三.webp', '2008-06-01 00:00:00.000000', '国家级', '民俗');
INSERT INTO `ich_project` VALUES (9004, '畲族婚俗', '景宁县', '畲族婚俗是流传于浙江省景宁畲族自治县及周边畲族聚居区的传统民俗，是畲族独具特色的婚庆仪式，整个过程包括“借镬”“杀鸡”“劝酒”“对歌”等一系列环节，热闹喜庆，民族风情浓郁，已有数百年历史。畲族婚俗以“歌”贯穿始终，有“以歌为媒”“以歌代言”之说。说亲时，男方请媒人到女方家提亲，双方父母同意后，择日“定亲”。定亲时，男方送聘礼到女方家，女方设宴款待，双方对唱山歌表示祝贺。迎亲是婚礼的高潮，新郎带着迎亲队伍到新娘家接亲，要经过“拦门”“对歌”“讨酒”等关卡，才能接到新娘。新娘头戴凤冠，身着盛装，由兄长背出家门，哭别父母。到男方家后，举行拜堂仪式，一拜天地，二拜高堂，夫妻对拜，然后送入洞房。当晚要闹洞房，亲友们唱山歌、做游戏，祝福新人。婚后三天，新婚夫妇回门，拜见女方父母。畲族婚俗仪式隆重，歌声不断，充满了喜庆和欢乐。2014年，畲族婚俗被列入国家级非物质文化遗产代表性项目名录。', '/pictures/畲族婚俗.webp', '2014-12-01 00:00:00.000000', '国家级', '民俗');
INSERT INTO `ich_project` VALUES (9005, '畲族彩带编织技艺', '景宁县', '畲族彩带编织技艺是流传于浙江省景宁畲族自治县及周边畲族聚居区的传统手工技艺，是畲族妇女世代传承的技艺，彩带不仅是日常服饰的装饰品，更是青年男女的定情信物，其图案纹样蕴含着丰富的民族文化内涵，已有数百年历史。畲族彩带用彩色丝线或棉线编织而成，宽约一至三寸，长约数尺，两端有流苏。彩带的图案丰富多样，有几何纹、文字纹、花鸟纹等，每种图案都有特定的寓意，如“蝴蝶花”象征爱情，“铜钱花”象征财富，“万字纹”象征吉祥。彩带编织技艺的工序包括选线、染色、整经、编织等。选线要选质量好的丝线或棉线。染色用植物染料将白线染成各种颜色。整经将经线按一定顺序排列在织机上。编织是最关键的环节，用纬线在经线中穿梭编织，织出各种图案。编织技法有平纹、斜纹、提花等，技艺高超的织手可以织出复杂的文字和图案。畲族彩带用途广泛，可作腰带、围裙带、背包带，也可作定情信物。2021年，畲族彩带编织技艺被列入国家级非物质文化遗产代表性项目名录。', '/pictures/畲族彩带编织技艺.webp', '2021-06-01 00:00:00.000000', '国家级', NULL);
INSERT INTO `ich_project` VALUES (9006, '畲族婚俗', '景宁县', '畲族婚俗是流传于浙江省景宁畲族自治县的传统民俗，包含“借镬”“杀鸡”“劝酒”“对歌”等环节，热闹喜庆，是畲族独具特色的婚庆仪式，已有数百年历史。畲族婚俗以“歌”贯穿始终，有“以歌为媒”之说。说亲时，男方请媒人到女方家提亲，双方父母同意后择日定亲。定亲时，男方送聘礼到女方家，双方对唱山歌表示祝贺。迎亲是婚礼的高潮，新郎带着迎亲队伍到新娘家接亲，要经过“拦门”“对歌”“讨酒”等关卡。新娘头戴凤冠，身着盛装，由兄长背出家门，哭别父母。到男方家后举行拜堂仪式，一拜天地，二拜高堂，夫妻对拜，然后送入洞房。当晚闹洞房，亲友们唱山歌、做游戏，祝福新人。婚后三天，新婚夫妇回门。畲族婚俗仪式隆重，歌声不断，充满了喜庆和欢乐。2007年，畲族婚俗被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/畲族婚俗.webp', '2007-01-01 00:00:00.000000', '省级', '民俗');
INSERT INTO `ich_project` VALUES (9007, '畲族彩带编织技艺', '景宁县', '畲族彩带编织技艺是流传于浙江省景宁畲族自治县的传统手工技艺，是畲族妇女世代传承的技艺，彩带图案纹样蕴含丰富民族文化内涵，已有数百年历史。畲族彩带用彩色丝线或棉线编织而成，宽约一至三寸，长约数尺，两端有流苏。彩带的图案丰富多样，有几何纹、文字纹、花鸟纹等，每种图案都有特定的寓意，如“蝴蝶花”象征爱情，“铜钱花”象征财富。彩带编织技艺包括选线、染色、整经、编织等工序。选线要选质量好的丝线或棉线。染色用植物染料将白线染成各种颜色。整经将经线按一定顺序排列在织机上。编织是最关键的环节，用纬线在经线中穿梭编织，织出各种图案。编织技法有平纹、斜纹、提花等，技艺高超的织手可以织出复杂的文字和图案。畲族彩带用途广泛，可作腰带、围裙带、背包带，也可作定情信物。2007年，畲族彩带编织技艺被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/畲族彩带编织技艺.webp', '2007-01-01 00:00:00.000000', '省级', NULL);
INSERT INTO `ich_project` VALUES (9008, '菇民防身术', '景宁县', '菇民防身术是流传于浙江省景宁畲族自治县的传统体育项目，是菇民在长期深山劳作中创编的传统体育项目，包含拳术和器械套路，用于防身健体，已有数百年历史。景宁菇民每年秋冬季节进入深山老林培育香菇，要在山中居住数月之久，常遇野兽出没、歹人骚扰，于是创编了这套实用的防身功夫。菇民防身术包括拳术和器械两部分，拳术有“扁担拳”“柴刀拳”“挑担拳”等，器械有柴刀、扁担、木棍等日常用具。其特点是动作朴实、实用性强，讲究一招制敌，不追求花哨。如“扁担拳”以挑香菇的扁担为武器，有挑、压、扫、劈等招式；“柴刀术”以砍柴的柴刀为武器，有砍、削、挡、刺等动作。菇民防身术还包含一些养生功法，如“八段锦”“易筋经”等，用于调理身体，抵御山中湿寒。菇民防身术不仅是防身技艺，更是菇民艰苦生活的写照。2012年，菇民防身术被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/菇民防身术.webp', '2012-01-01 00:00:00.000000', '省级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (9009, '马仙信俗', '景宁县', '马仙信俗是流传于浙江省景宁畲族自治县的传统民俗类项目，祭祀马仙娘娘的传统信俗，包含祭祀、巡游等活动，已有数百年历史。马仙娘娘是浙南地区信奉的民间女神，传说她生前孝亲爱民，死后显灵护佑百姓。景宁是马仙信仰的重要传播地，每年农历七月十五马仙诞辰，各地都要举行祭祀活动。祭祀仪式在马仙庙举行，信众献上三牲五果，焚香点烛，跪拜祈祷，祈求平安吉祥。巡游是仪式的高潮，信众抬着马仙娘娘的神像巡游村庄，沿途居民焚香礼拜，祈求保佑。巡游队伍中还有舞龙、舞狮、钢叉舞等民间表演，热闹非凡。演戏请来戏班连演数日，剧目多为地方戏曲，内容多为神话传说和民间故事。马仙信俗集祭祀、娱乐于一体，是当地重要的民俗活动。2016年，马仙信俗被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/马仙信俗.webp', '2016-01-01 00:00:00.000000', '省级', '民俗');
INSERT INTO `ich_project` VALUES (9010, '畲族三月三', '景宁县', '畲族三月三是流传于浙江省景宁畲族自治县的传统节日，是畲族最重要的传统节日，举办歌会，吃乌米饭，祭祀祖先，已有上千年历史。畲族三月三起源于唐代，相传畲族英雄雷万兴率众起义，被围困山中，靠乌稔果充饥，最终取得胜利。为纪念此事，畲民每年三月三吃乌米饭，遂成节日。三月三的主要活动包括祭祖、歌会、吃乌米饭等。祭祖在祠堂举行，全族聚集，献上三牲五果，焚香点烛，祭祀祖先。歌会是三月三的高潮，男女老少身着盛装，聚集在山坡上，对唱山歌，一唱一和，通宵达旦。歌会上还有畲族舞蹈、武术表演等。吃乌米饭是三月三的重要习俗，乌米饭用乌稔树叶汁浸泡糯米蒸制而成，色泽乌黑，清香扑鼻。三月三期间还有赶墟、舞龙、舞狮等民俗活动。2007年，畲族三月三被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/畲族三月三.webp', '2007-01-01 00:00:00.000000', '省级', '民俗');
INSERT INTO `ich_project` VALUES (9011, '抢猪节', '景宁县', '抢猪节是流传于浙江省景宁畲族自治县的传统民俗活动，在特定节日举行抢猪比赛，热闹喜庆，已有数百年历史。抢猪节是景宁大漈乡的传统节日，每年农历十月十五举行。关于抢猪节的由来，有说是为了纪念一位为民除害的英雄，有说是为了庆祝丰收。节日当天，各村选出最强壮的男子，组成抢猪队。抢猪用的猪是经过精心饲养的，每头重达数百斤。抢猪比赛开始，各队争相抢夺猪只，你争我夺，场面激烈。抢到猪的队将猪扛回本村，全村欢庆，杀猪设宴，共同分享。抢猪节期间还有祭祖、演戏、赶墟等活动，热闹非凡。抢猪节不仅是对力量的考验，更是各村凝聚力和荣誉感的体现。抢猪节反映了畲族人民尚武、团结的民族精神。2009年，抢猪节被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/抢猪节.webp', '2009-01-01 00:00:00.000000', '省级', '民俗');
INSERT INTO `ich_project` VALUES (9012, '惠明茶手工制作技艺', '景宁县', '惠明茶手工制作技艺是流传于浙江省景宁畲族自治县的传统技艺类项目，以惠明寺周边茶青为原料，经杀青、揉捻、干燥等工序制成惠明茶，已有数百年历史。惠明茶产于景宁敕木山惠明寺周边，因寺得名，是浙江名茶之一。惠明茶选用当地群体种茶树，清明前后采摘一芽一叶或一芽二叶。制作技艺包括摊青、杀青、揉捻、初烘、复烘、提香等工序，全部手工完成。摊青将鲜叶摊放数小时，使水分适度蒸发。杀青用铁锅高温炒制，破坏酶活性，固定茶叶品质。揉捻用手工揉搓，使茶叶卷曲成条，促进茶汁溢出。初烘用炭火低温烘干，去除大部分水分。复烘再次烘干，使茶叶足干。提香用高温短时烘焙，激发茶叶香气。惠明茶外形条索紧结，色泽翠绿，白毫显露，汤色清澈明亮，香气清高持久，滋味鲜爽醇厚，有“兰花清香”之誉。2012年，惠明茶手工制作技艺被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/惠明茶手工制作技艺.webp', '2012-01-01 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (9013, '传师学师', '景宁县', '传师学师是流传于浙江省景宁畲族自治县的传统舞蹈，用于祭祀和传授师承的舞蹈仪式，动作庄重肃穆，具有深厚的宗教文化内涵，已有数百年历史。传师学师是畲族巫师（师公）的传承仪式，老巫师将法术传授给新巫师时举行的仪式。仪式包括请神、传法、学法等环节，持续数日。传师学师舞蹈是仪式的重要组成部分，由老巫师带领新巫师，在锣鼓和经咒声中舞蹈。舞蹈动作模仿神仙、鬼怪、动物等，动作夸张，富有神秘色彩。舞蹈队形变化丰富，有围圈、穿插、列队等。传师学师舞蹈不仅有艺术价值，更是研究畲族宗教文化的重要资料。2006年，传师学师被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/传师学师.webp', '2006-06-10 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (9014, '做功德', '景宁县', '做功德是流传于浙江省景宁畲族自治县的传统民俗活动，为逝者所做的功德仪式，包含唱祭歌、做法事等环节，体现畲族丧葬文化，已有数百年历史。做功德是畲族丧葬习俗中的重要仪式，认为通过做功德可以超度亡魂，使其早日投胎。仪式由巫师主持，包括请神、开路、超度、送亡等环节，持续一至三日。期间要唱祭歌，内容多为歌颂死者生平、劝人行善、超度亡魂等。祭歌用畲语演唱，曲调悲凉，感人至深。做法事时，巫师身穿法衣，手持法器，在锣鼓声中表演各种法术，如破地狱、过奈何桥等。做功德期间，亲友前来吊唁，送葬队伍浩浩荡荡。做功德不仅是对死者的追思，也是对生者的安慰。2006年，做功德被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/做功德.webp', '2006-06-10 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (9015, '金田鱼灯', '景宁县', '金田鱼灯是流传于浙江省景宁畲族自治县金田村的传统舞蹈，舞者手持扎制的鱼形彩灯进行表演，模仿鱼类生活习性，动作优美，已有数百年历史。金田鱼灯起源于清代，最初是渔民祈求丰收的祭祀活动，后发展成节庆表演。鱼灯用竹篾扎制骨架，外糊彩纸或彩绸，绘有鱼鳞、鱼眼、鱼鳍，内点蜡烛，形态逼真。鱼灯种类有鲤鱼、鲢鱼、草鱼、青鱼等十多种。表演时，由一人持龙珠引路，数十人手持各色鱼灯，在锣鼓声中做出“鱼戏水”“鱼抢食”“鱼产卵”“鱼跃龙门”等动作，模拟鱼类的生活习性。队形变化丰富，有“单龙入海”“双凤朝阳”“八卦阵”等图案。夜间表演时，鱼灯内烛光闪烁，犹如鱼群在水中游动，美不胜收。2006年，金田鱼灯被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/金田鱼灯.webp', '2006-06-10 00:00:00.000000', '县级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (9016, '畲族民歌', '景宁县', '畲族民歌是流传于浙江省景宁畲族自治县的畲族传统音乐，以畲语演唱，内容涉及历史、传说、婚恋、劳动等，曲调朴实动听，是畲族文化的瑰宝。畲族民歌的曲调优美动听，节奏自由灵活，有独唱、对唱、齐唱等多种形式。歌词多为七言四句，讲究押韵，比喻生动，情感真挚。内容十分丰富，有历史歌如《高皇歌》讲述畲族始祖盘瓠的传说；有劳动歌如《采茶歌》《砍柴歌》；有情歌如《相思歌》《送郎歌》；有礼俗歌如《敬酒歌》《哭嫁歌》。对唱是畲族民歌最具特色的形式，男女青年在山间地头一唱一和，互相试探，表达爱慕之情。畲族民歌没有固定的曲谱，全凭口头传承，即兴编唱。2006年，畲族民歌被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/畲族民歌.webp', '2006-06-10 00:00:00.000000', '县级', '传统音乐');
INSERT INTO `ich_project` VALUES (9017, '汉族民歌', '景宁县', '汉族民歌是流传于浙江省景宁畲族自治县汉族聚居区的传统音乐，内容涉及劳动、爱情、生活等，是汉族民间文化的重要组成部分。景宁汉族民歌受畲族民歌影响，形成了独特的风格。民歌的曲调优美动听，节奏自由灵活，有独唱、对唱、齐唱等多种形式。歌词多为七言四句，讲究押韵，比喻生动。内容有劳动歌如《插秧歌》《砍柴歌》，表现了农民劳动的艰辛和快乐；有情歌如《望郎歌》《送郎歌》，表达了青年男女的爱慕之情；有生活歌如《劝世歌》《十二月歌》，传递做人道理和生活常识。景宁汉族民歌没有固定的曲谱，全凭口头传承，即兴编唱。2006年，汉族民歌被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/汉族民歌.webp', '2006-06-10 00:00:00.000000', '县级', '传统音乐');
INSERT INTO `ich_project` VALUES (9018, '菇民戏', '景宁县', '菇民戏是流传于浙江省景宁畲族自治县的传统戏曲，以香菇栽培为背景创作的戏曲形式，反映菇民生活，具有浓郁地方特色，已有数百年历史。菇民戏由菇民创造，是他们在漫长的菇山生活中创造的。菇民戏的唱腔以乱弹为主，融合徽调、昆腔等，高亢激越，粗犷豪放。伴奏乐器有锣、鼓、钹、唢呐、笛子、二胡等，气氛热烈。剧目多为菇民生活的反映，如《香菇记》讲述菇民进山种菇的艰辛，《菇山情》表现菇民之间的感情，《采菇妹》描写菇山男女的爱情。这些剧目情节生动，语言朴实，充满山乡风味。菇民戏的演员都是菇民自己，农忙时种菇，农闲时演戏，自娱自乐。2006年，菇民戏被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/菇民戏.webp', '2006-06-10 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (9019, '木偶戏', '景宁县', '木偶戏是流传于浙江省景宁畲族自治县的传统戏剧，艺人以线操纵木偶表演，配以唱腔和乐器伴奏，演绎各类故事，已有三百多年历史。景宁木偶戏属于提线木偶，木偶高约两尺，用樟木雕刻头部，彩绘脸谱，服饰用绸缎制作，四肢关节可活动，通过十几根细线连接操纵。木偶戏的操纵技巧十分复杂，艺人通过提拉不同位置的线，使木偶做出行走、转身、作揖、舞剑等各种动作。唱腔以乱弹为主，融合徽调、昆腔等，高亢激越。伴奏乐器有锣、鼓、钹、笛子、二胡等，气氛热烈。传统剧目有《白蛇传》《西游记》《三国演义》《封神榜》等数十本，内容多为历史故事和神话传说。木偶戏班多在庙会、节庆时演出，走村串户，深受欢迎。2006年，木偶戏被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/木偶戏.webp', '2006-06-10 00:00:00.000000', '县级', '传统戏剧');
INSERT INTO `ich_project` VALUES (9020, '畲族彩带', '景宁县', '畲族彩带编织技艺是流传于浙江省景宁畲族自治县的传统手工技艺，编织各种花纹的彩带，是畲族妇女世代传承的技艺。畲族彩带用彩色丝线或棉线编织而成，宽约一至三寸，长约数尺，两端有流苏。彩带的图案丰富多样，有几何纹、文字纹、花鸟纹等，每种图案都有特定的寓意。彩带编织技艺包括选线、染色、整经、编织等工序。选线要选质量好的丝线或棉线。染色用植物染料将白线染成各种颜色。整经将经线按一定顺序排列在织机上。编织是最关键的环节，用纬线在经线中穿梭编织，织出各种图案。编织技法有平纹、斜纹、提花等。畲族彩带用途广泛，可作腰带、围裙带、背包带，也可作定情信物。2006年，畲族彩带被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/畲族彩带.webp', '2006-06-10 00:00:00.000000', '县级', NULL);
INSERT INTO `ich_project` VALUES (9021, '大漈罐', '景宁县', '大漈罐是流传于浙江省景宁畲族自治县大漈乡的传统技艺类项目，以大漈乡特有的陶土烧制的陶罐，用于储存和烹制食品，已有数百年历史。大漈罐选用当地特有的陶土，这种陶土含铁量高，烧成后呈黑色。大漈罐烧制技艺包括选土、淘洗、陈腐、练泥、拉坯、修坯、晾干、烧制等工序。选土要选质地细腻、黏性好的陶土。淘洗将陶土加水淘洗，去除杂质。陈腐将淘洗好的泥料放置数月，使泥质更加均匀细腻。练泥用脚踩或手揉，排除泥中气泡，增加可塑性。拉坯是最关键的环节，将泥料放在转盘上，用手拉制成各种器型，要求器壁厚薄均匀，造型规整。修坯将拉好的坯体修整光滑。晾干将坯体阴干，不能暴晒，以免开裂。烧制将干坯装入窑中，用松柴烧制，烧成温度约一千度。大漈罐品种多样，有饭罐、菜罐、水罐、酒罐等。大漈罐烧制的食品特别香，深受群众喜爱。', '/pictures/大漈罐.webp', '2006-06-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9022, '畲族服饰', '景宁县', '畲族服饰是流传于浙江省景宁畲族自治县的传统美术类项目，畲族传统服装的设计、裁剪、刺绣工艺，具有鲜明的民族特色。畲族服饰以其色彩鲜艳、图案精美、工艺精湛而著称。畲族服饰制作技艺包括面料选择、裁剪、刺绣、镶边、缀饰等环节。面料多选用自织的麻布或棉布，也有用绸缎的。裁剪根据穿着者的身材和服饰款式，将布料剪裁成衣片。刺绣是最重要的装饰手段，用彩色丝线在衣领、袖口、襟边、围裙等处绣出各种图案。刺绣针法有平绣、锁绣、打籽绣、辫绣等数十种，图案有花卉、鸟兽、几何纹样等，寓意吉祥。镶边用不同颜色的布条镶在衣边，增加美观和牢固度。缀饰在服饰上缀以银饰、铜钱、彩带等，使服饰更加华丽。畲族服饰因性别、年龄、场合不同而有区别。男子服装简朴，女子服装华丽。2006年，畲族服饰被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/畲族服饰.webp', '2006-06-10 00:00:00.000000', '县级', '传统美术');
INSERT INTO `ich_project` VALUES (9023, '畲族三月三', '景宁县', '畲族三月三是流传于浙江省景宁畲族自治县的传统节日，是畲族最重要的传统节日，举办歌会，吃乌米饭，祭祀祖先，已有上千年历史。三月三的主要活动包括祭祖、歌会、吃乌米饭等。祭祖在祠堂举行，全族聚集，献上三牲五果，焚香点烛，祭祀祖先。歌会是三月三的高潮，男女老少身着盛装，聚集在山坡上，对唱山歌，一唱一和，通宵达旦。歌会上还有畲族舞蹈、武术表演等。吃乌米饭是三月三的重要习俗，乌米饭用乌稔树叶汁浸泡糯米蒸制而成，色泽乌黑，清香扑鼻。三月三期间还有赶墟、舞龙、舞狮等民俗活动。2006年，畲族三月三被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/畲族三月三.webp', '2006-06-10 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (9024, '畲族婚俗', '景宁县', '畲族婚俗是流传于浙江省景宁畲族自治县的传统民俗，包含“借镬”“杀鸡”“劝酒”“对歌”等环节，热闹喜庆，是畲族独具特色的婚庆仪式。畲族婚俗以“歌”贯穿始终，有“以歌为媒”之说。说亲时，男方请媒人到女方家提亲，双方父母同意后择日定亲。定亲时，男方送聘礼到女方家，双方对唱山歌表示祝贺。迎亲是婚礼的高潮，新郎带着迎亲队伍到新娘家接亲，要经过“拦门”“对歌”“讨酒”等关卡。新娘头戴凤冠，身着盛装，由兄长背出家门，哭别父母。到男方家后举行拜堂仪式，一拜天地，二拜高堂，夫妻对拜，然后送入洞房。当晚闹洞房，亲友们唱山歌、做游戏，祝福新人。婚后三天，新婚夫妇回门。畲族婚俗仪式隆重，歌声不断，充满了喜庆和欢乐。', '/pictures/畲族婚俗.webp', '2006-06-10 00:00:00.000000', '县级', '民俗');
INSERT INTO `ich_project` VALUES (9025, '惠明茶手工技艺', '景宁县', '惠明茶手工技艺是流传于浙江省景宁畲族自治县的传统技艺，以惠明寺周边茶青为原料，经杀青、揉捻、干燥等工序制成惠明茶，是浙江名茶之一。惠明茶选用当地群体种茶树，清明前后采摘一芽一叶或一芽二叶。制作技艺包括摊青、杀青、揉捻、初烘、复烘、提香等工序，全部手工完成。摊青将鲜叶摊放数小时，使水分适度蒸发。杀青用铁锅高温炒制，破坏酶活性，固定茶叶品质。揉捻用手工揉搓，使茶叶卷曲成条，促进茶汁溢出。初烘用炭火低温烘干，去除大部分水分。复烘再次烘干，使茶叶足干。提香用高温短时烘焙，激发茶叶香气。惠明茶外形条索紧结，色泽翠绿，白毫显露，汤色清澈明亮，香气清高持久，滋味鲜爽醇厚，有“兰花清香”之誉。2006年，惠明茶手工技艺被列入景宁畲族自治县非物质文化遗产代表性项目名录。', '/pictures/惠明茶手工技艺.webp', '2006-06-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9026, '香菇手工技艺', '景宁县', '香菇手工技艺是流传于浙江省景宁畲族自治县的传统农业技艺，包括菇木砍伐、接种、管理、采收等环节，是香菇栽培的传统技艺。景宁是世界香菇发源地之一，千百年来，无数菇民每年秋冬季节进入深山老林培育香菇。香菇手工技艺包括选山、砍树、截段、砍花、遮衣、散水、惊蕈、采菇、烘干等一整套工序。选山要选择向阳通风、土壤肥沃的山地。砍树在冬至前后，选择树龄合适的阔叶树。截段将砍倒的树木截成段木。砍花是最关键的环节，用特制的砍花斧在段木上砍出花纹，控制香菇生长。遮衣用树枝覆盖段木，保持湿润。散水在干燥时浇水保湿。惊蕈用木槌敲击菇木，震动刺激菌丝生长。采菇在香菇成熟时及时采摘。烘干用炭火将香菇烘干，便于保存。', '/pictures/香菇手工技艺.webp', '2006-06-10 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9027, '操石磉', '景宁县', '操石磉是流传于浙江省景宁畲族自治县的传统体育项目，以脚踢动石磉（石制圆柱体），比拼力量和技巧，是畲族传统体育项目。石磉是农村用来平整场院的石制工具，圆柱形，重约百斤，一端有孔可穿绳。操石磉比赛时，参与者用脚踢动石磉，使其向前滚动，比拼力量和技巧。比赛形式多样，可以比谁踢得远，也可以比谁踢得准，还可以进行团体接力。踢石磉需要全身发力，尤其考验腰腿力量和爆发力。有经验的选手不仅能把石磉踢出很远，还能控制其滚动方向和速度。这项活动最初是农民在打谷场上劳作之余的娱乐，后发展成为节庆活动的比赛项目。操石磉不仅锻炼了参与者的体魄，也增进了乡邻之间的感情。', '/pictures/操石磉.webp', '2006-06-10 00:00:00.000000', '县级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (9028, '稳凳', '景宁县', '稳凳是流传于浙江省景宁畲族自治县的传统体育项目，参与者坐在凳上保持平衡，比拼稳定性和技巧，是畲族传统体育项目。稳凳用木板制作，长约两米，宽约二十厘米，下有两个弧形凳脚，人可以坐在凳上，通过身体晃动使凳子摇摆。稳凳比赛时，参与者坐在凳上，通过身体重心移动和脚部配合，使凳子保持平衡不倾倒。可以比谁稳得时间长，也可以比谁在凳上做的动作多，如转身、站立等。这项活动看似简单，实则需要极强的平衡能力和身体协调性。稳凳最初是畲族青年在山间劳作之余的娱乐方式，后发展成为节庆活动的表演项目。稳凳不仅锻炼了参与者的平衡能力，也体现了畲族人民乐观向上的生活态度。', '/pictures/稳凳.webp', '2006-06-10 00:00:00.000000', '县级', '传统体育、游艺与杂技');
INSERT INTO `ich_project` VALUES (9029, '汤夫人传说', '景宁县', '汤夫人传说是流传于浙江省景宁畲族自治县的民间文学，关于汤夫人的传说故事，在景宁当地广为流传。汤夫人是景宁民间信仰中的女神，传说她生前孝顺公婆，友爱乡邻，乐善好施，死后显灵护佑百姓。最著名的传说是“汤夫人祈雨”：有一年景宁大旱，禾苗枯焦，百姓祈雨无应。汤夫人独自上山，在悬崖边祈雨三天三夜，最终感动上天，降下甘霖。汤夫人却因劳累过度，坠崖身亡。百姓为纪念她，建庙祭祀，尊为“汤夫人”。另一传说是“汤夫人治病”：汤夫人生前精通医术，常为百姓治病。死后仍显灵治病，百姓有疑难杂症，到汤夫人庙祈拜，往往灵验。汤夫人传说情节感人，反映了民众对善良、仁爱品德的崇敬。', '/pictures/汤夫人传说.webp', '2006-06-10 00:00:00.000000', '县级', '民间文学');
INSERT INTO `ich_project` VALUES (9030, '畲族绿曲酒制作技艺', '景宁县', '畲族绿曲酒制作技艺是流传于浙江省景宁畲族自治县的传统技艺，以糯米和绿曲为原料，经发酵酿制绿曲酒，酒色碧绿，口感醇和，已有数百年历史。绿曲是一种特殊的酒曲，用大米和多种草药发酵制成，因曲呈绿色而得名。绿曲酒酿造技艺包括浸米、蒸饭、摊凉、拌曲、入缸发酵、榨酒、澄清、煎酒、陈化等工序。选用当地优质糯米，浸泡后蒸熟，摊凉至适宜温度。拌入绿曲，这是绿曲酒酿造的关键，曲的质量直接影响酒的品质。入缸发酵约一周，期间要控制温度湿度。发酵完成后榨取酒液，澄清数日。煎酒将酒液加热到八十度左右，杀灭酵母菌，停止发酵。最后装坛密封，陈化数月使酒质更加醇和。畲族绿曲酒色泽碧绿，香气清雅，口感醇和，是畲族传统饮品。2018年，畲族绿曲酒制作技艺被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/畲族绿曲酒制作技艺.webp', '2018-10-23 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (9031, '畲族民居传统营造技艺', '景宁县', '畲族民居传统营造技艺是流传于浙江省景宁畲族自治县的传统技艺，涵盖畲族传统民居的规划设计、建筑结构、装饰艺术等，体现了畲族人民的建筑智慧。畲族民居多为木结构瓦房，依山而建，布局灵活。营造技艺包括选址、设计、备料、地基、木作、瓦作、装饰等工序。选址要依山傍水，避风向阳。设计根据家庭人口和经济条件，确定房屋规模和布局。备料选用优质杉木，要求笔直无疤节。地基用石块垒砌，坚固耐用。木作是最关键的环节，包括柱、梁、枋、椽的制作安装，全部榫卯连接，不用一钉一铁。瓦作铺设小青瓦，要求排列整齐，不漏雨水。装饰在梁枋、门窗等处雕刻花鸟图案，朴素大方。畲族民居营造技艺世代相传，保持了传统的建筑风格和工艺。2018年，畲族民居传统营造技艺被列入浙江省非物质文化遗产代表性项目名录。', '/pictures/畲族民居传统营造技艺.webp', '2018-10-23 00:00:00.000000', '省级', '传统技艺');
INSERT INTO `ich_project` VALUES (9032, '畲族舞蹈', '景宁县', '畲族舞蹈是流传于浙江省景宁畲族自治县的传统舞蹈，舞姿优美，节奏欢快，多在节庆和祭祀场合表演。畲族舞蹈是畲族文化的重要组成部分，与畲族的历史、信仰、生活密切相关。景宁畲族舞蹈的种类丰富，有祭祖舞、狩猎舞、采茶舞、婚庆舞等。祭祖舞在祭祀祖先时表演，动作庄重肃穆，表达对祖先的崇敬；狩猎舞模仿狩猎过程，动作矫健有力，表现畲族人民的勇敢；采茶舞模仿采茶劳动，动作优美流畅，表现茶园的欢乐；婚庆舞在婚礼上表演，动作欢快热烈，祝福新人幸福。畲族舞蹈的伴奏以锣鼓和山歌为主，节奏明快，气氛热烈。舞蹈队形变化丰富，有围圈、穿插、列队等。畲族舞蹈的独特之处在于“以歌带舞”，舞蹈与山歌紧密结合，边唱边舞，载歌载舞。', '/pictures/畲族舞蹈.webp', '2018-10-23 00:00:00.000000', '市级', '传统舞蹈');
INSERT INTO `ich_project` VALUES (9033, '番薯面制作手工技艺', '景宁县', '番薯面制作手工技艺是流传于浙江省景宁畲族自治县的传统技艺，以番薯为原料，经打浆、漏粉、晾晒等工序制成番薯面，是当地传统食品。番薯面制作技艺包括选薯、清洗、打浆、过滤、沉淀、调浆、漏粉、煮粉、晾晒等工序。选薯要选淀粉含量高的番薯。清洗将番薯洗净，去除泥土。打浆将番薯磨成浆。过滤用纱布将浆汁过滤，去除渣滓。沉淀将滤液静置，使淀粉沉淀，倒去上层清水。调浆将沉淀的淀粉加水调成糊状。漏粉是最关键的环节，将调好的粉浆装入底部有孔的漏瓢中，用手掌拍打，使粉浆均匀漏入沸水锅中，瞬间凝固成粉丝。煮粉将漏出的粉丝在沸水中煮熟。晾晒将煮熟的粉丝捞出，挂在竹竿上晾晒干燥。景宁番薯面晶莹剔透，韧性十足，无论是煮汤、凉拌还是炒食，都爽滑可口。', '/pictures/番薯面制作手工技艺.webp', '2018-10-23 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9034, '算盘制作技艺', '景宁县', '算盘制作技艺是流传于浙江省景宁畲族自治县的传统技艺，以木材为原料，手工制作算盘的传统工艺，已有上百年历史。算盘制作技艺包括选材、制作框架、制作算珠、组装、上漆等工序。选材要选质地坚硬、不易变形的木材，如红木、黄杨木、梓木等。制作框架将木材锯成所需尺寸，开榫卯，组装成算盘框架。框架四周要平整光滑，四角要直角。制作算珠是最关键的环节，将木材车成算珠形状，要求大小一致，中间穿孔光滑。每个算盘需要数十颗算珠，都要逐个车制。组装将算珠穿在竹制或铁制的档上，每档穿七颗或五颗算珠，然后将档固定在框架上。要求算珠转动灵活，不松不紧。上漆用清漆涂饰算盘，保护木材，增加美观。景宁算盘制作精细，算珠圆滑，框架平整，使用顺手。随着计算器的普及，算盘使用减少，会这门手艺的人也越来越少。', '/pictures/算盘制作技艺.webp', '2018-10-23 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9035, '碱粽制作技艺', '景宁县', '碱粽制作技艺是流传于浙江省景宁畲族自治县的传统技艺，以碱水浸泡糯米，包制粽子，蒸煮而成，是当地传统食品。碱粽因其用碱水制作而得名，色泽金黄，清香扑鼻。制作技艺包括烧灰、浸米、包粽、煮粽等工序。烧灰选用山中的灌木和杂草烧成灰，用开水冲泡过滤，得到碱水。这种碱水呈碱性，能使糯米变成金黄色，并赋予独特的清香。浸米将糯米放入碱水中浸泡数小时，使米粒充分吸收碱水，变成淡黄色。包粽将浸泡好的糯米和馅料用粽叶包裹成三角形或四角形，用棕榈叶撕成的细绳扎紧。馅料可甜可咸，甜馅常用红豆沙，咸馅常用猪肉、咸蛋黄等。煮粽将包好的粽子放入大锅中，加水没过粽子，用旺火煮三小时以上，再焖一夜，使粽叶的清香充分渗入糯米。景宁碱粽色泽金黄，清香扑鼻，口感软糯。', '/pictures/碱粽制作技艺.webp', '2018-10-23 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9036, '山豆腐制作技艺', '景宁县', '山豆腐制作技艺是流传于浙江省景宁畲族自治县的传统技艺，以山中的植物果实或树叶为原料，制作成类似豆腐的食品，已有数百年历史。山豆腐不是用黄豆做的，而是用山中的植物做的，如苦褚豆腐、橡子豆腐、神仙豆腐等。苦褚豆腐用苦褚树果实制作，苦褚果实富含淀粉，经浸泡、磨浆、过滤、沉淀、煮浆、凝固等工序制成，色泽灰褐，口感滑嫩，带有独特的苦味。橡子豆腐用橡子制作，橡子去壳浸泡去涩，磨浆过滤，沉淀煮浆，凝固成型，色泽棕褐，口感略涩。神仙豆腐用神仙树叶制作，树叶洗净捣烂，过滤取汁，加入草木灰水凝固，色泽碧绿，晶莹剔透。山豆腐制作技艺充分利用山中的自然资源，是山区人民智慧的结晶。山豆腐可直接食用，也可凉拌、煮汤、炒食。', '/pictures/山豆腐制作技艺.webp', '2018-10-23 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9037, '豆腐娘制作技艺', '景宁县', '豆腐娘制作技艺是流传于浙江省景宁畲族自治县的传统技艺，以黄豆为原料，制作豆腐娘（豆腐花）的传统工艺。豆腐娘是景宁人对豆腐花的称呼，是当地传统早餐食品。制作技艺包括选豆、浸豆、磨浆、煮浆、点卤、成型等工序。选豆要选颗粒饱满、无虫蛀的黄豆，以本地小黄豆为佳。浸豆将黄豆淘洗干净，用清水浸泡过夜，使豆粒充分吸水膨胀。磨浆将浸泡好的黄豆加水磨成豆浆，用石磨磨出的豆浆最香浓。煮浆将磨好的豆浆倒入锅中煮沸，边煮边撇去浮沫，煮沸后继续煮几分钟，使豆浆熟透。点卤是最关键的环节，将盐卤或石膏水慢慢倒入热豆浆中，轻轻搅拌，使蛋白质凝固，形成豆腐花。点卤的火候决定豆腐花的老嫩，全凭经验掌握。成型将点好的豆腐花舀入铺有纱布的模具中，压去部分水分，即成豆腐娘。景宁豆腐娘洁白细嫩，豆香浓郁，可咸可甜。', '/pictures/豆腐娘制作技艺.webp', '2018-10-23 00:00:00.000000', '县级', '传统技艺');
INSERT INTO `ich_project` VALUES (9038, '木偶制作技艺', '景宁县', '木偶制作技艺是流传于浙江省景宁畲族自治县的传统技艺，以木材雕刻木偶，用于木偶戏表演。木偶制作技艺包括选材、设计、雕刻、组装、彩绘、服饰等工序。选材要选质地细腻、不易开裂的木材，如樟木、银杏木等。设计要根据木偶的角色和性格，设计木偶的形象和尺寸。雕刻是最关键的环节，用各种刀具雕刻出木偶的头像，要求五官端正，表情生动。木偶头部要雕刻出角色的特征，如生、旦、净、末、丑各有不同。组装将雕刻好的头部与木偶身体连接，身体用竹篾或木材制作，四肢关节可活动。彩绘用矿物颜料给木偶上色，描绘五官和脸谱。服饰用绸缎制作木偶的服装，根据角色身份穿着不同服饰。景宁木偶制作精细，形象生动，为木偶戏表演提供了精美的道具。', '/pictures/木偶制作技艺.webp', '2018-10-23 00:00:00.000000', '县级', '传统美术');
